function renderVisualGamePluginBuildingPanel(plugin) {
  const entryView = renderVisualGamePluginEntryView(plugin);
  if (entryView) {
    return entryView;
  }

  const issue = getPluginBuildingIssue(plugin);
  if (issue) {
    const nextStep = renderPluginNextSetupAction(plugin, issue, { minimal: true });
    return `
      <div class="visual-building-panel-scroll visual-building-plugin-panel visual-building-plugin-panel-minimal">
        ${
          nextStep
            ? nextStep
            : `
              <section class="plugin-next-step is-minimal" aria-label="${escapeHtml(`${plugin.name} next step`)}">
                <div class="plugin-next-step-head">
                  <strong>Next step</strong>
                  <span>${escapeHtml(issue.label || "needs setup")}</span>
                </div>
                <p>${escapeHtml(issue.detail || "Complete this building setup to unlock its UI.")}</p>
              </section>
            `
        }
      </div>
    `;
  }

  const health = isAgentTownFunctionalPlugin(plugin)
    ? getAgentTownBuildingHealth(plugin)
    : { status: "ok", label: "healthy", detail: "Built in and ready." };
  return `
    <div class="visual-building-panel-scroll visual-building-plugin-panel">
      <section class="visual-building-plugin-card">
        ${renderPluginBuilding(plugin, { issue })}
        <div class="plugin-detail-copy">
          <span class="main-search-kind">${escapeHtml(plugin.source || "building")}</span>
          <h2>${escapeHtml(plugin.name)}</h2>
          <p>${escapeHtml(plugin.description)}</p>
          <span class="plugin-status ${issue ? "is-warning" : ""}">${escapeHtml(getPluginStatusBadgeLabel(plugin, issue))}</span>
          ${renderAgentTownBuildingHealthBadge(health)}
          ${issue ? "" : `<div class="settings-status ${health.status === "blocked" || health.status === "warning" ? "is-warning" : ""}">${escapeHtml(health.detail)}</div>`}
        </div>
      </section>
      <section class="plugin-detail-settings visual-building-plugin-settings">
        ${renderPluginDetailSettings(plugin)}
      </section>
    </div>
  `;
}

function renderAgentTownCosmeticPanelContent(details) {
  if (!details) {
    return `
      <div class="visual-building-panel-scroll">
        <section class="visual-building-summary">
          <span class="main-search-kind">cosmetic</span>
          <strong>Cosmetic not found</strong>
        </section>
      </div>
    `;
  }

  const { decoration, item } = details;
  const rect = getAgentTownDecorationRect(decoration, item) || { width: item.width, height: item.height };
  const sameItemCount = getAgentTownDecorations().filter((candidate) => candidate.itemId === item.id).length;
  const locationLabel = `grid ${Math.round(decoration.x / AGENT_TOWN_BUILD_GRID_SIZE)}, ${Math.round(decoration.y / AGENT_TOWN_BUILD_GRID_SIZE)}`;
  const columns = Math.max(1, Math.round(rect.width / AGENT_TOWN_BUILD_GRID_SIZE));
  const rows = Math.max(1, Math.round(rect.height / AGENT_TOWN_BUILD_GRID_SIZE));
  const sizeLabel = `${columns}x${rows} ${columns * rows === 1 ? "tile" : "tiles"}`;
  const countLabel = sameItemCount === 1 ? "1 placed" : `${sameItemCount} placed`;

  return `
    <div class="visual-building-panel-scroll visual-building-cosmetic-panel">
      <section class="visual-building-summary">
        <span class="main-search-kind">cosmetic</span>
        <strong>${escapeHtml(item.label)}</strong>
        <p>${escapeHtml(`${item.meta || item.kind} · ${sizeLabel} · ${locationLabel}`)}</p>
        <div class="visual-building-library-actions">
          <button class="primary-button toolbar-control" type="button" data-agent-town-builder-place-cosmetic="${escapeHtml(item.id)}">
            <span aria-hidden="true">${renderIcon(Plus)}</span>
            <span>Place another</span>
          </button>
          <button class="ghost-button toolbar-control" type="button" data-agent-town-remove-decoration="${escapeHtml(decoration.id)}">
            <span aria-hidden="true">${renderIcon(Trash2)}</span>
            <span>Remove</span>
          </button>
        </div>
      </section>
      <section class="visual-building-cosmetic-card" aria-label="${escapeHtml(`${item.label} cosmetic details`)}">
        ${renderAgentTownBuilderCosmeticPreview(item)}
        <span>
          <strong>${escapeHtml(item.label)}</strong>
          <em>${escapeHtml(countLabel)}</em>
          <span>${escapeHtml(`${sizeLabel} at ${locationLabel}.`)}</span>
        </span>
      </section>
    </div>
  `;
}

function renderVisualGameBuildingPanelContent(buildingId, plugin) {
  if (buildingId === "automations") {
    return renderAutomationsBuildingPanel();
  }

  if (buildingId === "toolshed") {
    return renderToolshedBuildingPanel();
  }

  if (buildingId === VISUAL_GAME_DOGHOUSE_BUILDING_ID) {
    return renderDoghouseBuildingPanel(plugin);
  }

  if (buildingId === "system") {
    return renderSystemBuildingPanel();
  }

  if (buildingId === "knowledge-base") {
    return renderVisualGameLibraryBuildingPanel();
  }

  if (plugin) {
    return renderVisualGamePluginBuildingPanel(plugin);
  }

  return `
    <div class="visual-building-panel-scroll">
      <section class="visual-building-summary">
        <span class="main-search-kind">unavailable</span>
        <strong>Building not found</strong>
      </section>
    </div>
  `;
}

