const ACTION_PREDICATE_HINTS = new Map([
  ["first_building_placed", { anchor: "builder-fab", label: "Open the builder to place your first building" }],
  ["cosmetic_building_placed", { anchor: "builder-fab", label: "Open the builder to place a cosmetic piece" }],
  ["functional_building_placed", { anchor: "builder-fab", label: "Open the builder to place a functional building" }],
  ["library_note_saved", { anchor: "knowledge-base", label: "Open or create a note, then save it" }],
  ["automation_created", { anchor: "automation-create", label: "Fill in the form, then create your first automation" }],
]);

async function openAgentTownActionHref(actionItemId) {
  const item = state.agentTown.actionItems.find((candidate) => candidate.id === actionItemId);
  const href = String(item?.href || item?.target?.href || "").trim();
  const tutorialId = ACTION_PREDICATE_GUIDED_TUTORIALS.get(String(item?.predicate || "").trim()) || "";
  if (tutorialId && startGuidedTutorial(tutorialId, { actionItemId })) {
    return;
  }

  if (!href) {
    return;
  }

  const predicate = String(item?.predicate || "").trim();
  const questHint = ACTION_PREDICATE_HINTS.get(predicate) || null;

  if (href.startsWith("?")) {
    const params = new URLSearchParams(href);
    const view = params.get("view");
    if (view) {
      if (questHint) {
        setQuestHint(questHint.anchor, questHint.label);
      }
      await openMainView(view);
      return;
    }
    window.location.href = `${window.location.pathname}${href}`;
    return;
  }

  if (href.startsWith("#")) {
    window.location.hash = href.slice(1);
    return;
  }

  window.location.href = href;
}

function renderTutorialMarkdown(markdown) {
  const lines = String(markdown || "").replace(/\r\n/g, "\n").split("\n");
  const blocks = [];
  let paragraphBuffer = [];
  let listBuffer = null;
  let codeBuffer = null;

  const flushParagraph = () => {
    if (paragraphBuffer.length) {
      blocks.push(`<p>${renderTutorialInline(paragraphBuffer.join(" "))}</p>`);
      paragraphBuffer = [];
    }
  };
  const flushList = () => {
    if (listBuffer) {
      const tag = listBuffer.type === "ol" ? "ol" : "ul";
      blocks.push(`<${tag}>${listBuffer.items.map((entry) => `<li>${renderTutorialInline(entry)}</li>`).join("")}</${tag}>`);
      listBuffer = null;
    }
  };

  for (const rawLine of lines) {
    const line = rawLine;
    if (codeBuffer !== null) {
      if (/^```/.test(line.trim())) {
        blocks.push(`<pre><code>${escapeHtml(codeBuffer.join("\n"))}</code></pre>`);
        codeBuffer = null;
      } else {
        codeBuffer.push(line);
      }
      continue;
    }

    if (/^```/.test(line.trim())) {
      flushParagraph();
      flushList();
      codeBuffer = [];
      continue;
    }

    if (!line.trim()) {
      flushParagraph();
      flushList();
      continue;
    }

    const headingMatch = /^(#{1,3})\s+(.*)$/.exec(line);
    if (headingMatch) {
      flushParagraph();
      flushList();
      const level = headingMatch[1].length;
      blocks.push(`<h${level}>${renderTutorialInline(headingMatch[2])}</h${level}>`);
      continue;
    }

    const orderedMatch = /^\s*\d+\.\s+(.*)$/.exec(line);
    const unorderedMatch = /^\s*-\s+(.*)$/.exec(line);
    if (orderedMatch || unorderedMatch) {
      flushParagraph();
      const type = orderedMatch ? "ol" : "ul";
      const text = (orderedMatch || unorderedMatch)[1];
      if (!listBuffer || listBuffer.type !== type) {
        flushList();
        listBuffer = { type, items: [] };
      }
      listBuffer.items.push(text);
      continue;
    }

    flushList();
    paragraphBuffer.push(line.trim());
  }

  if (codeBuffer !== null) {
    blocks.push(`<pre><code>${escapeHtml(codeBuffer.join("\n"))}</code></pre>`);
  }
  flushParagraph();
  flushList();

  return blocks.join("\n");
}

function renderTutorialInline(text) {
  const escaped = escapeHtml(String(text || ""));
  return escaped.replace(/`([^`]+)`/g, (_, code) => `<code>${code}</code>`);
}

function closeTutorialOverlay() {
  const existing = document.querySelector(".tutorial-overlay");
  if (existing) {
    existing.remove();
  }
}

async function openTutorialOverlay(tutorialId, actionItemId) {
  const id = String(tutorialId || "").trim();
  if (!id) {
    return;
  }
  if (getGuidedTutorialConfig(id)) {
    startGuidedTutorial(id, { actionItemId });
    return;
  }
  let tutorial = null;
  try {
    const payload = await fetchJson(`/api/tutorials/${encodeURIComponent(id)}`);
    tutorial = payload.tutorial;
  } catch (error) {
    window.alert(error.message || "Could not load tutorial.");
    return;
  }
  if (!tutorial) {
    return;
  }

  closeTutorialOverlay();
  const overlay = document.createElement("div");
  overlay.className = "tutorial-overlay";
  overlay.innerHTML = `
    <div class="tutorial-overlay-backdrop" data-tutorial-dismiss></div>
    <div class="tutorial-overlay-card" role="dialog" aria-label="${escapeHtml(tutorial.title || "Tutorial")}">
      <header class="tutorial-overlay-head">
        <strong>${escapeHtml(tutorial.title || "Tutorial")}</strong>
        <button type="button" class="icon-button" data-tutorial-dismiss aria-label="Close tutorial">&times;</button>
      </header>
      <div class="tutorial-overlay-body">${renderTutorialMarkdown(tutorial.body)}</div>
      <footer class="tutorial-overlay-actions">
        <button type="button" class="ghost-button toolbar-control" data-tutorial-dismiss>Close</button>
        <button type="button" class="primary-button toolbar-control" data-tutorial-done="${escapeHtml(String(actionItemId || ""))}">Got it</button>
      </footer>
    </div>
  `;
  document.body.appendChild(overlay);

  overlay.querySelectorAll("[data-tutorial-dismiss]").forEach((element) => {
    element.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      closeTutorialOverlay();
    });
  });

  const doneButton = overlay.querySelector("[data-tutorial-done]");
  if (doneButton) {
    doneButton.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();
      const targetId = doneButton.getAttribute("data-tutorial-done") || "";
      if (targetId) {
        await updateAgentTownActionItemStatus(targetId, "completed");
      }
      closeTutorialOverlay();
    });
  }
}

function getAgentTownTheme(themeId = state.visualGame.themeId) {
  return AGENT_TOWN_THEME_BY_ID.get(normalizeAgentTownThemeId(themeId)) || AGENT_TOWN_THEME_BY_ID.get(AGENT_TOWN_DEFAULT_THEME_ID);
}

function saveAgentTownThemePreference() {
  try {
    window.localStorage.setItem(AGENT_TOWN_THEME_STORAGE_KEY, normalizeAgentTownThemeId(state.visualGame.themeId));
  } catch {
    // Theme selection is cosmetic; storage failures should not block Agent Town.
  }
}

function setAgentTownTheme(themeId, { render = true } = {}) {
  const nextThemeId = normalizeAgentTownThemeId(themeId);
  if (state.visualGame.themeId === nextThemeId) {
    return false;
  }

  state.visualGame.themeId = nextThemeId;
  saveAgentTownThemePreference();
  void mirrorAgentTownState({ refreshUi: false, reason: "theme changed" });
  if (render) {
    renderShell();
  }
  return true;
}

function getAgentTownDogName() {
  return normalizeAgentTownDogName(state.visualGame.dogName);
}

function saveAgentTownDogNamePreference() {
  try {
    const dogName = getAgentTownDogName();
    if (dogName === AGENT_TOWN_DOG_NAME_DEFAULT) {
      window.localStorage.removeItem(AGENT_TOWN_DOG_NAME_STORAGE_KEY);
    } else {
      window.localStorage.setItem(AGENT_TOWN_DOG_NAME_STORAGE_KEY, dogName);
    }
  } catch {
    // The dog name is cosmetic; storage failures should not block Agent Town.
  }
}

function setAgentTownDogName(value, { render = true } = {}) {
  const nextDogName = normalizeAgentTownDogName(value);
  if (state.visualGame.dogName === nextDogName) {
    return false;
  }

  state.visualGame.dogName = nextDogName;
  saveAgentTownDogNamePreference();
  void mirrorAgentTownState({ refreshUi: false, reason: "dog name changed" });
  if (render) {
    renderShell();
  }
  return true;
}

function resetAgentTownLayout({ render = true } = {}) {
  const activePlacement = state.visualGame.builderPlacement;
  if (activePlacement?.kind === "functional" && !isPluginIdInstalled(activePlacement.pluginId)) {
    cancelFunctionalPluginPlacementInstall(activePlacement.pluginId);
  }
  state.visualGame.customLayout = getEmptyAgentTownLayout();
  state.visualGame.builderPlacement = null;
  state.visualGame.builderFeedback = null;
  state.visualGame.builderPulse = null;
  state.visualGame.builderConstruction = null;
  saveAgentTownLayoutPreferences({ reason: "layout reset" });
  if (render) {
    renderShell();
  }
}

function applyAgentTownLayoutToVisualGame(layoutInput = {}, { mirror = true, render = true } = {}) {
  const activePlacement = state.visualGame.builderPlacement;
  if (activePlacement?.kind === "functional" && !isPluginIdInstalled(activePlacement.pluginId)) {
    cancelFunctionalPluginPlacementInstall(activePlacement.pluginId);
  }
  const layout = applyAgentTownPersistedLayout(layoutInput);
  state.visualGame.builderPlacement = null;
  state.visualGame.builderFeedback = null;
  state.visualGame.builderPulse = null;
  state.visualGame.builderConstruction = null;
  if (mirror) {
    void mirrorAgentTownState({ refreshUi: false, reason: "import town share" });
  }
  if (render) {
    renderShell();
  }
  return layout;
}

function toggleAgentTownEditMode() {
  state.visualGame.editMode = !state.visualGame.editMode;
  renderShell();
}

function isAgentTownEditMode() {
  return Boolean(state.visualGame.editMode);
}

function getAgentTownLayoutBucket(kind) {
  if (!state.visualGame.customLayout || typeof state.visualGame.customLayout !== "object") {
    state.visualGame.customLayout = { places: {}, roads: {}, decorations: [], functional: {}, pendingFunctional: [] };
  }
  const key = kind === "road" ? "roads" : "places";
  if (!state.visualGame.customLayout[key] || typeof state.visualGame.customLayout[key] !== "object") {
    state.visualGame.customLayout[key] = {};
  }
  return state.visualGame.customLayout[key];
}

function getAgentTownLayoutOffset(kind, id) {
  return normalizeAgentTownLayoutOffset(getAgentTownLayoutBucket(kind)[id]) || { x: 0, y: 0 };
}

function setAgentTownLayoutOffset(kind, id, offset) {
  const normalized = normalizeAgentTownLayoutOffset(offset) || { x: 0, y: 0 };
  const bucket = getAgentTownLayoutBucket(kind);
  if (Math.abs(normalized.x) < 0.5 && Math.abs(normalized.y) < 0.5) {
    delete bucket[id];
    return;
  }
  bucket[id] = normalized;
}

function getAgentTownDecorations() {
  if (!state.visualGame.customLayout || typeof state.visualGame.customLayout !== "object") {
    state.visualGame.customLayout = { places: {}, roads: {}, decorations: [], functional: {}, pendingFunctional: [] };
  }
  if (!Array.isArray(state.visualGame.customLayout.decorations)) {
    state.visualGame.customLayout.decorations = [];
  }
  return state.visualGame.customLayout.decorations;
}

function addAgentTownDecoration(itemId, rect, { rotation = rect?.rotation } = {}) {
  const item = getAgentTownCosmeticItem(itemId);
  if (!item || !rect) {
    return null;
  }

  const normalizedRotation = normalizeAgentTownRotation(rotation);
  const size = getAgentTownCosmeticItemSize(item, normalizedRotation);
  const snappedRect = getAgentTownSnappedPlacementRect({
    x: rect.x,
    y: rect.y,
    width: size.width,
    height: size.height,
  });
  const decoration = normalizeAgentTownDecoration({
    id: createClientId(`decor-${item.id}`),
    itemId: item.id,
    x: snappedRect.x,
    y: snappedRect.y,
    rotation: normalizedRotation,
  });
  if (!decoration) {
    return null;
  }

  getAgentTownDecorations().push(decoration);
  saveAgentTownLayoutPreferences();
  return decoration;
}

function removeLastAgentTownDecoration() {
  const decorations = getAgentTownDecorations();
  const removed = decorations.pop() || null;
  if (removed) {
    saveAgentTownLayoutPreferences();
  }
  return removed;
}

function clearAgentTownDecorations() {
  const decorations = getAgentTownDecorations();
  if (!decorations.length) {
    return false;
  }

  state.visualGame.customLayout.decorations = [];
  saveAgentTownLayoutPreferences();
  return true;
}

function getAgentTownDecorationById(decorationId) {
  const id = String(decorationId || "").trim();
  if (!id) {
    return null;
  }

  return getAgentTownDecorations().find((decoration) => decoration.id === id) || null;
}

function getAgentTownDecorationDetails(decorationId) {
  const decoration = getAgentTownDecorationById(decorationId);
  const item = decoration ? getAgentTownCosmeticItem(decoration.itemId) : null;
  if (!decoration || !item) {
    return null;
  }

  return { decoration, item };
}

function getAgentTownDecorationRect(decoration, item = getAgentTownCosmeticItem(decoration?.itemId)) {
  if (!decoration || !item) {
    return null;
  }

  const rotation = normalizeAgentTownRotation(decoration.rotation);
  const size = getAgentTownCosmeticItemSize(item, rotation);
  return {
    x: decoration.x,
    y: decoration.y,
    width: size.width,
    height: size.height,
    rotation,
  };
}

function removeAgentTownDecoration(decorationId) {
  const id = String(decorationId || "").trim();
  if (!id) {
    return null;
  }

  const decorations = getAgentTownDecorations();
  const decorationIndex = decorations.findIndex((decoration) => decoration.id === id);
  if (decorationIndex < 0) {
    return null;
  }

  const [removed] = decorations.splice(decorationIndex, 1);
  if (state.visualGame.selectedCosmeticDecorationId === id) {
    state.visualGame.selectedCosmeticDecorationId = "";
  }
  saveAgentTownLayoutPreferences();
  return removed || null;
}

function getAgentTownFunctionalPlacements() {
  if (!state.visualGame.customLayout || typeof state.visualGame.customLayout !== "object") {
    state.visualGame.customLayout = { places: {}, roads: {}, decorations: [], functional: {}, pendingFunctional: [] };
  }
  if (!state.visualGame.customLayout.functional || typeof state.visualGame.customLayout.functional !== "object") {
    state.visualGame.customLayout.functional = {};
  }
  return state.visualGame.customLayout.functional;
}

function getAgentTownPendingFunctionalIds() {
  if (!state.visualGame.customLayout || typeof state.visualGame.customLayout !== "object") {
    state.visualGame.customLayout = { places: {}, roads: {}, decorations: [], functional: {}, pendingFunctional: [] };
  }
  if (!Array.isArray(state.visualGame.customLayout.pendingFunctional)) {
    state.visualGame.customLayout.pendingFunctional = [];
  }
  return state.visualGame.customLayout.pendingFunctional;
}

function getAgentTownFunctionalPlacement(pluginId) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  const placement = normalizedPluginId ? getAgentTownFunctionalPlacements()[normalizedPluginId] : null;
  if (!placement) {
    return null;
  }

  const rotation = normalizeAgentTownRotation(placement.rotation);
  const size = getAgentTownFunctionalBuildingSize(rotation);
  return {
    x: placement.x,
    y: placement.y,
    width: size.width,
    height: size.height,
    rotation,
  };
}

function setAgentTownFunctionalPlacement(pluginId, rect, { rotation = rect?.rotation } = {}) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  if (!normalizedPluginId || !rect) {
    return false;
  }

  const normalizedRotation = normalizeAgentTownRotation(rotation);
  const size = getAgentTownFunctionalBuildingSize(normalizedRotation);
  const snappedRect = getAgentTownSnappedPlacementRect({
    x: rect.x,
    y: rect.y,
    width: size.width,
    height: size.height,
  });
  const placement = {
    x: snappedRect.x,
    y: snappedRect.y,
  };
  if (normalizedRotation) {
    placement.rotation = normalizedRotation;
  }
  getAgentTownFunctionalPlacements()[normalizedPluginId] = placement;
  setAgentTownFunctionalPending(normalizedPluginId, false);
  return true;
}

function removeAgentTownFunctionalPlacement(pluginId) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  if (!normalizedPluginId) {
    return;
  }

  delete getAgentTownFunctionalPlacements()[normalizedPluginId];
  setAgentTownFunctionalPending(normalizedPluginId, false);
}

function isAgentTownFunctionalPending(pluginId) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  return Boolean(normalizedPluginId && getAgentTownPendingFunctionalIds().includes(normalizedPluginId));
}

function setAgentTownFunctionalPending(pluginId, pending) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  if (!normalizedPluginId) {
    return false;
  }

  const pendingIds = getAgentTownPendingFunctionalIds();
  const index = pendingIds.indexOf(normalizedPluginId);
  if (pending) {
    if (index < 0) {
      pendingIds.push(normalizedPluginId);
      return true;
    }
    return false;
  }

  if (index >= 0) {
    pendingIds.splice(index, 1);
    return true;
  }
  return false;
}

function getAgentTownSnappedLayoutValueInRange(value, min, max) {
  const snap = AGENT_TOWN_LAYOUT_EDIT_SNAP;
  const lower = Math.ceil(Math.min(min, max) / snap) * snap;
  const upper = Math.floor(Math.max(min, max) / snap) * snap;
  if (lower > upper) {
    return clamp(snapAgentTownLayoutValue(value), min, max);
  }
  return clamp(snapAgentTownLayoutValue(value), lower, upper);
}

function getAgentTownSnappedPlacementRect(rect) {
  const width = Math.max(1, Number(rect?.width || 1));
  const height = Math.max(1, Number(rect?.height || 1));
  return {
    x: getAgentTownSnappedLayoutValueInRange(Number(rect?.x || 0), 0, Math.max(0, VISUAL_GAME_WIDTH - width)),
    y: getAgentTownSnappedLayoutValueInRange(Number(rect?.y || 0), 0, Math.max(0, VISUAL_GAME_HEIGHT - height)),
    width,
    height,
  };
}

function snapAgentTownLayoutValue(value) {
  return Math.round(Number(value || 0) / AGENT_TOWN_LAYOUT_EDIT_SNAP) * AGENT_TOWN_LAYOUT_EDIT_SNAP;
}

function snapAgentTownLayoutOffset(offset) {
  return {
    x: snapAgentTownLayoutValue(offset.x),
    y: snapAgentTownLayoutValue(offset.y),
  };
}

function clampAgentTownOffset(baseRect, offset) {
  return {
    x: getAgentTownSnappedLayoutValueInRange(offset.x, -baseRect.x, VISUAL_GAME_WIDTH - (baseRect.x + baseRect.width)),
    y: getAgentTownSnappedLayoutValueInRange(offset.y, -baseRect.y, VISUAL_GAME_HEIGHT - (baseRect.y + baseRect.height)),
  };
}

function visualGameRectsOverlap(left, right, gap = 0) {
  if (!left || !right) {
    return false;
  }

  return (
    left.x - gap < right.x + right.width
    && left.x + left.width + gap > right.x
    && left.y - gap < right.y + right.height
    && left.y + left.height + gap > right.y
  );
}

function getAgentTownPluginBuildingPlaces() {
  return getAgentTownPluginBuildingBlueprints()
    .map((blueprint) =>
      getVisualGameTownVirtualPlace({
        ...blueprint,
        spots: [],
        entrance: { side: "bottom" },
        baseAnchor: {
          x: blueprint.baseRect.x + blueprint.baseRect.width / 2,
          y: blueprint.baseRect.y + blueprint.baseRect.height,
        },
      }),
    )
    .filter(Boolean);
}

function getAgentTownVisibleBuildingPlaces() {
  const places = [
    ...getAgentTownProviderDorms(),
    getVisualGameTownPlace("occupations"),
    getVisualGameTownPlace("library"),
    getVisualGameTownPlace("workshop"),
    isPluginIdInstalled("browser-use") ? getVisualGameTownPlace("browser") : null,
    getVisualGameTownPlace("automations"),
    getVisualGameTownPlace(VISUAL_GAME_DOGHOUSE_BUILDING_ID),
    isPluginIdInstalled("ottoauth") ? getVisualGameTownPlace("ottoauth") : null,
    isVideoMemoryPluginInstalled() ? getVisualGameTownPlace("camera") : null,
    ...getAgentTownPluginBuildingPlaces(),
    getVisualGameTownPlace(VISUAL_GAME_SYSTEM_BUILDING_ID),
    isLocalhostAppsEnabled() ? getVisualGameTownPlace("dock") : null,
  ];

  return places.filter((place) => place?.id && place.rect);
}

function getAgentTownPlaceCollision(candidateRect, placeId) {
  return getAgentTownVisibleBuildingPlaces()
    .filter((place) => place.id !== placeId)
    .find((place) => visualGameRectsOverlap(candidateRect, place.rect, AGENT_TOWN_PLACE_COLLISION_GAP))
    || null;
}

function offsetVisualGameRect(rect, offset) {
  return {
    ...rect,
    x: rect.x + offset.x,
    y: rect.y + offset.y,
  };
}

function offsetVisualGamePoint(point, offset) {
  return {
    x: point.x + offset.x,
    y: point.y + offset.y,
  };
}

function getVisualGameTownPlace(placeId) {
  const place = getVisualGamePlace(VISUAL_GAME_MAP_LAYOUT, placeId);
  if (!place) {
    return null;
  }

  return getVisualGameTownVirtualPlace({
    ...place,
    baseRect: place.rect,
    spots: Array.isArray(place.spots) ? place.spots : [],
  });
}

function getVisualGameTownVirtualPlace(place) {
  if (!place) {
    return null;
  }

  const placeId = place.id || "";
  const baseRect = place.baseRect || place.rect || { x: 0, y: 0, width: 1, height: 1 };
  const offset = getAgentTownLayoutOffset("place", placeId);
  const rect = offsetVisualGameRect(baseRect, offset);
  const spots = Array.isArray(place.spots) ? place.spots.map((spot) => offsetVisualGamePoint(spot, offset)) : [];
  const anchor =
    place.baseAnchor
      ? offsetVisualGamePoint(place.baseAnchor, offset)
      : place.cell
        ? offsetVisualGamePoint(getVisualGamePlaceAnchor(place), offset)
        : { x: rect.x + rect.width / 2, y: rect.y + rect.height };

  return {
    ...place,
    rect,
    spots,
    townOffset: offset,
    townAnchor: anchor,
  };
}

function getVisualGameTownPlaceAnchor(place) {
  return place?.townAnchor || getVisualGamePlaceAnchor(place);
}

function getVisualGameTownRoadRects() {
  return getVisualGameRoadRects(VISUAL_GAME_MAP_LAYOUT).map((road) => {
    const offset = getAgentTownLayoutOffset("road", road.id);
    return {
      ...road,
      baseRect: road.rect,
      rect: offsetVisualGameRect(road.rect, offset),
      townOffset: offset,
    };
  });
}

function getAgentTownRoadBaseBounds(roadId) {
  const rects = getVisualGameRoadRects(VISUAL_GAME_MAP_LAYOUT)
    .filter((road) => road.id === roadId)
    .map((road) => road.rect);
  if (!rects.length) {
    return { x: 0, y: 0, width: VISUAL_GAME_WIDTH, height: VISUAL_GAME_HEIGHT };
  }

  const minX = Math.min(...rects.map((rect) => rect.x));
  const minY = Math.min(...rects.map((rect) => rect.y));
  const maxX = Math.max(...rects.map((rect) => rect.x + rect.width));
  const maxY = Math.max(...rects.map((rect) => rect.y + rect.height));
  return {
    x: minX,
    y: minY,
    width: maxX - minX,
    height: maxY - minY,
  };
}

function getAgentTownProviderDisplayLabel(provider) {
  return provider?.label || provider?.defaultName || "Agent";
}

function getAgentTownProviderPriority(provider) {
  const priority = ["claude", "codex"];
  const index = priority.indexOf(provider?.id || "");
  return index >= 0 ? index : priority.length;
}

function getAgentTownProviderDormPalette(providerId) {
  const normalizedProviderId = providerId;
  const palettes = {
    claude: {
      floor: "#8a5a3e",
      wall: "#6a4237",
      trim: "#3b251f",
      blanket: "#d77b4a",
      pillow: "#f2d2b2",
      floorPattern: "claude",
      floorPatternColor: "#ffe8c7",
      floorPatternAlpha: 0.62,
    },
    codex: {
      floor: "#23584c",
      wall: "#1b3f38",
      trim: "#112b26",
      blanket: "#7ce3c7",
      pillow: "#d8fff6",
      floorPattern: "codex",
      floorPatternColor: "#d8fff6",
      floorPatternAlpha: 0.46,
    },
  };

  return palettes[normalizedProviderId] || {
    floor: "#826449",
    wall: "#63463b",
    trim: "#3b2a22",
    blanket: "#7895b4",
    pillow: "#f1d9a6",
  };
}

function getVisualGameProviderAgentPalette(providerId) {
  const normalizedProviderId = providerId;
  const palettes = {
    claude: {
      hat: "#b65d3d",
      brim: "#713624",
      hair: "#33231c",
      skin: "#f2c29a",
      coat: "#d77b4a",
      trim: "#ffd0a3",
      pants: "#2f2730",
      boots: "#57331f",
    },
    codex: {
      hat: "#2f8d79",
      brim: "#145248",
      hair: "#241c18",
      skin: "#e8b484",
      coat: "#35b89d",
      trim: "#d8fff6",
      pants: "#173f3a",
      boots: "#102923",
    },
  };

  return palettes[normalizedProviderId] || null;
}

function getAgentTownProviderDorms() {
  const providers = (Array.isArray(state.providers) ? state.providers : [])
    .filter((provider) => provider?.available && provider.id !== "shell")
    .sort((left, right) => getAgentTownProviderPriority(left) - getAgentTownProviderPriority(right));

  if (!providers.length) {
    return [getVisualGameTownVirtualPlace({
      id: "dormitory",
      label: "Dormitory",
      meta: "quiet beds",
      baseRect: getVisualGamePlace(VISUAL_GAME_MAP_LAYOUT, "dormitory")?.rect || { x: 4, y: 4, width: 172, height: 52 },
      baseAnchor: getVisualGamePlaceAnchor(getVisualGamePlace(VISUAL_GAME_MAP_LAYOUT, "dormitory")),
      beds: [],
      spots: [
        { x: 26, y: 47 },
        { x: 52, y: 47 },
        { x: 78, y: 47 },
        { x: 104, y: 47 },
      ],
      entrance: { side: "bottom" },
      providerId: "",
    })];
  }

  return providers.slice(0, AGENT_TOWN_DORM_SLOT_RECTS.length).map((provider, index) => {
    const baseRect = AGENT_TOWN_DORM_SLOT_RECTS[index];
    const label = `${getAgentTownProviderDisplayLabel(provider)} Dorm`;
    return getVisualGameTownVirtualPlace({
      id: `provider-dorm-${provider.id}`,
      label,
      meta: provider.available ? "installed" : "offline",
      baseRect,
      baseAnchor: { x: baseRect.x + baseRect.width / 2, y: baseRect.y + baseRect.height },
      beds: [],
      spots: [
        { x: baseRect.x + baseRect.width * 0.36, y: baseRect.y + baseRect.height - 10 },
        { x: baseRect.x + baseRect.width * 0.66, y: baseRect.y + baseRect.height - 10 },
        { x: baseRect.x + baseRect.width * 0.5, y: baseRect.y + baseRect.height - 25 },
      ],
      entrance: { side: "bottom" },
      providerId: provider.id,
    });
  });
}

function getAgentTownDormForAgent(agent) {
  const dorms = getAgentTownProviderDorms();
  if (!dorms.length) {
    return null;
  }

  return dorms.find((dorm) => dorm.providerId && dorm.providerId === agent.providerId) || dorms[agent.familyIndex % dorms.length] || dorms[0];
}

function isAgentTownPluginBuilding(plugin) {
  const pluginId = getPluginId(plugin);
  return Boolean(pluginId && !AGENT_TOWN_SPECIAL_BUILDING_IDS.has(pluginId));
}

function isAgentTownFunctionalPlugin(plugin) {
  const pluginId = getPluginId(plugin);
  return Boolean(isAgentTownPluginBuilding(plugin) && pluginId !== "buildinghub");
}

function getAgentTownFunctionalPlugins() {
  return PLUGIN_CATALOG
    .filter(isAgentTownFunctionalPlugin)
    .sort((left, right) => {
      const leftInstalled = isPluginInstalled(left) ? 1 : 0;
      const rightInstalled = isPluginInstalled(right) ? 1 : 0;
      if (leftInstalled !== rightInstalled) {
        return rightInstalled - leftInstalled;
      }
      const leftPending = isAgentTownFunctionalPending(getPluginId(left)) ? 1 : 0;
      const rightPending = isAgentTownFunctionalPending(getPluginId(right)) ? 1 : 0;
      if (leftPending !== rightPending) {
        return rightPending - leftPending;
      }
      return String(left.name || "").localeCompare(String(right.name || ""));
    });
}

function getAgentTownUnplacedFunctionalPlugins() {
  return getAgentTownFunctionalPlugins()
    .filter((plugin) => isPluginInstalled(plugin))
    .filter((plugin) => isAgentTownFunctionalPending(getPluginId(plugin)));
}

function getAgentTownPlacedFunctionalPluginIds() {
  return new Set(
    getAgentTownFunctionalPlugins()
      .filter((plugin) => isPluginInstalled(plugin) && !isAgentTownFunctionalPending(getPluginId(plugin)))
      .map(getPluginId),
  );
}

function getAgentTownBuildingInstallStatus(plugin) {
  const pluginId = getPluginId(plugin);
  if (!pluginId) return "installed";
  if (pluginId === "buildinghub") return "installed";
  const job = state.buildingInstallJobs && state.buildingInstallJobs[pluginId];
  if (job) {
    if (job.status === "starting" || job.status === "running") return "installing";
    if (job.status === "auth-required") return "auth-required";
    if (job.status === "failed") return "failed";
  }
  if (isPluginInstalled(plugin)) return "installed";
  // Has placement record but no install in flight and not yet installed.
  return "placed";
}

function getAgentTownInstallStatusMeta(installStatus, fallbackMeta) {
  if (installStatus === "installing") return "installing…";
  if (installStatus === "auth-required") return "needs setup";
  if (installStatus === "failed") return "setup failed";
  if (installStatus === "placed") return "needs setup";
  return fallbackMeta;
}

function getAgentTownPluginBuildingBlueprints() {
  // Visibility = placement, not install state. A building shows on the map
  // the moment it's dropped; appearance reflects install status. Pending
  // placements (user opened install dialog but hasn't dropped yet) stay
  // excluded.
  const visiblePlugins = PLUGIN_CATALOG
    .filter(isAgentTownPluginBuilding)
    .filter((plugin) => {
      const pluginId = getPluginId(plugin);
      if (isAgentTownFunctionalPending(pluginId)) return false;
      if (pluginId === "buildinghub") return true;
      const hasPlacement = Boolean(getAgentTownFunctionalPlacement(pluginId));
      return hasPlacement || isPluginInstalled(plugin);
    });

  let autoSlotIndex = 0;
  return visiblePlugins.map((plugin) => {
    const pluginId = getPluginId(plugin);
    const issue = getPluginBuildingIssue(plugin);
    const shape = getPluginBuildingShape(plugin);
    const placedRect = getAgentTownFunctionalPlacement(pluginId);
    const autoRect = placedRect ? null : AGENT_TOWN_PLUGIN_BUILDING_RECTS[autoSlotIndex++];
    const baseRect = placedRect || autoRect;
    if (!baseRect) {
      return null;
    }
    const installStatus = getAgentTownBuildingInstallStatus(plugin);
    const fallbackMeta = pluginId === "tailscale"
      ? getTailscaleBuildingMeta()
      : getPluginStatusBadgeLabel(plugin, issue) || plugin.category || "building";
    const meta = installStatus === "installed"
      ? fallbackMeta
      : getAgentTownInstallStatusMeta(installStatus, fallbackMeta);
    return {
      ...getAgentTownPluginBuildingPalette(pluginId),
      id: `building-${pluginId}`,
      issue,
      pluginId,
      label: plugin.name,
      meta,
      shape,
      baseRect,
      installStatus,
      action: {
        kind: "building",
        buildingId: pluginId,
        label: `${plugin.name} building`,
      },
    };
  }).filter(Boolean);
}

