function pushAgentTownPlaceHit(hitAreas, place, action) {
  if (!place?.rect) {
    return;
  }

  const { x, y, width, height } = place.rect;
  if (isAgentTownEditMode()) {
    hitAreas.push({
      x,
      y,
      width,
      height,
      kind: "town-place",
      placeId: place.id || "",
      baseRect: place.baseRect || place.rect,
      label: `Move ${place.label || "building"}`,
    });
    const pluginId = normalizeBuildingId(place.pluginId || action?.pluginId || action?.buildingId);
    if (pluginId && canUninstallAgentTownPlugin(pluginId)) {
      hitAreas.push({
        ...getAgentTownUninstallHitRect(place.rect),
        kind: "town-uninstall",
        pluginId,
        placeId: place.id || "",
        label: `Uninstall ${place.label || "building"}`,
      });
    }
    return;
  }

  if (action) {
    hitAreas.push({ x, y, width, height, ...action });
  }
}

function canUninstallAgentTownPlugin(pluginId) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  if (!normalizedPluginId) {
    return false;
  }

  const plugin = getPluginById(normalizedPluginId);
  if (!plugin || isPluginSystemApp(plugin) || !isPluginInstalled(plugin)) {
    return false;
  }

  return !getPluginPendingAction(plugin);
}

function getAgentTownUninstallHitRect(rect) {
  const size = AGENT_TOWN_UNINSTALL_HIT_SIZE;
  return {
    x: rect.x + rect.width - size * 0.5,
    y: rect.y - size * 0.5,
    width: size,
    height: size,
  };
}

function getVisualGameDefaultViewport() {
  return {
    width: VISUAL_GAME_WIDTH,
    height: VISUAL_GAME_HEIGHT,
  };
}

function getVisualGameCanvasViewport(canvas) {
  const rect = canvas instanceof HTMLCanvasElement ? canvas.getBoundingClientRect() : null;
  const width = Math.max(1, Number(rect?.width || 0));
  const height = Math.max(1, Number(rect?.height || 0));

  if (!rect || !width || !height) {
    return getVisualGameDefaultViewport();
  }

  return {
    width: Math.max(VISUAL_GAME_MIN_VIEWPORT_WIDTH, width / VISUAL_GAME_CSS_PIXELS_PER_WORLD_UNIT),
    height: Math.max(VISUAL_GAME_MIN_VIEWPORT_HEIGHT, height / VISUAL_GAME_CSS_PIXELS_PER_WORLD_UNIT),
  };
}

function getVisualGameCameraBounds(visibleWidth, visibleHeight) {
  const paddingX = Math.max(VISUAL_GAME_CAMERA_MIN_PADDING_X, visibleWidth * 0.5);
  const paddingY = Math.max(VISUAL_GAME_CAMERA_MIN_PADDING_Y, visibleHeight * 0.5);

  return {
    minX: -paddingX,
    minY: -paddingY,
    maxX: VISUAL_GAME_WIDTH + paddingX - visibleWidth,
    maxY: VISUAL_GAME_HEIGHT + paddingY - visibleHeight,
  };
}

function getVisualGameCenteredCamera(viewport = getVisualGameDefaultViewport(), zoom = getVisualGameFitZoom(viewport)) {
  return {
    x: (VISUAL_GAME_WIDTH - viewport.width / zoom) / 2,
    y: (VISUAL_GAME_HEIGHT - viewport.height / zoom) / 2,
    zoom,
  };
}

function getVisualGameFitZoom(viewport = getVisualGameDefaultViewport()) {
  return clamp(
    Math.min(1, viewport.width / VISUAL_GAME_WIDTH, viewport.height / VISUAL_GAME_HEIGHT),
    VISUAL_GAME_MIN_ZOOM,
    VISUAL_GAME_MAX_ZOOM,
  );
}

function normalizeVisualGameCamera(camera = {}, viewport = getVisualGameDefaultViewport()) {
  const zoom = clamp(Number(camera.zoom || 1), VISUAL_GAME_MIN_ZOOM, VISUAL_GAME_MAX_ZOOM);
  const visibleWidth = viewport.width / zoom;
  const visibleHeight = viewport.height / zoom;
  const bounds = getVisualGameCameraBounds(visibleWidth, visibleHeight);

  return {
    x: clamp(Number(camera.x || 0), bounds.minX, bounds.maxX),
    y: clamp(Number(camera.y || 0), bounds.minY, bounds.maxY),
    zoom,
  };
}

function setVisualGameCamera(camera, viewport = state.visualGame.viewport || getVisualGameDefaultViewport()) {
  state.visualGame.camera = normalizeVisualGameCamera(camera, viewport);
  return state.visualGame.camera;
}

function getVisualGameCamera(viewport = state.visualGame.viewport || getVisualGameDefaultViewport()) {
  return setVisualGameCamera(state.visualGame.camera || getVisualGameCenteredCamera(viewport), viewport);
}

function syncVisualGameCameraToViewport(viewport) {
  const previousViewport = state.visualGame.viewport;
  const currentCamera = state.visualGame.camera || getVisualGameCenteredCamera(viewport);
  const zoom = clamp(Number(currentCamera.zoom || 1), VISUAL_GAME_MIN_ZOOM, VISUAL_GAME_MAX_ZOOM);

  if (!previousViewport) {
    state.visualGame.viewport = viewport;
    return setVisualGameCamera(getVisualGameCenteredCamera(viewport, getVisualGameFitZoom(viewport)), viewport);
  }

  state.visualGame.viewport = viewport;
  if (
    Math.abs(previousViewport.width - viewport.width) > 0.25 ||
    Math.abs(previousViewport.height - viewport.height) > 0.25
  ) {
    const previousVisibleWidth = previousViewport.width / zoom;
    const previousVisibleHeight = previousViewport.height / zoom;
    const centerX = Number(currentCamera.x || 0) + previousVisibleWidth / 2;
    const centerY = Number(currentCamera.y || 0) + previousVisibleHeight / 2;
    return setVisualGameCamera({
      x: centerX - viewport.width / zoom / 2,
      y: centerY - viewport.height / zoom / 2,
      zoom,
    }, viewport);
  }

  return setVisualGameCamera(currentCamera, viewport);
}

function getVisualGameCameraWorldPoint(viewportPoint, viewport = state.visualGame.viewport || getVisualGameDefaultViewport()) {
  const camera = getVisualGameCamera(viewport);
  return {
    x: camera.x + viewportPoint.x / camera.zoom,
    y: camera.y + viewportPoint.y / camera.zoom,
  };
}

function zoomVisualGameCameraAt(viewportPoint, zoomFactor, viewport = state.visualGame.viewport || getVisualGameDefaultViewport()) {
  const camera = getVisualGameCamera(viewport);
  const worldPoint = getVisualGameCameraWorldPoint(viewportPoint, viewport);
  const nextZoom = clamp(camera.zoom * zoomFactor, VISUAL_GAME_MIN_ZOOM, VISUAL_GAME_MAX_ZOOM);
  return setVisualGameCamera({
    x: worldPoint.x - viewportPoint.x / nextZoom,
    y: worldPoint.y - viewportPoint.y / nextZoom,
    zoom: nextZoom,
  }, viewport);
}

function syncVisualGameCameraDebugAttributes(canvas, camera) {
  if (!(canvas instanceof HTMLCanvasElement) || !camera) {
    return;
  }

  const nextZoom = Number(camera.zoom || 0).toFixed(4);
  const nextX = Number(camera.x || 0).toFixed(2);
  const nextY = Number(camera.y || 0).toFixed(2);
  if (canvas.dataset.cameraZoom !== nextZoom) {
    canvas.dataset.cameraZoom = nextZoom;
  }
  if (canvas.dataset.cameraX !== nextX) {
    canvas.dataset.cameraX = nextX;
  }
  if (canvas.dataset.cameraY !== nextY) {
    canvas.dataset.cameraY = nextY;
  }
}

function centerVisualGameCameraOnWorldRect(rect, { paddingWorld = 56, maxZoom = 1.6 } = {}) {
  if (!rect) {
    return null;
  }

  const viewport = state.visualGame.viewport || getVisualGameDefaultViewport();
  const width = Math.max(32, Number(rect.width) || 0);
  const height = Math.max(32, Number(rect.height) || 0);
  const x = Number(rect.x);
  const y = Number(rect.y);
  if (!Number.isFinite(x) || !Number.isFinite(y)) {
    return null;
  }

  const paddedWidth = width + paddingWorld * 2;
  const paddedHeight = height + paddingWorld * 2;
  const fitZoom = Math.min(viewport.width / paddedWidth, viewport.height / paddedHeight);
  const zoom = clamp(
    Math.min(Number.isFinite(fitZoom) ? fitZoom : getVisualGameFitZoom(viewport), maxZoom),
    VISUAL_GAME_MIN_ZOOM,
    VISUAL_GAME_MAX_ZOOM,
  );

  return setVisualGameCamera({
    x: x + width / 2 - viewport.width / zoom / 2,
    y: y + height / 2 - viewport.height / zoom / 2,
    zoom,
  }, viewport);
}

function ensureVisualGameSimulationLoop() {
  if (state.visualGame.simulationFrameHandle || !state.swarmGraph.data) {
    return;
  }

  const tick = (time) => {
    state.visualGame.simulationFrameHandle = 0;
    const graph = state.swarmGraph.data;
    if (!graph) {
      return;
    }

    advanceVisualGameSimulation(time, graph);
    if (state.swarmGraph.data) {
      state.visualGame.simulationFrameHandle = window.requestAnimationFrame(tick);
    }
  };

  state.visualGame.simulationFrameHandle = window.requestAnimationFrame(tick);
}

function mountVisualPixelGame() {
  teardownVisualPixelGame();

  const canvas = document.querySelector("#visual-game-canvas");
  const zoomInButton = document.querySelector("#visual-game-zoom-in");
  const zoomOutButton = document.querySelector("#visual-game-zoom-out");
  const resetCameraButton = document.querySelector("#visual-game-reset-camera");
  const graph = getVisualGameGraphForDisplay();
  if (!(canvas instanceof HTMLCanvasElement) || !graph) {
    return;
  }
  ensureVisualGameSimulationLoop();

  const context = canvas.getContext("2d");
  if (!context) {
    return;
  }

  if (VISUAL_GAME_LAYOUT_ISSUES.length) {
    console.warn("Visual game layout issues:", VISUAL_GAME_LAYOUT_ISSUES);
  }

  context.imageSmoothingEnabled = false;
  if (!state.systemMetricsLoading) {
    void loadSystemMetrics();
  }

  let panState = null;
  let townDragState = null;
  let suppressClickUntil = 0;

  const resizeCanvasToDisplaySize = () => {
    const rect = canvas.getBoundingClientRect();
    const pixelRatio = clamp(window.devicePixelRatio || 1, 1, VISUAL_GAME_RENDER_SCALE);
    const nextWidth = Math.max(1, Math.round((rect.width || VISUAL_GAME_WIDTH) * pixelRatio));
    const nextHeight = Math.max(1, Math.round((rect.height || VISUAL_GAME_HEIGHT) * pixelRatio));

    if (canvas.width !== nextWidth || canvas.height !== nextHeight) {
      canvas.width = nextWidth;
      canvas.height = nextHeight;
      context.imageSmoothingEnabled = false;
    }
  };

  const getViewportPoint = (event) => {
    const rect = canvas.getBoundingClientRect();
    if (!rect.width || !rect.height) {
      return null;
    }

    const viewport = getVisualGameCanvasViewport(canvas);
    return {
      x: ((event.clientX - rect.left) / rect.width) * viewport.width,
      y: ((event.clientY - rect.top) / rect.height) * viewport.height,
    };
  };

  const getWorldPoint = (event) => {
    const point = getViewportPoint(event);
    return point ? getVisualGameCameraWorldPoint(point, getVisualGameCanvasViewport(canvas)) : null;
  };

  const getHitAtPoint = (point) => {
    if (!point) {
      return null;
    }

    for (let index = state.visualGame.hitAreas.length - 1; index >= 0; index -= 1) {
      const hit = state.visualGame.hitAreas[index];
      if (point.x >= hit.x && point.x <= hit.x + hit.width && point.y >= hit.y && point.y <= hit.y + hit.height) {
        return hit;
      }
    }

    return null;
  };

  const hoverElement = document.querySelector(".visual-game-hover");
  const getDefaultHoverLabel = () => (isAgentTownEditMode() ? "edit town: drag buildings or paths" : "agent town");
  const setHoverLabel = (label) => {
    const nextLabel = label || getDefaultHoverLabel();
    if (state.visualGame.hoverLabel === nextLabel) {
      return;
    }

    state.visualGame.hoverLabel = nextLabel;
    if (hoverElement instanceof HTMLElement) {
      hoverElement.textContent = nextLabel;
    }
  };

  const isTownEditHit = (hit) => isAgentTownEditMode() && (hit?.kind === "town-place" || hit?.kind === "town-road");
  const updateBuilderPlacementFromEvent = (event) => {
    if (!state.visualGame.builderPlacement) {
      return false;
    }

    hideVisualGameAgentHoverProfile();
    const point = getWorldPoint(event);
    if (!point) {
      return true;
    }

    const preview = updateAgentTownBuilderPlacementPreview(point);
    const blockedLabel = preview?.blocker?.label || "building";
    canvas.classList.add("is-builder-placement");
    canvas.classList.toggle("is-editing-blocked", Boolean(preview?.blocker));
    setHoverLabel(preview?.blocker ? `blocked by ${blockedLabel}` : `place ${state.visualGame.builderPlacement.label}`);
    event.preventDefault();
    return true;
  };
  const commitBuilderPlacementFromEvent = (event) => {
    if (!state.visualGame.builderPlacement) {
      return false;
    }

    const point = getWorldPoint(event);
    if (!point) {
      return true;
    }

    const placed = commitAgentTownBuilderPlacement(point);
    canvas.classList.toggle("is-editing-blocked", !placed);
    if (placed) {
      setHoverLabel(state.visualGame.builderPlacement ? `place ${state.visualGame.builderPlacement.label}` : "placed");
    } else {
      setHoverLabel("blocked");
    }
    event.preventDefault();
    return true;
  };
  const startTownEditDrag = (event, hit) => {
    const worldPoint = getWorldPoint(event);
    if (!worldPoint || !isTownEditHit(hit)) {
      return false;
    }

    const kind = hit.kind === "town-road" ? "road" : "place";
    const id = hit.roadId || hit.placeId || "";
    if (!id) {
      return false;
    }

    townDragState = {
      pointerId: event.pointerId,
      kind,
      id,
      label: hit.label || "Move town item",
      startClientX: event.clientX,
      startClientY: event.clientY,
      startWorldX: worldPoint.x,
      startWorldY: worldPoint.y,
      startOffset: getAgentTownLayoutOffset(kind, id),
      lastValidOffset: getAgentTownLayoutOffset(kind, id),
      baseRect: hit.baseRect || (kind === "road" ? getAgentTownRoadBaseBounds(id) : { x: 0, y: 0, width: 1, height: 1 }),
      moved: false,
    };
    canvas.classList.add("is-editing-drag");
    canvas.setPointerCapture?.(event.pointerId);
    setHoverLabel(townDragState.label);
    hideVisualGameAgentHoverProfile();
    event.preventDefault();
    return true;
  };
  const updateTownEditDrag = (event) => {
    if (!townDragState || townDragState.pointerId !== event.pointerId) {
      return false;
    }

    const worldPoint = getWorldPoint(event);
    if (!worldPoint) {
      return true;
    }

    const distance = Math.hypot(event.clientX - townDragState.startClientX, event.clientY - townDragState.startClientY);
    townDragState.moved = townDragState.moved || distance >= VISUAL_GAME_DRAG_SLOP_PX;
    const proposedOffset = clampAgentTownOffset(
      townDragState.baseRect,
      snapAgentTownLayoutOffset({
        x: townDragState.startOffset.x + worldPoint.x - townDragState.startWorldX,
        y: townDragState.startOffset.y + worldPoint.y - townDragState.startWorldY,
      }),
    );
    const blockedPlace =
      townDragState.kind === "place"
        ? getAgentTownPlaceCollision(offsetVisualGameRect(townDragState.baseRect, proposedOffset), townDragState.id)
        : null;
    const nextOffset = blockedPlace ? townDragState.lastValidOffset : proposedOffset;
    if (!blockedPlace) {
      townDragState.lastValidOffset = nextOffset;
    }
    setAgentTownLayoutOffset(townDragState.kind, townDragState.id, nextOffset);
    canvas.classList.add("is-dragging");
    canvas.classList.toggle("is-editing-blocked", Boolean(blockedPlace));
    setHoverLabel(blockedPlace ? `blocked by ${blockedPlace.label || "building"}` : townDragState.label);
    event.preventDefault();
    return true;
  };
  const finishTownEditDrag = (event) => {
    if (!townDragState || townDragState.pointerId !== event.pointerId) {
      return false;
    }

    if (townDragState.moved) {
      suppressClickUntil = Date.now() + 250;
      saveAgentTownLayoutPreferences();
    }
    townDragState = null;
    canvas.classList.remove("is-editing-drag", "is-editing-blocked", "is-dragging");
    canvas.releasePointerCapture?.(event.pointerId);
    const hit = getHitAtPoint(getWorldPoint(event));
    canvas.classList.toggle("is-actionable", Boolean(hit));
    setHoverLabel(hit?.label || "");
    updateVisualGameAgentHoverProfile(event, hit);
    return true;
  };
  const onPointerMove = (event) => {
    if (updateBuilderPlacementFromEvent(event)) {
      return;
    }

    if (updateTownEditDrag(event)) {
      return;
    }

    if (panState?.pointerId === event.pointerId) {
      hideVisualGameAgentHoverProfile();
      const rect = canvas.getBoundingClientRect();
      if (!rect.width || !rect.height) {
        return;
      }

      const viewport = getVisualGameCanvasViewport(canvas);
      const deltaX = ((event.clientX - panState.startClientX) / rect.width) * viewport.width;
      const deltaY = ((event.clientY - panState.startClientY) / rect.height) * viewport.height;
      const distance = Math.hypot(event.clientX - panState.startClientX, event.clientY - panState.startClientY);
      panState.moved = panState.moved || distance >= VISUAL_GAME_DRAG_SLOP_PX;
      setVisualGameCamera({
        x: panState.startCamera.x - deltaX / panState.startCamera.zoom,
        y: panState.startCamera.y - deltaY / panState.startCamera.zoom,
        zoom: panState.startCamera.zoom,
      }, viewport);
      canvas.classList.toggle("is-dragging", panState.moved);
      setHoverLabel(panState.moved ? "move map" : "");
      event.preventDefault();
      return;
    }

    const hit = getHitAtPoint(getWorldPoint(event));
    canvas.classList.toggle("is-actionable", Boolean(hit));
    setHoverLabel(hit?.label || "");
    updateVisualGameAgentHoverProfile(event, hit);
  };
  const onPointerLeave = () => {
    if (!panState && !townDragState) {
      canvas.classList.remove("is-actionable");
      if (!state.visualGame.builderPlacement) {
        canvas.classList.remove("is-builder-placement", "is-editing-blocked");
      }
      setHoverLabel("");
      hideVisualGameAgentHoverProfile();
    }
  };
  const onPointerDown = (event) => {
    if (event.button !== 0) {
      return;
    }

    const point = getViewportPoint(event);
    if (!point) {
      return;
    }

    if (state.visualGame.builderPlacement) {
      updateBuilderPlacementFromEvent(event);
      return;
    }

    const editHit = getHitAtPoint(getWorldPoint(event));
    if (editHit?.kind === "town-uninstall") {
      event.preventDefault();
      return;
    }
    if (startTownEditDrag(event, editHit)) {
      return;
    }

    panState = {
      pointerId: event.pointerId,
      startClientX: event.clientX,
      startClientY: event.clientY,
      startCamera: { ...getVisualGameCamera(getVisualGameCanvasViewport(canvas)) },
      moved: false,
    };
    canvas.classList.add("is-panning");
    canvas.setPointerCapture?.(event.pointerId);
  };
  const endPointerPan = (event) => {
    if (finishTownEditDrag(event)) {
      return;
    }

    if (!panState || panState.pointerId !== event.pointerId) {
      return;
    }

    if (panState.moved) {
      suppressClickUntil = Date.now() + 250;
    }
    panState = null;
    canvas.classList.remove("is-panning", "is-dragging");
    canvas.releasePointerCapture?.(event.pointerId);
    const hit = getHitAtPoint(getWorldPoint(event));
    canvas.classList.toggle("is-actionable", Boolean(hit));
    setHoverLabel(hit?.label || "");
    updateVisualGameAgentHoverProfile(event, hit);
  };
  const onClick = (event) => {
    if (Date.now() < suppressClickUntil) {
      event.preventDefault();
      return;
    }

    if (commitBuilderPlacementFromEvent(event)) {
      return;
    }

    const hit = getHitAtPoint(getWorldPoint(event));
    if (hit?.kind === "town-uninstall" && hit.pluginId) {
      event.preventDefault();
      hideVisualGameAgentHoverProfile();
      void uninstallAgentTownBuilding(hit.pluginId);
      return;
    }
    if (isTownEditHit(hit)) {
      event.preventDefault();
      return;
    }

    if (hit) {
      event.preventDefault();
      hideVisualGameAgentHoverProfile();
      void handleVisualGameHit(hit);
      return;
    }

    if (clearVisualGameSelection()) {
      event.preventDefault();
    }
  };
  const onWheel = (event) => {
    const point = getViewportPoint(event);
    if (!point) {
      return;
    }

    event.preventDefault();
    const zoomFactor = Math.exp(-event.deltaY * 0.0014);
    const viewport = getVisualGameCanvasViewport(canvas);
    zoomVisualGameCameraAt(point, zoomFactor, viewport);
    const hit = getHitAtPoint(getVisualGameCameraWorldPoint(point, viewport));
    canvas.classList.toggle("is-actionable", Boolean(hit));
    setHoverLabel(hit?.label || "");
    updateVisualGameAgentHoverProfile(event, hit);
  };
  const zoomCameraFromCenter = (zoomFactor) => {
    const viewport = getVisualGameCanvasViewport(canvas);
    zoomVisualGameCameraAt({ x: viewport.width / 2, y: viewport.height / 2 }, zoomFactor, viewport);
  };
  const resetCamera = () => {
    const viewport = getVisualGameCanvasViewport(canvas);
    state.visualGame.viewport = viewport;
    setVisualGameCamera(getVisualGameCenteredCamera(viewport, getVisualGameFitZoom(viewport)), viewport);
    setHoverLabel("agent town");
  };
  const onLostPointerCapture = () => {
    panState = null;
    townDragState = null;
    canvas.classList.remove("is-panning", "is-editing-drag", "is-editing-blocked", "is-dragging", "is-builder-placement");
    hideVisualGameAgentHoverProfile();
  };
  const onZoomInClick = () => zoomCameraFromCenter(VISUAL_GAME_ZOOM_STEP);
  const onZoomOutClick = () => zoomCameraFromCenter(1 / VISUAL_GAME_ZOOM_STEP);
  const onDragOver = (event) => {
    if (!state.visualGame.builderPlacement) {
      return;
    }

    event.preventDefault();
    if (event.dataTransfer) {
      event.dataTransfer.dropEffect = state.visualGame.builderPlacement.kind === "functional" ? "move" : "copy";
    }
    updateBuilderPlacementFromEvent(event);
  };
  const onDrop = (event) => {
    if (!state.visualGame.builderPlacement) {
      return;
    }

    commitBuilderPlacementFromEvent(event);
  };
  const onKeyDown = (event) => {
    if (!state.visualGame.builderPlacement) {
      return;
    }

    if (event.key === "Escape") {
      event.preventDefault();
      clearAgentTownBuilderPlacement();
      return;
    }

    const target = event.target;
    const isEditableTarget =
      target instanceof HTMLElement &&
      (target.isContentEditable || Boolean(target.closest("input, textarea, select")));
    if (
      event.repeat ||
      event.metaKey ||
      event.ctrlKey ||
      event.altKey ||
      isEditableTarget ||
      String(event.key || "").toLowerCase() !== "r"
    ) {
      return;
    }

    event.preventDefault();
    const preview = rotateAgentTownBuilderPlacement();
    const blockedLabel = preview?.blocker?.label || "building";
    canvas.classList.add("is-builder-placement");
    canvas.classList.toggle("is-editing-blocked", Boolean(preview?.blocker));
    setHoverLabel(preview?.blocker ? `blocked by ${blockedLabel}` : `place ${state.visualGame.builderPlacement.label}`);
  };

  canvas.addEventListener("pointerdown", onPointerDown);
  canvas.addEventListener("pointermove", onPointerMove);
  canvas.addEventListener("pointerup", endPointerPan);
  canvas.addEventListener("pointercancel", endPointerPan);
  canvas.addEventListener("lostpointercapture", onLostPointerCapture);
  canvas.addEventListener("pointerleave", onPointerLeave);
  canvas.addEventListener("click", onClick);
  canvas.addEventListener("wheel", onWheel, { passive: false });
  canvas.addEventListener("dragover", onDragOver);
  canvas.addEventListener("drop", onDrop);
  window.addEventListener("keydown", onKeyDown);
  zoomInButton?.addEventListener("click", onZoomInClick);
  zoomOutButton?.addEventListener("click", onZoomOutClick);
  resetCameraButton?.addEventListener("click", resetCamera);

  const drawFrame = (time) => {
    state.visualGame.hitAreas = [];
    resizeCanvasToDisplaySize();
    const viewport = getVisualGameCanvasViewport(canvas);
    const camera = syncVisualGameCameraToViewport(viewport);
    syncVisualGameCameraDebugAttributes(canvas, camera);
    const renderScale = canvas.width / viewport.width;
    const visibleWorld = {
      x: camera.x,
      y: camera.y,
      width: viewport.width / camera.zoom,
      height: viewport.height / camera.zoom,
    };
    if (state.visualGame.builderPlacement?.centerOnNextFrame) {
      updateAgentTownBuilderPlacementPreview({
        x: visibleWorld.x + visibleWorld.width / 2,
        y: visibleWorld.y + visibleWorld.height / 2,
      }, { preferOpen: true });
    }
    context.setTransform(1, 0, 0, 1, 0, 0);
    context.clearRect(0, 0, canvas.width, canvas.height);
    context.setTransform(
      renderScale * camera.zoom,
      0,
      0,
      renderScale * camera.zoom,
      -camera.x * renderScale * camera.zoom,
      -camera.y * renderScale * camera.zoom,
    );
    context.imageSmoothingEnabled = false;
    const gameModel = getVisualGameModel(graph);
    const agents = advanceVisualGameSimulation(time, graph);
    drawVisualGameScene(context, graph, gameModel, time, state.visualGame.hitAreas, visibleWorld, agents);
    syncGuidedOnboardingVisualFocus();
    state.visualGame.frameHandle = window.requestAnimationFrame(drawFrame);
  };

  state.visualGame.cleanup = () => {
    canvas.removeEventListener("pointerdown", onPointerDown);
    canvas.removeEventListener("pointermove", onPointerMove);
    canvas.removeEventListener("pointerup", endPointerPan);
    canvas.removeEventListener("pointercancel", endPointerPan);
    canvas.removeEventListener("lostpointercapture", onLostPointerCapture);
    canvas.removeEventListener("pointerleave", onPointerLeave);
    canvas.removeEventListener("click", onClick);
    canvas.removeEventListener("wheel", onWheel);
    canvas.removeEventListener("dragover", onDragOver);
    canvas.removeEventListener("drop", onDrop);
    window.removeEventListener("keydown", onKeyDown);
    zoomInButton?.removeEventListener("click", onZoomInClick);
    zoomOutButton?.removeEventListener("click", onZoomOutClick);
    resetCameraButton?.removeEventListener("click", resetCamera);
  };
  state.visualGame.frameHandle = window.requestAnimationFrame(drawFrame);
}

async function handleVisualGameHit(hit) {
  if (!hit || !hit.kind) {
    return;
  }

  if (hit.kind === "session" && hit.sessionId) {
    const nextSession = state.sessions.find((session) => session.id === hit.sessionId);
    if (!nextSession) {
      void loadSessions();
      return;
    }
    markSessionRead(hit.sessionId, { refresh: false });
    state.activeSessionId = hit.sessionId;
    state.visualGame.selectedSessionId = hit.sessionId;
    state.visualGame.selectedBrowserUseSessionId = hit.browserUseSessionId || "";
    state.visualGame.selectedBuildingId = "";
    state.visualGame.selectedCosmeticDecorationId = "";
    setAgentProfileSelection({
      sessionId: hit.sessionId,
      subagentId: hit.subagentId || hit.agentId || "",
      browserUseSessionId: hit.browserUseSessionId || "",
    });
    void recordAgentTownEvent("agent_clicked", {
      label: hit.label || nextSession.name || "agent",
      metadata: { sessionId: hit.sessionId },
    });
    expandSessionProject(nextSession.cwd);
    renderShell();
    connectToSession(state.activeSessionId);
    closeMobileSidebar();
    return;
  }

  if (hit.kind === "browser" && hit.browserUseSessionId) {
    await openBrowserUseSession(hit.browserUseSessionId);
    return;
  }

  if (hit.kind === "port" && hit.port) {
    openPortPreview(hit.port);
    return;
  }

  if (hit.kind === "main-view" && hit.view) {
    await openMainView(hit.view, { buildingId: hit.pluginId || "" });
    return;
  }

  if (hit.kind === "building" && hit.buildingId) {
    openVisualGameBuildingPanel(hit.buildingId);
    return;
  }

  if (hit.kind === "decoration" && hit.decorationId) {
    openAgentTownCosmeticPanel(hit.decorationId);
    return;
  }

  if (hit.kind === "new-session") {
    await startNewAgentFromUi({ openInTown: true });
  }
}

async function uninstallAgentTownBuilding(pluginId) {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  if (!canUninstallAgentTownPlugin(normalizedPluginId)) {
    return;
  }

  const plugin = getPluginById(normalizedPluginId);
  const pluginName = plugin?.name || "this building";
  const confirmed = window.confirm(
    `Uninstall ${pluginName}? Saved setup and settings will stay, but the building will be removed from Agent Town.`,
  );
  if (!confirmed) {
    return;
  }

  await setPluginInstalled(normalizedPluginId, false);
}

function getVisualGameModel(graph) {
  return {
    pathBucketCount: collectSwarmPathBuckets(graph).length,
    dirtyCount: Number(graph?.git?.dirtyCount || 0),
    gpuFactories: getVisualGameGpuFactories(),
  };
}

function getVisualGameGpuFactories() {
  const gpus = Array.isArray(state.systemMetrics?.gpus) ? state.systemMetrics.gpus : [];
  return gpus.map((gpu, index) => {
    const utilizationPercent = getFiniteMetricPercent(gpu?.utilizationPercent);
    const memoryUtilizationPercent = getFiniteMetricPercent(gpu?.memoryUtilizationPercent);
    const powerW = getFiniteVisualGameMetric(gpu?.powerW);
    const powerLimitW = getFiniteVisualGameMetric(gpu?.powerLimitW);
    const active = isVisualGameGpuActive({
      utilizationPercent,
      memoryUtilizationPercent,
      powerW,
      powerLimitW,
    });

    return {
      id: String(gpu?.id || `gpu-${index}`),
      name: gpu?.name || `GPU ${index + 1}`,
      label: `GPU ${index + 1}`,
      utilizationPercent,
      memoryUtilizationPercent,
      powerW,
      powerLimitW,
      active,
    };
  });
}

function getFiniteVisualGameMetric(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

function isVisualGameGpuActive(gpu) {
  if (Number.isFinite(gpu.utilizationPercent) && gpu.utilizationPercent >= VISUAL_GAME_GPU_ACTIVE_THRESHOLD) {
    return true;
  }

  if (Number.isFinite(gpu.memoryUtilizationPercent) && gpu.memoryUtilizationPercent >= 10) {
    return true;
  }

  if (Number.isFinite(gpu.powerW)) {
    const poweredThreshold = Number.isFinite(gpu.powerLimitW) ? Math.max(10, gpu.powerLimitW * 0.08) : 10;
    return gpu.powerW >= poweredThreshold;
  }

  return false;
}

function drawVisualGameScene(context, graph, model, time, hitAreas, visibleWorld = null, agents = advanceVisualGameSimulation(time, graph)) {
  context.save();
  context.imageSmoothingEnabled = false;
  const deskAgents = agents.filter((agent) => agent.destination === "desk");
  const browserAgents = agents.filter((agent) => agent.destination === "browser");
  const ottoAuthAgents = agents.filter((agent) => agent.destination === "ottoauth");
  const cameraAgents = agents.filter((agent) => agent.destination === "camera");
  const harborAgents = agents.filter((agent) => agent.destination === "harbor");
  const libraryAgents = agents.filter((agent) => agent.destination === "library");
  const sleepingAgents = agents.filter((agent) => agent.destination === "sleep");

  drawVisualGameGround(context, time, visibleWorld);
  drawVisualGamePaths(context, hitAreas);
  drawAgentTownScenery(context, hitAreas, time, visibleWorld);
  drawVisualGameSleepingQuarters(context, hitAreas, time, sleepingAgents);
  drawVisualGameSchool(context, hitAreas, time);
  drawVisualGameLibrary(context, hitAreas, model, time, libraryAgents);
  drawVisualGameWorkshop(context, hitAreas, time, deskAgents);
  if (isPluginIdInstalled("browser-use")) {
    drawVisualGameBrowserLab(context, hitAreas, time, browserAgents);
  }
  drawVisualGameCampanile(context, hitAreas, time);
  drawVisualGameDoghouse(context, hitAreas, time);
  if (isPluginIdInstalled("ottoauth")) {
    drawVisualGameOttoAuth(context, hitAreas, time, ottoAuthAgents);
  }
  if (isVideoMemoryPluginInstalled()) {
    drawVisualGameCameraRoom(context, hitAreas, time, cameraAgents);
  }
  drawAgentTownInstalledPluginBuildings(context, hitAreas, time, { harborAgents });
  drawVisualGameSystemBuilding(context, hitAreas, model.gpuFactories, time);
  if (isLocalhostAppsEnabled()) {
    drawVisualGameDock(context, hitAreas, time);
  }
  drawAgentTownBottleneckOverlays(context, time);

  if (isAgentTownEditMode()) {
    drawAgentTownEditOutlines(context, hitAreas);
  }

  drawAgentTownBuilderPlacementPulse(context, time);
  drawAgentTownBuilderPlacementPreview(context, time);

  for (const agent of agents.sort((left, right) => left.y - right.y)) {
    drawVisualGameAgent(context, agent, time, hitAreas);
  }
  drawVisualGameDog(context, time, hitAreas);
  drawAgentTownBuilderConstructionAgent(context, time);

  drawVisualGameForeground(context, time);
  context.restore();
}

function drawVisualGameGround(context, time, visibleWorld = null) {
  const theme = getAgentTownTheme();
  const ground = theme.ground || AGENT_TOWN_THEME_BY_ID.get(AGENT_TOWN_DEFAULT_THEME_ID).ground;
  const tiles = Array.isArray(ground.tiles) && ground.tiles.length ? ground.tiles : ["#34714f", "#2b6046", "#31694b"];
  const padding = VISUAL_GAME_TILE * 3;
  const left = Math.floor(((visibleWorld?.x ?? 0) - padding) / VISUAL_GAME_TILE) * VISUAL_GAME_TILE;
  const top = Math.floor(((visibleWorld?.y ?? 0) - padding) / VISUAL_GAME_TILE) * VISUAL_GAME_TILE;
  const right = Math.ceil(((visibleWorld?.x ?? 0) + (visibleWorld?.width ?? VISUAL_GAME_WIDTH) + padding) / VISUAL_GAME_TILE) * VISUAL_GAME_TILE;
  const bottom = Math.ceil(((visibleWorld?.y ?? 0) + (visibleWorld?.height ?? VISUAL_GAME_HEIGHT) + padding) / VISUAL_GAME_TILE) * VISUAL_GAME_TILE;

  context.fillStyle = ground.base || "#2f6849";
  context.fillRect(left, top, right - left, bottom - top);

  for (let y = top; y < bottom; y += VISUAL_GAME_TILE) {
    for (let x = left; x < right; x += VISUAL_GAME_TILE) {
      const hash = getVisualGameHash(Math.floor(x / VISUAL_GAME_TILE), Math.floor(y / VISUAL_GAME_TILE));
      context.fillStyle = tiles[hash % tiles.length];
      context.fillRect(x, y, VISUAL_GAME_TILE, VISUAL_GAME_TILE);

      if (hash % 4 === 0) {
        context.fillStyle = ground.detail || "#3d8356";
        context.fillRect(x + 3, y + 11, 2, 5);
        context.fillRect(x + 6, y + 9, 2, 7);
      }

      if (hash % 17 === 0) {
        context.fillStyle = ground.sparkle || "#e7ca79";
        context.fillRect(x + 11, y + 7 + Math.floor(Math.sin(time / 600 + hash) * 1), 2, 2);
      }
    }
  }
}

function drawVisualGamePaths(context, hitAreas = []) {
  for (const road of getVisualGameTownRoadRects()) {
    drawVisualGamePathRect(context, road.rect.x, road.rect.y, road.rect.width, road.rect.height);
    if (isAgentTownEditMode()) {
      hitAreas.push({
        x: road.rect.x,
        y: road.rect.y,
        width: road.rect.width,
        height: road.rect.height,
        kind: "town-road",
        roadId: road.id,
        baseRect: getAgentTownRoadBaseBounds(road.id),
        label: `Move ${road.id.replace(/-/g, " ")} path`,
      });
    }
  }
}

function drawVisualGamePathRect(context, x, y, width, height) {
  if (width <= 0 || height <= 0) {
    return;
  }

  const path = getAgentTownTheme().path || AGENT_TOWN_THEME_BY_ID.get(AGENT_TOWN_DEFAULT_THEME_ID).path;
  context.fillStyle = path.edge || "#c09a52";
  context.fillRect(x, y, width, height);
  context.fillStyle = path.fill || "#d1af63";
  context.fillRect(x + 3, y + 3, width - 6, height - 6);
  drawAgentTownPathSquares(context, x, y, width, height, path);
  context.fillStyle = path.detail || "#a87b3f";
  for (let offset = 0; offset < width; offset += 21) {
    context.fillRect(x + offset + 5, y + 7 + ((offset / 7) % 3), 6, 2);
  }
  context.fillStyle = path.shadow || "rgba(82, 58, 31, 0.2)";
  context.fillRect(x, y, width, 2);
  context.fillRect(x, y + height - 2, width, 2);
}

function drawAgentTownPathSquares(context, x, y, width, height, path) {
  const left = x + 6;
  const top = y + 6;
  const right = x + width - 5;
  const bottom = y + height - 5;

  if (right <= left || bottom <= top) {
    return;
  }

  const squareFill = path.square || "rgba(255, 242, 190, 0.24)";
  const squareAltFill = path.squareAlt || "rgba(118, 82, 43, 0.18)";
  const squareShadow = path.squareShadow || "rgba(78, 54, 28, 0.2)";
  for (let tileY = top; tileY < bottom; tileY += 11) {
    const row = Math.floor((tileY - top) / 11);
    const stagger = row % 2 === 0 ? 0 : 6;
    for (let tileX = left + stagger; tileX < right; tileX += 13) {
      const squareWidth = Math.min(8, right - tileX);
      const squareHeight = Math.min(5, bottom - tileY);
      if (squareWidth < 3 || squareHeight < 2) {
        continue;
      }
      const hash = getVisualGameHash(Math.floor(tileX / 3), Math.floor(tileY / 3));
      const nudgeX = (hash % 3) - 1;
      const nudgeY = Math.floor(hash / 5) % 2;
      context.fillStyle = hash % 4 === 0 ? squareAltFill : squareFill;
      context.fillRect(tileX + nudgeX, tileY + nudgeY, squareWidth, squareHeight);
      context.fillStyle = squareShadow;
      context.fillRect(tileX + nudgeX, tileY + nudgeY + squareHeight - 1, squareWidth, 1);
    }
  }
}

function drawAgentTownScenery(context, hitAreas, time, visibleWorld = null) {
  const palette = getAgentTownSceneryPalette();

  for (const paver of AGENT_TOWN_SCENERY_PAVERS) {
    if (isAgentTownSceneryVisible(getAgentTownPaverBounds(paver), visibleWorld)) {
      drawAgentTownPaverPatch(context, paver, palette);
    }
  }

  for (const fence of AGENT_TOWN_SCENERY_FENCES) {
    if (isAgentTownSceneryVisible(getAgentTownFenceBounds(fence), visibleWorld)) {
      drawAgentTownFence(context, fence, palette);
    }
  }

  for (const planter of AGENT_TOWN_SCENERY_PLANTERS) {
    if (isAgentTownSceneryVisible(planter, visibleWorld)) {
      drawAgentTownPlanter(context, planter, palette, time);
    }
  }

  for (const structure of AGENT_TOWN_SCENERY_STRUCTURES) {
    if (isAgentTownSceneryVisible(structure, visibleWorld)) {
      drawAgentTownCosmeticStructure(context, structure, palette, time);
    }
  }

  drawAgentTownPlacedCosmetics(context, hitAreas, time, visibleWorld, palette);
}

function getAgentTownSceneryPalette() {
  const theme = getAgentTownTheme();
  const path = theme.path || AGENT_TOWN_THEME_BY_ID.get(AGENT_TOWN_DEFAULT_THEME_ID).path || {};
  return {
    fenceShadow: "rgba(52, 34, 20, 0.28)",
    fenceDark: "#4f321f",
    fence: "#8a5a32",
    fenceLight: "#c08a52",
    paver: path.square || "rgba(225, 198, 136, 0.45)",
    paverAlt: path.squareAlt || "rgba(188, 148, 83, 0.38)",
    paverShadow: path.squareShadow || "rgba(72, 48, 24, 0.18)",
    planterShadow: "rgba(38, 25, 16, 0.24)",
    planterBox: "#74512e",
    planterTrim: "#b47a3c",
    leaf: "#4c9b57",
    leafAlt: "#77bd62",
    flower: "#f2cf66",
    structureShadow: "rgba(34, 24, 18, 0.28)",
    structureTrim: "#36281f",
  };
}

function isAgentTownSceneryVisible(rect, visibleWorld = null, padding = 44) {
  if (!visibleWorld) {
    return true;
  }

  return (
    rect.x + rect.width >= visibleWorld.x - padding
    && rect.x <= visibleWorld.x + visibleWorld.width + padding
    && rect.y + rect.height >= visibleWorld.y - padding
    && rect.y <= visibleWorld.y + visibleWorld.height + padding
  );
}

function getAgentTownFenceBounds(fence) {
  if (fence.orientation === "vertical") {
    return { x: fence.x, y: fence.y, width: 17, height: fence.length + 5 };
  }
  return { x: fence.x, y: fence.y, width: fence.length + 5, height: 17 };
}

function getAgentTownPaverBounds(paver) {
  const size = paver.size || 10;
  const gap = paver.gap ?? 2;
  return {
    x: paver.x,
    y: paver.y,
    width: paver.columns * size + Math.max(0, paver.columns - 1) * gap + Math.floor(size / 2),
    height: paver.rows * size + Math.max(0, paver.rows - 1) * gap,
  };
}

function drawAgentTownPaverPatch(context, paver, palette) {
  const size = paver.size || 10;
  const gap = paver.gap ?? 2;
  for (let row = 0; row < paver.rows; row += 1) {
    const offsetX = row % 2 === 0 ? 0 : Math.floor(size / 2);
    for (let column = 0; column < paver.columns; column += 1) {
      const x = paver.x + offsetX + column * (size + gap);
      const y = paver.y + row * (size + gap);
      context.fillStyle = (row + column) % 2 === 0 ? palette.paver : palette.paverAlt;
      context.fillRect(x, y, size, size);
      context.fillStyle = palette.paverShadow;
      context.fillRect(x, y + size - 1, size, 1);
      context.fillRect(x + size - 1, y + 2, 1, Math.max(0, size - 2));
    }
  }
}

function drawAgentTownPlacedCosmetics(context, hitAreas, time, visibleWorld, palette) {
  for (const decoration of getAgentTownDecorations()) {
    const item = getAgentTownCosmeticItem(decoration.itemId);
    if (!item) {
      continue;
    }
    const rect = getAgentTownDecorationRect(decoration, item);
    if (!rect) {
      continue;
    }
    if (!isAgentTownSceneryVisible(rect, visibleWorld)) {
      continue;
    }
    drawAgentTownCosmeticItem(context, item, rect, palette, time, {
      fenceConnections: item.kind === "fence" ? getAgentTownFenceConnections(decoration, rect) : null,
    });
    if (!isAgentTownEditMode()) {
      hitAreas.push({
        ...rect,
        kind: "decoration",
        decorationId: decoration.id,
        itemId: item.id,
        label: item.label,
      });
    }
  }
}

function getAgentTownFenceCenter(rect) {
  return {
    x: rect.x + rect.width / 2,
    y: rect.y + rect.height / 2,
  };
}

function isAgentTownFenceNeighbor(rect, otherRect, direction) {
  const tolerance = Math.max(2, Math.round(AGENT_TOWN_BUILD_GRID_SIZE * 0.1));
  const center = getAgentTownFenceCenter(rect);
  const otherCenter = getAgentTownFenceCenter(otherRect);
  const horizontalAlignment = Math.abs(center.x - otherCenter.x) <= Math.max(rect.width, otherRect.width) * 0.35;
  const verticalAlignment = Math.abs(center.y - otherCenter.y) <= Math.max(rect.height, otherRect.height) * 0.35;

  if (direction === "up") {
    return horizontalAlignment && Math.abs(otherRect.y + otherRect.height - rect.y) <= tolerance;
  }
  if (direction === "down") {
    return horizontalAlignment && Math.abs(rect.y + rect.height - otherRect.y) <= tolerance;
  }
  if (direction === "left") {
    return verticalAlignment && Math.abs(otherRect.x + otherRect.width - rect.x) <= tolerance;
  }
  if (direction === "right") {
    return verticalAlignment && Math.abs(rect.x + rect.width - otherRect.x) <= tolerance;
  }
  return false;
}

function getAgentTownFenceConnections(decoration, rect) {
  const connections = { up: false, right: false, down: false, left: false };
  if (!rect) {
    return connections;
  }

  for (const otherDecoration of getAgentTownDecorations()) {
    if (decoration?.id && otherDecoration.id === decoration.id) {
      continue;
    }

    const otherItem = getAgentTownCosmeticItem(otherDecoration.itemId);
    if (otherItem?.kind !== "fence") {
      continue;
    }

    const otherRect = getAgentTownDecorationRect(otherDecoration, otherItem);
    if (!otherRect) {
      continue;
    }

    connections.up = connections.up || isAgentTownFenceNeighbor(rect, otherRect, "up");
    connections.right = connections.right || isAgentTownFenceNeighbor(rect, otherRect, "right");
    connections.down = connections.down || isAgentTownFenceNeighbor(rect, otherRect, "down");
    connections.left = connections.left || isAgentTownFenceNeighbor(rect, otherRect, "left");

    if (connections.up && connections.right && connections.down && connections.left) {
      break;
    }
  }

  return connections;
}

function drawAgentTownFenceConnector(context, segment, palette) {
  context.fillStyle = palette.fenceShadow;
  context.fillRect(segment.x + 1, segment.y + 2, segment.width, segment.height);
  context.fillStyle = palette.fenceDark;
  context.fillRect(segment.x, segment.y, segment.width, segment.height);
  context.fillStyle = palette.fence;
  context.fillRect(segment.x + 1, segment.y + 1, Math.max(1, segment.width - 2), Math.max(1, segment.height - 2));
  context.fillStyle = palette.fenceLight;
  if (segment.width >= segment.height) {
    context.fillRect(segment.x + 2, segment.y + 2, Math.max(1, segment.width - 4), 2);
  } else {
    context.fillRect(segment.x + 2, segment.y + 2, 2, Math.max(1, segment.height - 4));
  }
}

function drawAgentTownConnectedFencePost(context, rect, connections, palette) {
  const centerX = Math.round(rect.x + rect.width / 2);
  const centerY = Math.round(rect.y + rect.height / 2);
  const radius = Math.max(7, Math.round(Math.min(rect.width, rect.height) * 0.28));
  const connectorWidth = Math.max(8, Math.round(radius * 1.05));
  const halfConnector = Math.floor(connectorWidth / 2);
  const segments = [];

  if (connections?.up) {
    segments.push({
      x: centerX - halfConnector,
      y: rect.y,
      width: connectorWidth,
      height: Math.max(1, centerY - rect.y),
    });
  }
  if (connections?.right) {
    segments.push({
      x: centerX,
      y: centerY - halfConnector,
      width: Math.max(1, rect.x + rect.width - centerX),
      height: connectorWidth,
    });
  }
  if (connections?.down) {
    segments.push({
      x: centerX - halfConnector,
      y: centerY,
      width: connectorWidth,
      height: Math.max(1, rect.y + rect.height - centerY),
    });
  }
  if (connections?.left) {
    segments.push({
      x: rect.x,
      y: centerY - halfConnector,
      width: Math.max(1, centerX - rect.x),
      height: connectorWidth,
    });
  }

  for (const segment of segments) {
    drawAgentTownFenceConnector(context, segment, palette);
  }

  context.fillStyle = palette.fenceShadow;
  context.beginPath();
  context.arc(centerX + 2, centerY + 3, radius + 2, 0, Math.PI * 2);
  context.fill();

  context.fillStyle = palette.fenceDark;
  context.beginPath();
  context.arc(centerX, centerY, radius + 2, 0, Math.PI * 2);
  context.fill();

  context.fillStyle = palette.fence;
  context.beginPath();
  context.arc(centerX, centerY, radius, 0, Math.PI * 2);
  context.fill();

  context.strokeStyle = palette.fenceDark;
  context.lineWidth = 1.5;
  context.beginPath();
  context.arc(centerX, centerY, Math.max(2, radius - 3), 0, Math.PI * 2);
  context.stroke();

  context.fillStyle = palette.fenceLight;
  context.beginPath();
  context.arc(centerX - 2, centerY - 2, Math.max(2, radius - 5), 0, Math.PI * 2);
  context.fill();
}

function drawAgentTownCosmeticItem(context, item, rect, palette, time, { fenceConnections = null } = {}) {
  if (item.kind === "road") {
    drawVisualGamePathRect(context, rect.x, rect.y, rect.width, rect.height);
    return;
  }

  if (item.kind === "fence") {
    drawAgentTownConnectedFencePost(context, rect, fenceConnections || getAgentTownFenceConnections(null, rect), palette);
    return;
  }

  if (item.kind === "planter") {
    const planterHeight = Math.min(14, rect.height);
    drawAgentTownPlanter(context, {
      ...rect,
      y: rect.y + Math.round((rect.height - planterHeight) / 2),
      height: planterHeight,
    }, palette, time);
    return;
  }

  if (item.kind === "structure") {
    drawAgentTownCosmeticStructure(context, {
      ...rect,
      roof: item.roof,
      body: item.body,
      accent: item.accent,
    }, palette, time);
  }
}

function drawAgentTownFence(context, fence, palette) {
  context.fillStyle = palette.fenceShadow;
  if (fence.orientation === "vertical") {
    context.fillRect(fence.x + 2, fence.y + 3, 14, fence.length + 4);
    context.fillStyle = palette.fenceDark;
    context.fillRect(fence.x + 4, fence.y, 3, fence.length);
    context.fillRect(fence.x + 11, fence.y, 3, fence.length);
    context.fillStyle = palette.fence;
    for (let offset = 0; offset <= fence.length; offset += 18) {
      context.fillRect(fence.x, fence.y + offset, 17, 5);
      context.fillStyle = palette.fenceLight;
      context.fillRect(fence.x + 2, fence.y + offset + 1, 12, 1);
      context.fillStyle = palette.fence;
    }
    return;
  }

  context.fillRect(fence.x + 2, fence.y + 3, fence.length + 4, 14);
  context.fillStyle = palette.fenceDark;
  context.fillRect(fence.x, fence.y + 4, fence.length, 3);
  context.fillRect(fence.x, fence.y + 11, fence.length, 3);
  context.fillStyle = palette.fence;
  for (let offset = 0; offset <= fence.length; offset += 18) {
    context.fillRect(fence.x + offset, fence.y, 5, 17);
    context.fillStyle = palette.fenceLight;
    context.fillRect(fence.x + offset + 1, fence.y + 2, 1, 12);
    context.fillStyle = palette.fence;
  }
}

function drawAgentTownPlanter(context, planter, palette, time) {
  const leafShift = Math.floor(Math.sin(time / 650 + planter.x) * 1);
  context.fillStyle = palette.planterShadow;
  context.fillRect(planter.x + 2, planter.y + planter.height - 1, planter.width, 5);
  context.fillStyle = palette.planterBox;
  context.fillRect(planter.x, planter.y + 6, planter.width, planter.height - 6);
  context.fillStyle = palette.planterTrim;
  context.fillRect(planter.x + 2, planter.y + 8, Math.max(0, planter.width - 4), 2);
  for (let offset = 3; offset < planter.width - 3; offset += 8) {
    context.fillStyle = offset % 16 === 3 ? palette.leaf : palette.leafAlt;
    context.fillRect(planter.x + offset, planter.y + 1 + leafShift, 5, 7);
    context.fillRect(planter.x + offset + 3, planter.y + 4 - leafShift, 5, 5);
    if (offset % 24 === 3) {
      context.fillStyle = palette.flower;
      context.fillRect(planter.x + offset + 2, planter.y, 2, 2);
    }
  }
}

function drawAgentTownCosmeticStructure(context, structure, palette, time) {
  const { x, y, width, height } = structure;
  const bodyTop = y + 9;
  const glow = 0.18 + Math.sin(time / 520 + x) * 0.05;

  context.fillStyle = palette.structureShadow;
  context.fillRect(x + 2, y + height - 1, width, 6);

  context.fillStyle = structure.body || "#6f5b3a";
  context.fillRect(x + 2, bodyTop, width - 4, height - 9);
  context.fillStyle = "rgba(255, 232, 171, 0.14)";
  context.fillRect(x + 5, bodyTop + 3, Math.max(0, width - 10), 3);

  context.fillStyle = structure.roof || "#80505e";
  context.beginPath();
  context.moveTo(x - 2, bodyTop);
  context.lineTo(x + Math.floor(width / 2), y + 1);
  context.lineTo(x + width + 2, bodyTop);
  context.lineTo(x + width - 1, bodyTop + 6);
  context.lineTo(x + 1, bodyTop + 6);
  context.closePath();
  context.fill();
  context.fillStyle = palette.structureTrim;
  context.fillRect(x + 1, bodyTop + 6, width - 2, 2);

  context.fillStyle = palette.structureTrim;
  context.fillRect(x + Math.floor(width * 0.55), y + height - 11, 7, 11);
  context.fillStyle = `rgba(255, 218, 126, ${glow})`;
  context.fillRect(x + Math.floor(width * 0.22), bodyTop + 8, 6, 5);
  context.fillStyle = structure.accent || "#f1c978";
  context.fillRect(x + Math.floor(width * 0.22), bodyTop + 8, 6, 1);
  context.fillRect(x + Math.floor(width * 0.22) + 2, bodyTop + 8, 1, 5);
}

function drawAgentTownBuilderPlacementPulse(context, time) {
  const pulse = state.visualGame.builderPulse;
  if (!pulse) {
    return;
  }

  const elapsed = time - Number(pulse.startedAt || 0);
  if (!Number.isFinite(elapsed) || elapsed < 0 || elapsed > AGENT_TOWN_BUILDER_PULSE_MS) {
    state.visualGame.builderPulse = null;
    return;
  }

  const progress = clamp(elapsed / AGENT_TOWN_BUILDER_PULSE_MS, 0, 1);
  const outset = 3 + progress * 12;
  const alpha = 1 - progress;
  context.save();
  context.lineWidth = 2;
  context.strokeStyle = pulse.tone === "blocked"
    ? `rgba(255, 105, 105, ${0.78 * alpha})`
    : `rgba(126, 213, 255, ${0.86 * alpha})`;
  context.fillStyle = pulse.tone === "blocked"
    ? `rgba(255, 84, 84, ${0.14 * alpha})`
    : `rgba(98, 181, 255, ${0.15 * alpha})`;
  context.fillRect(pulse.x - outset, pulse.y - outset, pulse.width + outset * 2, pulse.height + outset * 2);
  context.strokeRect(
    pulse.x - outset + 0.5,
    pulse.y - outset + 0.5,
    pulse.width + outset * 2 - 1,
    pulse.height + outset * 2 - 1,
  );
  context.restore();
}

function getAgentTownBuilderConstructionEase(value) {
  const t = clamp(value, 0, 1);
  return t * t * (3 - 2 * t);
}

function drawAgentTownBuilderConstructionTrail(context, job, x, y, alpha) {
  if (alpha <= 0) {
    return;
  }

  const distance = Math.hypot(x - job.fromX, y - job.fromY);
  if (distance < 8) {
    return;
  }

  context.save();
  context.globalAlpha *= alpha;
  for (let index = 1; index <= 5; index += 1) {
    const step = index / 6;
    const px = job.fromX + (x - job.fromX) * step;
    const py = job.fromY + (y - job.fromY) * step;
    const size = index % 2 === 0 ? 3 : 2;
    context.fillStyle = index % 2 === 0 ? "rgba(255, 230, 142, 0.42)" : "rgba(151, 218, 255, 0.34)";
    context.fillRect(Math.round(px) - 1, Math.round(py) - 1, size, size);
  }
  context.restore();
}

function drawAgentTownBuilderConstructionPatch(context, job, time, alpha, doneAlpha = 0) {
  const rect = job?.rect;
  if (!rect || (alpha <= 0 && doneAlpha <= 0)) {
    return;
  }

  const workAlpha = clamp(alpha, 0, 1);
  const finishAlpha = clamp(doneAlpha, 0, 1);
  const workX = rect.x + rect.width * 0.64;
  const workY = rect.y + rect.height * 0.54;
  context.save();
  const baseAlpha = context.globalAlpha;

  if (workAlpha > 0) {
    context.globalAlpha = baseAlpha * workAlpha;
    context.fillStyle = "rgba(79, 172, 255, 0.12)";
    context.fillRect(rect.x - 4, rect.y - 4, rect.width + 8, rect.height + 8);
    context.strokeStyle = "rgba(180, 231, 255, 0.76)";
    context.lineWidth = 2;
    context.strokeRect(rect.x - 4.5, rect.y - 4.5, rect.width + 9, rect.height + 9);

    context.fillStyle = "rgba(255, 220, 124, 0.82)";
    context.fillRect(rect.x - 7, rect.y + 2, 3, rect.height + 5);
    context.fillRect(rect.x + rect.width + 4, rect.y + 2, 3, rect.height + 5);
    context.fillRect(rect.x - 9, rect.y + 8, rect.width + 18, 3);
    context.fillRect(rect.x - 8, rect.y + rect.height - 8, rect.width + 16, 3);

    const sparkBeat = Math.floor(time / 84);
    for (let index = 0; index < 6; index += 1) {
      const hash = getVisualGameHash(job.seed + sparkBeat + index * 7, index + 13);
      const angle = ((hash % 360) / 180) * Math.PI;
      const radius = 4 + (hash % 11);
      const sparkX = workX + Math.cos(angle) * radius;
      const sparkY = workY + Math.sin(angle) * radius * 0.72;
      context.fillStyle = index % 2 === 0 ? "#fff2a8" : "#ffb15f";
      context.fillRect(Math.round(sparkX), Math.round(sparkY), 2, 2);
    }
  }

  if (finishAlpha > 0) {
    context.globalAlpha = baseAlpha * finishAlpha;
    context.strokeStyle = "rgba(184, 255, 166, 0.92)";
    context.lineWidth = 3;
    context.beginPath();
    context.moveTo(Math.round(rect.x + rect.width * 0.34), Math.round(rect.y + rect.height * 0.58));
    context.lineTo(Math.round(rect.x + rect.width * 0.46), Math.round(rect.y + rect.height * 0.72));
    context.lineTo(Math.round(rect.x + rect.width * 0.68), Math.round(rect.y + rect.height * 0.38));
    context.stroke();
  }

  context.restore();
}

function drawAgentTownBuilderMechanic(context, x, y, time, options = {}) {
  const alpha = clamp(Number(options.alpha) || 0, 0, 1);
  if (alpha <= 0) {
    return;
  }

  const walking = Boolean(options.walking);
  const working = Boolean(options.working);
  const scale = clamp(Number(options.scale) || 1, 0.45, 1.15);
  const facing = Number(options.direction) < 0 ? -1 : 1;
  const step = Math.floor(time / 120) % 4;
  const bob = walking ? Math.sin(time / 95) * 1.6 : working ? Math.sin(time / 70) * 0.8 : 0;
  const leftLeg = walking ? step % 2 : 0;
  const rightLeg = walking ? (step + 1) % 2 : 0;
  const toolSwing = working ? Math.floor(Math.sin(time / 68) * 3) : 0;

  context.save();
  context.globalAlpha *= alpha;
  context.translate(Math.round(x), Math.round(y + bob));
  context.scale(facing * scale, scale);

  context.fillStyle = "rgba(0, 0, 0, 0.28)";
  context.fillRect(-10, 0, 21, 4);

  context.fillStyle = "#1f2730";
  context.fillRect(-7, -3 + leftLeg, 6, 3);
  context.fillRect(2, -3 + rightLeg, 6, 3);
  context.fillStyle = "#263846";
  context.fillRect(-6, -13, 5, 11 + leftLeg);
  context.fillRect(2, -13, 5, 11 + rightLeg);
  context.fillStyle = "#315f68";
  context.fillRect(-8, -25, 16, 13);
  context.fillStyle = "#d8763f";
  context.fillRect(-5, -25, 10, 6);
  context.fillStyle = "#9bd1e8";
  context.fillRect(-5, -21, 3, 10);
  context.fillRect(2, -21, 3, 10);
  context.fillStyle = "#223844";
  context.fillRect(-2, -18, 4, 2);

  context.fillStyle = "#d8a16f";
  if (working) {
    context.fillRect(7, -24 + toolSwing, 4, 9);
    context.fillStyle = "#c9d2d5";
    context.fillRect(10, -31 + toolSwing, 2, 13);
    context.fillRect(7, -31 + toolSwing, 8, 2);
    context.fillRect(13, -34 + toolSwing, 2, 5);
  } else {
    context.fillRect(-11, -23 + leftLeg, 4, 9);
    context.fillRect(8, -23 + rightLeg, 4, 8);
    context.save();
    context.translate(11, -20 + rightLeg);
    context.rotate(-0.58);
    context.fillStyle = "#c9d2d5";
    context.fillRect(0, -8, 2, 12);
    context.fillRect(-3, -9, 8, 2);
    context.fillRect(4, -12, 2, 5);
    context.restore();
  }

  context.fillStyle = "#d8a16f";
  context.fillRect(-5, -33, 10, 9);
  context.fillStyle = "#4a2b1b";
  context.fillRect(-6, -34, 12, 3);
  context.fillStyle = "#ffd45c";
  context.fillRect(-8, -37, 16, 4);
  context.fillRect(-5, -40, 10, 4);
  context.fillStyle = "#fff0a6";
  context.fillRect(-3, -39, 6, 1);
  context.fillStyle = "#25323a";
  context.fillRect(-3, -30, 2, 2);
  context.fillRect(3, -30, 2, 2);
  context.fillStyle = "#f1c58f";
  context.fillRect(-1, -27, 3, 1);

  context.restore();
}

function drawAgentTownBuilderConstructionAgent(context, time) {
  const job = state.visualGame.builderConstruction;
  if (!job) {
    return;
  }

  const elapsed = time - Number(job.startedAt || 0);
  if (!Number.isFinite(elapsed) || elapsed < 0) {
    return;
  }
  if (elapsed > AGENT_TOWN_BUILDER_CONSTRUCTION_MS) {
    state.visualGame.builderConstruction = null;
    return;
  }

  const progress = clamp(elapsed / AGENT_TOWN_BUILDER_CONSTRUCTION_MS, 0, 1);
  const travelEnd = 0.48;
  const workEnd = 0.86;
  const travelProgress = getAgentTownBuilderConstructionEase(progress / travelEnd);
  const workProgress = clamp((progress - travelEnd) / (workEnd - travelEnd), 0, 1);
  const fade = progress > workEnd ? 1 - clamp((progress - workEnd) / (1 - workEnd), 0, 1) : 1;
  const popScale = progress < 0.12 ? 0.45 + getAgentTownBuilderConstructionEase(progress / 0.12) * 0.55 : 1;
  const x = job.fromX + (job.targetX - job.fromX) * travelProgress;
  const y = job.fromY + (job.targetY - job.fromY) * travelProgress;
  const direction = job.targetX >= job.fromX ? 1 : -1;
  const workAlpha = progress > travelEnd * 0.78 ? Math.min(1, workProgress + 0.24) * fade : 0;
  const doneAlpha = progress > 0.78 ? clamp((progress - 0.78) / 0.12, 0, 1) * fade : 0;
  const trailAlpha = clamp(1 - progress / 0.68, 0, 1) * fade;

  drawAgentTownBuilderConstructionTrail(context, job, x, y, trailAlpha);
  drawAgentTownBuilderConstructionPatch(context, job, time, workAlpha, doneAlpha);
  drawAgentTownBuilderMechanic(context, x, y, time, {
    alpha: fade,
    walking: progress < travelEnd,
    working: progress >= travelEnd && progress < workEnd,
    direction,
    scale: popScale,
  });
}

function drawAgentTownBuilderFootprintGrid(context, rect, blocked, time) {
  const phase = Math.floor(time / 180) % 2;
  context.fillStyle = blocked ? "rgba(255, 90, 90, 0.27)" : "rgba(61, 157, 255, 0.34)";
  context.fillRect(rect.x - 4, rect.y - 4, rect.width + 8, rect.height + 8);
  context.fillStyle = blocked ? "rgba(255, 90, 90, 0.3)" : "rgba(88, 180, 255, 0.38)";
  context.fillRect(rect.x, rect.y, rect.width, rect.height);
  context.fillStyle = blocked ? "rgba(255, 213, 213, 0.46)" : "rgba(229, 247, 255, 0.52)";
  for (let x = rect.x; x <= rect.x + rect.width; x += AGENT_TOWN_BUILDER_GRID_SIZE) {
    context.fillRect(Math.round(x), rect.y, 1, rect.height);
  }
  for (let y = rect.y; y <= rect.y + rect.height; y += AGENT_TOWN_BUILDER_GRID_SIZE) {
    context.fillRect(rect.x, Math.round(y), rect.width, 1);
  }
  context.fillStyle = blocked ? "rgba(255, 226, 226, 0.84)" : "rgba(224, 244, 255, 0.9)";
  for (let x = rect.x + 5 + phase * 2; x < rect.x + rect.width - 2; x += 12) {
    context.fillRect(x, rect.y + 4 + Math.floor(Math.sin(time / 280 + x) * 1), 6, 2);
  }
  for (let y = rect.y + 5; y < rect.y + rect.height - 2; y += 12) {
    context.fillRect(rect.x + 4, y, 2, 6);
    context.fillRect(rect.x + rect.width - 6, y, 2, 6);
  }
}

function drawAgentTownBuilderPlacementGhost(context, placement, rect, time) {
  if (placement.kind === "cosmetic") {
    const item = getAgentTownCosmeticItem(placement.itemId);
    if (!item) {
      return;
    }
    drawAgentTownCosmeticItem(context, item, rect, getAgentTownSceneryPalette(), time, {
      fenceConnections: item.kind === "fence" ? getAgentTownFenceConnections(null, rect) : null,
    });
    return;
  }

  const plugin = getPluginById(placement.pluginId);
  const palette = getAgentTownPluginBuildingPalette(placement.pluginId);
  const building = {
    ...palette,
    rect,
    pluginId: placement.pluginId,
    label: plugin?.name || placement.label,
    meta: plugin?.category || "building",
  };
  if (plugin && getPluginBuildingShape(plugin) === "portal") {
    drawVisualGamePortalBuilding(context, [], building, time);
  } else if (plugin && getPluginBuildingShape(plugin) === "lab") {
    drawVisualGameLabBuilding(context, [], building, time);
  } else {
    drawVisualGameBuilding(context, [], building);
  }
}

function drawAgentTownBuilderPlacementPreview(context, time) {
  const placement = state.visualGame.builderPlacement;
  const rect = placement?.cursorRect;
  if (!placement || !rect) {
    return;
  }

  const blocked = Boolean(placement.blocked);
  context.save();
  drawAgentTownBuilderFootprintGrid(context, rect, blocked, time);

  context.save();
  context.globalAlpha = blocked ? 0.42 : 0.58;
  drawAgentTownBuilderPlacementGhost(context, placement, rect, time);
  context.restore();

  context.strokeStyle = blocked ? "rgba(255, 120, 120, 0.96)" : "rgba(114, 190, 255, 0.98)";
  context.lineWidth = 3;
  context.strokeRect(rect.x - 3, rect.y - 3, rect.width + 6, rect.height + 6);
  context.lineWidth = 2;
  context.strokeRect(rect.x + 1, rect.y + 1, Math.max(0, rect.width - 2), Math.max(0, rect.height - 2));
  context.fillStyle = blocked ? "rgba(255, 216, 216, 0.92)" : "rgba(229, 248, 255, 0.96)";
  const cornerSize = 7;
  context.fillRect(rect.x - 3, rect.y - 3, cornerSize, 3);
  context.fillRect(rect.x - 3, rect.y - 3, 3, cornerSize);
  context.fillRect(rect.x + rect.width - cornerSize + 3, rect.y - 3, cornerSize, 3);
  context.fillRect(rect.x + rect.width, rect.y - 3, 3, cornerSize);
  context.fillRect(rect.x - 3, rect.y + rect.height, cornerSize, 3);
  context.fillRect(rect.x - 3, rect.y + rect.height - cornerSize + 3, 3, cornerSize);
  context.fillRect(rect.x + rect.width - cornerSize + 3, rect.y + rect.height, cornerSize, 3);
  context.fillRect(rect.x + rect.width, rect.y + rect.height - cornerSize + 3, 3, cornerSize);
  if (blocked) {
    context.strokeStyle = "rgba(255, 216, 216, 0.88)";
    context.lineWidth = 2;
    context.beginPath();
    context.moveTo(rect.x + 7, rect.y + 7);
    context.lineTo(rect.x + rect.width - 7, rect.y + rect.height - 7);
    context.moveTo(rect.x + rect.width - 7, rect.y + 7);
    context.lineTo(rect.x + 7, rect.y + rect.height - 7);
    context.stroke();
  }
  context.restore();
}

function drawAgentTownEditOutlines(context, hitAreas) {
  context.save();
  context.setLineDash([4, 3]);
  for (const hit of hitAreas) {
    if (hit.kind !== "town-place" && hit.kind !== "town-road") {
      continue;
    }
    context.strokeStyle = hit.kind === "town-road" ? "rgba(255, 236, 166, 0.7)" : "rgba(216, 251, 255, 0.76)";
    context.lineWidth = 1.5;
    context.strokeRect(Math.round(hit.x) + 0.75, Math.round(hit.y) + 0.75, Math.round(hit.width) - 1.5, Math.round(hit.height) - 1.5);
  }
  context.setLineDash([]);
  for (const hit of hitAreas) {
    if (hit.kind !== "town-uninstall") {
      continue;
    }
    const centerX = hit.x + hit.width / 2;
    const centerY = hit.y + hit.height / 2;
    const radius = Math.max(4, Math.min(hit.width, hit.height) / 2 - 0.5);
    context.fillStyle = "rgba(161, 44, 44, 0.95)";
    context.strokeStyle = "rgba(255, 244, 244, 0.9)";
    context.lineWidth = 1.25;
    context.beginPath();
    context.arc(centerX, centerY, radius, 0, Math.PI * 2);
    context.fill();
    context.stroke();
    context.strokeStyle = "rgba(255, 250, 250, 0.96)";
    context.lineWidth = 1.5;
    context.beginPath();
    context.moveTo(centerX - 3.2, centerY - 3.2);
    context.lineTo(centerX + 3.2, centerY + 3.2);
    context.moveTo(centerX + 3.2, centerY - 3.2);
    context.lineTo(centerX - 3.2, centerY + 3.2);
    context.stroke();
  }
  context.restore();
}

function drawVisualGameRoomFloor(context, x, y, width, height, options = {}) {
  const theme = getAgentTownTheme();
  const room = theme.room || AGENT_TOWN_THEME_BY_ID.get(AGENT_TOWN_DEFAULT_THEME_ID).room;
  const entranceFill = theme.path?.fill || "#d1af63";
  const floor = options.floor || room.floor || "#72563a";
  const trim = options.trim || room.trim || "#3d291d";
  const entrance = normalizeVisualGameEntrance(options.entrance, x, y, width, height);

  drawVisualGameShadow(context, x + 3, y + height - 1, width, 7);
  context.fillStyle = floor;
  context.fillRect(x, y, width, height);

  context.fillStyle = room.highlight || "rgba(255, 231, 159, 0.12)";
  context.fillRect(x + 4, y + 4, Math.max(0, width - 8), 4);
  for (let row = y + 12; row < y + height - 6; row += 12) {
    context.fillRect(x + 5, row, Math.max(0, width - 10), 1);
  }
  context.fillStyle = room.shadow || "rgba(73, 46, 27, 0.18)";
  for (let column = x + 14; column < x + width - 6; column += 18) {
    context.fillRect(column, y + 5, 1, Math.max(0, height - 10));
  }

  drawVisualGameProviderFloorPattern(context, x, y, width, height, {
    pattern: options.floorPattern,
    color: options.floorPatternColor || room.edgeLight || "rgba(255, 238, 176, 0.16)",
    alpha: options.floorPatternAlpha,
    trim,
  });

  context.fillStyle = room.edgeShadow || "rgba(10, 13, 11, 0.16)";
  context.fillRect(x, y + height - 2, width, 2);
  context.fillRect(x + width - 2, y, 2, height);
  context.fillStyle = room.edgeLight || "rgba(255, 238, 176, 0.16)";
  context.fillRect(x, y, width, 1);
  context.fillRect(x, y, 1, height);

  const openingWidth = Math.min(28, Math.max(16, Math.floor(width * 0.28)));
  if (entrance.side === "bottom") {
    const openingX = Math.round(clamp(entrance.anchor.x, x + openingWidth / 2, x + width - openingWidth / 2) - openingWidth / 2);
    context.fillStyle = entranceFill;
    context.fillRect(openingX + 2, y + height - 2, openingWidth - 4, 5);
    context.fillStyle = trim;
    context.fillRect(openingX + 5, y + height, openingWidth - 10, 1);
  } else if (entrance.side === "top") {
    const openingX = Math.round(clamp(entrance.anchor.x, x + openingWidth / 2, x + width - openingWidth / 2) - openingWidth / 2);
    context.fillStyle = entranceFill;
    context.fillRect(openingX + 2, y - 3, openingWidth - 4, 5);
    context.fillStyle = trim;
    context.fillRect(openingX + 5, y - 1, openingWidth - 10, 1);
  } else if (entrance.side === "left") {
    const openingY = Math.round(clamp(entrance.anchor.y, y + openingWidth / 2, y + height - openingWidth / 2) - openingWidth / 2);
    context.fillStyle = entranceFill;
    context.fillRect(x - 3, openingY + 2, 5, openingWidth - 4);
    context.fillStyle = trim;
    context.fillRect(x - 1, openingY + 5, 1, openingWidth - 10);
  } else if (entrance.side === "right") {
    const openingY = Math.round(clamp(entrance.anchor.y, y + openingWidth / 2, y + height - openingWidth / 2) - openingWidth / 2);
    context.fillStyle = entranceFill;
    context.fillRect(x + width - 2, openingY + 2, 5, openingWidth - 4);
    context.fillStyle = trim;
    context.fillRect(x + width, openingY + 5, 1, openingWidth - 10);
  }
}

function normalizeVisualGameEntrance(entrance, x, y, width, height) {
  if (typeof entrance === "string") {
    return { side: entrance, anchor: getVisualGameDefaultEntranceAnchor(entrance, x, y, width, height) };
  }

  const side = entrance?.side || "bottom";
  return {
    side,
    anchor: entrance?.anchor || getVisualGameDefaultEntranceAnchor(side, x, y, width, height),
  };
}

function getVisualGameDefaultEntranceAnchor(side, x, y, width, height) {
  if (side === "top") {
    return { x: x + width / 2, y };
  }
  if (side === "left") {
    return { x, y: y + height / 2 };
  }
  if (side === "right") {
    return { x: x + width, y: y + height / 2 };
  }
  return { x: x + width / 2, y: y + height };
}

function getVisualGameRenderedEntrance(place) {
  return {
    ...(place?.entrance || { side: "bottom" }),
    anchor: getVisualGameTownPlaceAnchor(place),
  };
}

function drawVisualGameProviderFloorPattern(context, x, y, width, height, options = {}) {
  const pattern = String(options.pattern || "").trim();
  if (!pattern) {
    return;
  }

  const motifSize = Math.max(16, Math.min(24, Math.floor(Math.min(width, height) * 0.38)));
  const centers = [
    { x: x + Math.round(width * 0.5), y: y + Math.round(height * 0.7) },
  ];

  context.save();
  context.beginPath();
  context.rect(x + 3, y + 4, Math.max(0, width - 6), Math.max(0, height - 8));
  context.clip();
  context.globalAlpha = clamp(Number(options.alpha) || 0.42, 0.1, 0.75);
  for (const center of centers) {
    if (pattern === "claude") {
      drawVisualGameClaudeFloorLogo(context, center.x, center.y, motifSize, options.color);
    } else if (pattern === "codex") {
      drawVisualGameCodexFloorLogo(context, center.x, center.y, motifSize, options.color, options.trim);
    } else if (pattern === "openclaw") {
      drawVisualGameOpenClawFloorLogo(context, center.x, center.y, motifSize, options.color, options.trim);
    }
  }
  context.restore();
}

function drawVisualGameClaudeFloorLogo(context, centerX, centerY, size, color) {
  context.save();
  context.translate(centerX, centerY);
  context.fillStyle = color || "#ffd0a3";
  for (let index = 0; index < 8; index += 1) {
    context.save();
    context.rotate((Math.PI * 2 * index) / 8);
    context.beginPath();
    context.ellipse(0, -size * 0.3, size * 0.12, size * 0.38, 0, 0, Math.PI * 2);
    context.fill();
    context.restore();
  }
  context.fillStyle = "rgba(255, 244, 215, 0.82)";
  context.beginPath();
  context.arc(0, 0, size * 0.16, 0, Math.PI * 2);
  context.fill();
  context.restore();
}

function drawVisualGameCodexFloorLogo(context, centerX, centerY, size, color, trim) {
  context.save();
  context.translate(centerX, centerY);
  context.strokeStyle = color || "#d8fff6";
  context.lineWidth = Math.max(1.5, size * 0.12);
  context.lineCap = "round";
  context.lineJoin = "round";
  for (let index = 0; index < 6; index += 1) {
    context.save();
    context.rotate((Math.PI * 2 * index) / 6);
    context.beginPath();
    context.ellipse(size * 0.18, 0, size * 0.28, size * 0.11, Math.PI / 5, 0, Math.PI * 2);
    context.stroke();
    context.restore();
  }
  context.fillStyle = trim || "#112b26";
  context.beginPath();
  context.arc(0, 0, size * 0.11, 0, Math.PI * 2);
  context.fill();
  context.restore();
}

function drawVisualGameOpenClawFloorLogo(context, centerX, centerY, size, color, trim) {
  context.save();
  context.translate(centerX, centerY);
  context.fillStyle = color || "#ffd0b4";
  context.fillRect(Math.round(-size * 0.33), Math.round(-size * 0.12), Math.round(size * 0.66), Math.round(size * 0.34));
  context.fillRect(Math.round(-size * 0.52), Math.round(-size * 0.02), Math.round(size * 0.18), Math.round(size * 0.18));
  context.fillRect(Math.round(size * 0.34), Math.round(-size * 0.02), Math.round(size * 0.18), Math.round(size * 0.18));
  context.fillStyle = trim || "#331821";
  context.fillRect(Math.round(-size * 0.28), Math.round(-size * 0.24), Math.max(2, Math.round(size * 0.12)), Math.max(2, Math.round(size * 0.12)));
  context.fillRect(Math.round(size * 0.16), Math.round(-size * 0.24), Math.max(2, Math.round(size * 0.12)), Math.max(2, Math.round(size * 0.12)));
  context.fillRect(Math.round(-size * 0.5), Math.round(size * 0.22), Math.round(size), Math.max(2, Math.round(size * 0.1)));
  context.restore();
}

function drawVisualGameComputerStation(context, desk, occupied, time, index, screenColor = "#79bdf8") {
  context.fillStyle = "#293841";
  context.fillRect(desk.x - 11, desk.y - 27, 24, 16);
  context.fillStyle = occupied ? screenColor : "#31526a";
  context.fillRect(desk.x - 8, desk.y - 24, 18, 9);
  if (occupied) {
    context.fillStyle = `rgba(153, 224, 255, ${0.22 + Math.sin(time / 180 + index) * 0.08})`;
    context.fillRect(desk.x - 10, desk.y - 26, 22, 13);
  }
  context.fillStyle = "#161b1e";
  context.fillRect(desk.x - 2, desk.y - 12, 8, 2);
}

function getAgentTownFloorplanArt(buildingId) {
  return AGENT_TOWN_FLOORPLAN_ART[normalizeBuildingId(buildingId)] || null;
}

function getAgentTownFloorplanImage(buildingId) {
  const art = getAgentTownFloorplanArt(buildingId);
  if (!art?.src) {
    return null;
  }

  let entry = AGENT_TOWN_FLOORPLAN_IMAGE_CACHE.get(art.src);
  if (!entry) {
    const image = new Image();
    entry = {
      image,
      loaded: false,
      failed: false,
    };
    image.decoding = "async";
    image.addEventListener("load", () => {
      entry.loaded = true;
    }, { once: true });
    image.addEventListener("error", () => {
      entry.failed = true;
    }, { once: true });
    image.src = art.src;
    AGENT_TOWN_FLOORPLAN_IMAGE_CACHE.set(art.src, entry);
  }

  if (entry.failed || !entry.loaded) {
    return null;
  }
  return entry.image;
}

function getContainedDrawRect(width, height, frame, { alignX = 0.5, alignY = 1 } = {}) {
  const safeWidth = Math.max(1, Number(width || 1));
  const safeHeight = Math.max(1, Number(height || 1));
  const scale = Math.min(frame.width / safeWidth, frame.height / safeHeight);
  const targetWidth = safeWidth * scale;
  const targetHeight = safeHeight * scale;
  return {
    x: frame.x + (frame.width - targetWidth) * alignX,
    y: frame.y + (frame.height - targetHeight) * alignY,
    width: targetWidth,
    height: targetHeight,
  };
}

function drawAgentTownFloorplan(context, buildingId, rect) {
  const art = getAgentTownFloorplanArt(buildingId);
  const image = getAgentTownFloorplanImage(buildingId);
  if (!art || !image) {
    return null;
  }

  const extraX = Number(art.extraX || 0);
  const extraTop = Number(art.extraTop || 0);
  const extraBottom = Number(art.extraBottom || 0);
  const frame = {
    x: rect.x - extraX / 2,
    y: rect.y - extraTop,
    width: rect.width + extraX,
    height: rect.height + extraTop + extraBottom,
  };
  const target = getContainedDrawRect(
    image.naturalWidth || image.width || 1,
    image.naturalHeight || image.height || 1,
    frame,
    { alignX: 0.5, alignY: 1 },
  );

  context.save();
  const previousImageSmoothing = context.imageSmoothingEnabled;
  context.imageSmoothingEnabled = false;
  context.drawImage(
    image,
    Math.round(target.x),
    Math.round(target.y),
    Math.round(target.width),
    Math.round(target.height),
  );
  context.imageSmoothingEnabled = previousImageSmoothing;
  context.restore();
  return target;
}

function drawVisualGameFloorplanSign(context, floorplanRect, buildingId, label, meta) {
  if (!label && !meta) {
    return;
  }

  const art = getAgentTownFloorplanArt(buildingId);
  const signOptions = art?.sign || {};
  if (signOptions.hidden) {
    return;
  }
  const signWidth = Math.min(
    Math.max(Math.round(floorplanRect.width + Number(signOptions.widthPadding || 20)), 56),
    126,
  );
  const signHeight = Math.max(18, Math.round(Number(signOptions.height || 20)));
  const signX = Math.round(floorplanRect.x + floorplanRect.width / 2 - signWidth / 2);
  const signY = Math.round(floorplanRect.y - Number(signOptions.offsetY || 16));
  drawVisualGameBuildingSign(context, signX, signY, signWidth, signHeight, label, meta);
}

function drawVisualGameFloorplanBuilding(context, hitAreas, building, floorplanId) {
  const rect = building.rect || building;
  const art = getAgentTownFloorplanArt(floorplanId);
  const image = getAgentTownFloorplanImage(floorplanId);
  if (!rect || !art || !image) {
    return false;
  }

  const shadowInset = Math.max(8, Math.round(rect.width * 0.12));
  drawVisualGameShadow(context, rect.x + shadowInset / 2, rect.y + rect.height - 1, rect.width - shadowInset, 7);

  const floorplanRect = drawAgentTownFloorplan(context, floorplanId, rect);
  if (!floorplanRect) {
    return false;
  }

  drawVisualGameFloorplanSign(context, floorplanRect, floorplanId, building.label, building.meta);
  if (building.issue) {
    drawVisualGameBuildingIssueBadge(context, rect);
  }
  pushAgentTownPlaceHit(hitAreas, { ...building, rect, baseRect: building.baseRect || rect }, building.action);
  return true;
}

function drawVisualGameBuilding(context, hitAreas, building) {
  const rect = building.rect || building;
  const { x, y, width, height } = rect;
  const { label, meta, body, trim, fixture, screen, action, issue } = building;
  if (drawVisualGameFloorplanBuilding(context, hitAreas, building, building.pluginId)) {
    return;
  }
  drawVisualGameRoomFloor(context, x, y, width, height, {
    floor: body,
    trim: trim || "#4b2f22",
    entrance: "bottom",
  });

  if (building.pluginId === "buildinghub") {
    drawVisualGameBuildingHubWorkshop(context, rect, {
      trim: trim || "#4b2f22",
      fixture: fixture || "#4f3322",
      screen: screen || "#ffd88a",
    });
  } else {
    context.fillStyle = screen || "rgba(255, 232, 159, 0.16)";
    context.fillRect(x + width - 24, y + height - 18, 15, 7);
    context.fillStyle = fixture || "rgba(79, 51, 34, 0.42)";
    context.fillRect(x + width - 17, y + height - 18, 1, 7);
    context.fillRect(x + width - 24, y + height - 15, 15, 1);
  }

  drawVisualGameBuildingSign(context, x + 8, y + 7, Math.min(width - 16, 88), 23, label, meta);

  if (issue) {
    drawVisualGameBuildingIssueBadge(context, rect);
  }

  pushAgentTownPlaceHit(hitAreas, { ...building, rect, baseRect: building.baseRect || rect }, action);
}

function drawVisualGameBuildingHubWorkshop(context, rect, palette = {}) {
  const { x, y, width, height } = rect;
  const trim = palette.trim || "#4b2f22";
  const fixture = palette.fixture || "#4f3322";
  const screen = palette.screen || "#ffd88a";
  const benchY = y + height - 18;

  context.fillStyle = "rgba(35, 22, 15, 0.32)";
  context.fillRect(x + 10, benchY + 5, width - 20, 5);
  context.fillStyle = fixture;
  context.fillRect(x + 12, benchY, width - 24, 7);
  context.fillStyle = "rgba(255, 241, 184, 0.28)";
  context.fillRect(x + 15, benchY + 2, width - 30, 2);
  context.fillStyle = trim;
  context.fillRect(x + 17, benchY + 7, 4, 8);
  context.fillRect(x + width - 21, benchY + 7, 4, 8);

  context.fillStyle = "#d1af63";
  context.fillRect(x + 12, y + height - 31, 15, 12);
  context.fillStyle = "rgba(47, 30, 19, 0.34)";
  context.fillRect(x + 15, y + height - 28, 9, 1);
  context.fillRect(x + 18, y + height - 31, 1, 12);

  context.fillStyle = screen;
  context.fillRect(x + width - 41, y + height - 31, 6, 6);
  context.fillStyle = trim;
  context.fillRect(x + width - 40, y + height - 29, 4, 2);

  context.save();
  context.translate(x + width - 24, y + height - 22);
  context.rotate(-0.62);
  context.fillStyle = "rgba(36, 23, 16, 0.38)";
  context.fillRect(-2, -12, 5, 23);
  context.fillRect(-8, -15, 15, 5);
  context.fillStyle = screen;
  context.fillRect(-1, -11, 3, 21);
  context.fillRect(-7, -14, 12, 3);
  context.fillRect(-8, -18, 3, 7);
  context.fillRect(4, -18, 3, 7);
  context.restore();
}

function drawVisualGamePortalBuilding(context, hitAreas, building, time = 0) {
  const rect = building.rect || building;
  const { x, y, width, height } = rect;
  const { label, meta, body, trim, fixture, screen, action, issue } = building;
  if (drawVisualGameFloorplanBuilding(context, hitAreas, building, building.pluginId)) {
    return;
  }
  const portalTrim = trim || "#14243a";
  const portalScreen = screen || "#9ceaff";
  const glow = 0.34 + Math.sin(time / 260) * 0.08;
  const centerX = x + width / 2;
  const centerY = y + height - 29;

  drawVisualGameRoomFloor(context, x, y, width, height, {
    floor: body || "#253a59",
    trim: portalTrim,
    entrance: "bottom",
  });
  drawVisualGameBuildingSign(context, x + 8, y + 7, Math.min(width - 16, 88), 23, label, meta);

  context.fillStyle = "rgba(9, 15, 28, 0.32)";
  context.fillRect(x + 13, y + height - 11, width - 26, 7);
  context.fillStyle = fixture || "#d1af63";
  context.fillRect(x + 18, y + height - 16, width - 36, 6);
  context.fillStyle = portalTrim;
  context.fillRect(x + 16, y + height - 20, 11, 22);
  context.fillRect(x + width - 27, y + height - 20, 11, 22);
  context.fillRect(x + 21, y + height - 25, width - 42, 5);

  context.save();
  context.translate(centerX, centerY - 9);
  context.fillStyle = "#0e1b34";
  context.beginPath();
  context.ellipse(0, 0, 23, 32, 0, 0, Math.PI * 2);
  context.fill();
  context.strokeStyle = portalTrim;
  context.lineWidth = 7;
  context.stroke();
  context.strokeStyle = "rgba(209, 175, 99, 0.88)";
  context.lineWidth = 3;
  context.stroke();

  context.fillStyle = `rgba(156, 234, 255, ${0.52 + glow * 0.35})`;
  context.beginPath();
  context.ellipse(0, 1, 15, 23, 0, 0, Math.PI * 2);
  context.fill();
  context.fillStyle = `rgba(78, 105, 215, ${0.72 + glow * 0.2})`;
  context.beginPath();
  context.ellipse(0, 3, 9, 16, 0, 0, Math.PI * 2);
  context.fill();
  context.fillStyle = `rgba(255, 255, 255, ${0.26 + glow * 0.22})`;
  context.fillRect(-11, -10, 22, 3);
  context.fillRect(-7, 6, 14, 2);
  context.restore();

  context.fillStyle = portalScreen;
  context.fillRect(x + 18, y + height - 36, 8, 8);
  context.fillRect(x + width - 26, y + height - 36, 8, 8);
  context.fillStyle = `rgba(156, 234, 255, ${0.18 + glow * 0.25})`;
  context.fillRect(x + 14, y + height - 40, width - 28, 18);

  if (issue) {
    drawVisualGameBuildingIssueBadge(context, rect);
  }

  pushAgentTownPlaceHit(hitAreas, { ...building, rect, baseRect: building.baseRect || rect }, action);
}

function drawVisualGameLabPod(context, pod, { occupied = false, time = 0, index = 0, screen = "#b8f4f2", trim = "#163b3f" } = {}) {
  const glow = occupied ? 0.24 + Math.sin(time / 220 + index) * 0.08 : 0.08;
  context.fillStyle = "rgba(8, 18, 25, 0.34)";
  context.fillRect(pod.x + 2, pod.y + pod.height - 2, pod.width, 5);
  context.fillStyle = `rgba(184, 244, 242, ${occupied ? 0.28 : 0.14})`;
  context.fillRect(pod.x, pod.y + 5, pod.width, pod.height - 5);
  context.strokeStyle = trim;
  context.lineWidth = 2;
  context.strokeRect(pod.x + 0.5, pod.y + 5.5, pod.width - 1, pod.height - 6);
  context.fillStyle = screen;
  context.fillRect(pod.x + 3, pod.y + 8, 4, pod.height - 12);
  context.fillRect(pod.x + pod.width - 7, pod.y + 8, 4, pod.height - 12);
  context.fillStyle = `rgba(255, 255, 255, ${0.22 + glow})`;
  context.fillRect(pod.x + 8, pod.y + 8, Math.max(0, pod.width - 16), 2);
  context.fillRect(pod.x + 8, pod.y + 18, Math.max(0, pod.width - 16), 1);
  context.fillStyle = occupied ? "#dffcff" : "rgba(184, 244, 242, 0.34)";
  context.fillRect(pod.x + Math.floor(pod.width / 2) - 2, pod.y + 2, 4, 5);
}

function drawVisualGameLabBuilding(context, hitAreas, building, time = 0, labAgents = []) {
  const rect = building.rect || building;
  const { x, y, width, height } = rect;
  const { label, meta, body, trim, fixture, screen, action, issue } = building;
  if (drawVisualGameFloorplanBuilding(context, hitAreas, building, building.pluginId)) {
    return;
  }
  const labTrim = trim || "#163b3f";
  const labScreen = screen || "#b8f4f2";
  const activeCount = Array.isArray(labAgents) ? labAgents.length : 0;
  const statusMeta = activeCount
    ? `${activeCount} eval${activeCount === 1 ? "" : "s"}`
    : meta || "sandbox";

  drawVisualGameRoomFloor(context, x, y, width, height, {
    floor: body || "#294853",
    trim: labTrim,
    entrance: "bottom",
  });
  drawVisualGameBuildingSign(context, x + 8, y + 7, Math.min(width - 16, 88), 23, label, statusMeta);

  context.fillStyle = fixture || "#25343c";
  context.fillRect(x + 10, y + height - 14, width - 20, 7);
  context.fillStyle = "rgba(255, 232, 159, 0.2)";
  context.fillRect(x + 13, y + height - 12, width - 26, 2);

  const pods = [
    { x: x + 12, y: y + 34, width: 26, height: Math.max(24, height - 48) },
    { x: x + Math.round(width / 2 - 13), y: y + 31, width: 26, height: Math.max(27, height - 45) },
    { x: x + width - 38, y: y + 34, width: 26, height: Math.max(24, height - 48) },
  ];
  pods.forEach((pod, index) => {
    drawVisualGameLabPod(context, pod, {
      occupied: index < activeCount,
      time,
      index,
      screen: labScreen,
      trim: labTrim,
    });
  });

  const pulse = 0.18 + Math.sin(time / 260) * 0.06;
  context.fillStyle = labScreen;
  context.fillRect(x + width - 24, y + height - 29, 14, 9);
  context.fillStyle = `rgba(184, 244, 242, ${pulse})`;
  context.fillRect(x + width - 27, y + height - 32, 20, 15);
  context.fillStyle = labTrim;
  context.fillRect(x + width - 21, y + height - 26, 8, 3);

  if (activeCount > pods.length) {
    drawVisualGameOverflowBadge(context, x + width - 35, y + height - 20, `+${activeCount - pods.length}`);
  }
  if (issue) {
    drawVisualGameBuildingIssueBadge(context, rect);
  }

  pushAgentTownPlaceHit(hitAreas, { ...building, rect, baseRect: building.baseRect || rect }, action);
}

function drawAgentTownInstalledPluginBuildings(context, hitAreas, time = 0, { harborAgents = [] } = {}) {
  for (const blueprint of getAgentTownPluginBuildingBlueprints()) {
    const building = getVisualGameTownVirtualPlace({
      ...blueprint,
      spots: [],
      entrance: { side: "bottom" },
      baseAnchor: {
        x: blueprint.baseRect.x + blueprint.baseRect.width / 2,
        y: blueprint.baseRect.y + blueprint.baseRect.height,
      },
    });
    if (blueprint.shape === "portal") {
      drawVisualGamePortalBuilding(context, hitAreas, {
        ...building,
        body: blueprint.body,
        trim: blueprint.trim,
        fixture: blueprint.fixture,
        screen: blueprint.screen,
        issue: blueprint.issue,
        action: blueprint.action,
      }, time);
      drawAgentTownBuildingInstallStatusOverlay(context, building.rect || blueprint.baseRect, blueprint.installStatus, time);
      continue;
    }
    if (blueprint.shape === "lab") {
      drawVisualGameLabBuilding(context, hitAreas, {
        ...building,
        body: blueprint.body,
        trim: blueprint.trim,
        fixture: blueprint.fixture,
        screen: blueprint.screen,
        issue: blueprint.issue,
        action: blueprint.action,
      }, time, blueprint.pluginId === "harbor" ? harborAgents : []);
      drawAgentTownBuildingInstallStatusOverlay(context, building.rect || blueprint.baseRect, blueprint.installStatus, time);
      continue;
    }
    drawVisualGameBuilding(context, hitAreas, {
      ...building,
      body: blueprint.body,
      trim: blueprint.trim,
      fixture: blueprint.fixture,
      screen: blueprint.screen,
      issue: blueprint.issue,
      action: blueprint.action,
    });
    drawAgentTownBuildingInstallStatusOverlay(context, building.rect || blueprint.baseRect, blueprint.installStatus, time);
  }
}

const AGENT_TOWN_BUILDING_STATUS_THEMES = {
  installing: {
    label: "installing…",
    pillBody: "#1c2c46",
    pillTrim: "#7da6e0",
    pillText: "#e8f1ff",
    glow: "rgba(125, 166, 224, 0.65)",
    scaffoldA: "rgba(255, 255, 255, 0.16)",
    scaffoldB: "rgba(15, 30, 60, 0.18)",
    desaturateAlpha: 0,
    pulse: true,
  },
  "auth-required": {
    label: "needs setup",
    pillBody: "#3d2a14",
    pillTrim: "#f5b860",
    pillText: "#fff5d8",
    glow: "rgba(245, 184, 96, 0.55)",
    scaffoldA: "rgba(255, 222, 156, 0.16)",
    scaffoldB: "rgba(70, 38, 13, 0.20)",
    desaturateAlpha: 0,
    pulse: false,
  },
  failed: {
    label: "setup failed",
    pillBody: "#411b16",
    pillTrim: "#ee6e63",
    pillText: "#fff0ee",
    glow: "rgba(238, 110, 99, 0.6)",
    scaffoldA: "rgba(238, 110, 99, 0.15)",
    scaffoldB: "rgba(0, 0, 0, 0.22)",
    desaturateAlpha: 0.32,
    pulse: false,
  },
  placed: {
    label: "needs setup",
    pillBody: "#2a2e3a",
    pillTrim: "#a0a8b8",
    pillText: "#eef2f8",
    glow: "rgba(160, 168, 184, 0.45)",
    scaffoldA: "rgba(255, 255, 255, 0.14)",
    scaffoldB: "rgba(0, 0, 0, 0.18)",
    desaturateAlpha: 0.22,
    pulse: false,
  },
};

function drawAgentTownBuildingInstallStatusOverlay(context, rect, status, time = 0) {
  if (!rect || !status || status === "installed") return;
  const theme = AGENT_TOWN_BUILDING_STATUS_THEMES[status];
  if (!theme) return;

  const x = Math.round(rect.x);
  const y = Math.round(rect.y);
  const width = Math.round(rect.width);
  const height = Math.round(rect.height);

  // 1. Desaturation wash for failed / placed-without-install. Skipped for
  // installing + auth-required to keep them looking "live".
  if (theme.desaturateAlpha > 0) {
    context.save();
    context.fillStyle = `rgba(28, 32, 40, ${theme.desaturateAlpha})`;
    context.fillRect(x, y, width, height);
    context.restore();
  }

  // 2. Diagonal scaffold stripes, clipped to the building footprint.
  // Animated only while installing.
  context.save();
  context.beginPath();
  context.rect(x, y, width, height);
  context.clip();
  const cx = x + width / 2;
  const cy = y + height / 2;
  context.translate(cx, cy);
  context.rotate(Math.PI / 4);
  const span = Math.max(width, height) * 1.4;
  const stripeThickness = 2;
  const gap = 6;
  const stride = stripeThickness + gap;
  const animOffset = theme.pulse ? (time * 0.025) % stride : 0;
  context.fillStyle = theme.scaffoldA;
  for (let s = -span - animOffset; s < span; s += stride) {
    context.fillRect(-span, s, span * 2, stripeThickness);
  }
  context.fillStyle = theme.scaffoldB;
  for (let s = -span - animOffset + stride / 2; s < span; s += stride) {
    context.fillRect(-span, s, span * 2, 1);
  }
  context.restore();

  // 3. Status frame: pulsing glow for installing, steady accent otherwise.
  context.save();
  if (theme.pulse) {
    const pulse = 0.55 + 0.45 * Math.sin(time * 0.005);
    context.globalAlpha = 0.45 + 0.45 * pulse;
    context.strokeStyle = theme.glow;
    context.lineWidth = 2;
    context.strokeRect(x - 1 + 0.5, y - 1 + 0.5, width + 2, height + 2);
  } else {
    context.strokeStyle = theme.pillTrim;
    context.lineWidth = 1.5;
    context.strokeRect(x + 0.75, y + 0.75, width - 1.5, height - 1.5);
  }
  context.restore();

  // 4. Status pill above the building.
  drawAgentTownBuildingStatusPill(context, { x, y, width }, theme);

  // 5. Failure marker corner triangle for failed.
  if (status === "failed") {
    drawAgentTownBuildingFailureMarker(context, { x, y, width }, theme);
  }
}

function drawAgentTownBuildingStatusPill(context, rect, theme) {
  if (!theme?.label) return;
  const { x, y, width } = rect;
  context.save();
  context.font = "bold 7px 'IBM Plex Mono', ui-monospace, monospace";
  const padX = 5;
  const textWidth = Math.ceil(context.measureText(theme.label).width);
  const pillWidth = textWidth + padX * 2;
  const pillHeight = 11;
  const pillX = Math.round(x + (width - pillWidth) / 2);
  const pillY = Math.round(y - pillHeight - 3);
  context.fillStyle = "rgba(0, 0, 0, 0.45)";
  context.fillRect(pillX + 1, pillY + 1, pillWidth, pillHeight);
  context.fillStyle = theme.pillBody;
  context.fillRect(pillX, pillY, pillWidth, pillHeight);
  context.fillStyle = theme.pillTrim;
  context.fillRect(pillX, pillY, pillWidth, 1);
  context.fillRect(pillX, pillY + pillHeight - 1, pillWidth, 1);
  context.fillRect(pillX, pillY, 1, pillHeight);
  context.fillRect(pillX + pillWidth - 1, pillY, 1, pillHeight);
  context.fillStyle = "rgba(255, 255, 255, 0.10)";
  context.fillRect(pillX + 1, pillY + 1, pillWidth - 2, 1);
  context.fillStyle = theme.pillText;
  context.textBaseline = "middle";
  context.textAlign = "center";
  context.fillText(theme.label, pillX + pillWidth / 2, pillY + pillHeight / 2 + 0.5);
  context.restore();
}

function drawAgentTownBuildingFailureMarker(context, rect, theme) {
  const size = 14;
  const cornerX = Math.round(rect.x + rect.width - size - 3);
  const cornerY = Math.round(rect.y + 3);
  context.save();
  context.fillStyle = "rgba(0, 0, 0, 0.45)";
  context.beginPath();
  context.moveTo(cornerX + 1, cornerY + size + 1);
  context.lineTo(cornerX + size + 1, cornerY + size + 1);
  context.lineTo(cornerX + size + 1, cornerY + 1);
  context.closePath();
  context.fill();
  context.fillStyle = theme.pillBody;
  context.beginPath();
  context.moveTo(cornerX, cornerY + size);
  context.lineTo(cornerX + size, cornerY + size);
  context.lineTo(cornerX + size, cornerY);
  context.closePath();
  context.fill();
  context.fillStyle = theme.pillTrim;
  context.beginPath();
  context.moveTo(cornerX + 2, cornerY + size - 1);
  context.lineTo(cornerX + size - 1, cornerY + size - 1);
  context.lineTo(cornerX + size - 1, cornerY + 2);
  context.closePath();
  context.fill();
  context.fillStyle = theme.pillText;
  context.fillRect(cornerX + size - 5, cornerY + 3, 2, 6);
  context.fillRect(cornerX + size - 5, cornerY + 10, 2, 2);
  context.restore();
}

function drawVisualGameSleepingQuarters(context, hitAreas, time, sleepingAgents) {
  const dorms = getAgentTownProviderDorms();
  for (const dorm of dorms) {
    const restingCount = sleepingAgents.filter((agent) => (
      dorm.providerId ? agent.providerId === dorm.providerId : true
    )).length;
    const meta = restingCount ? `${restingCount} resting` : dorm.meta || "quiet beds";
    const action = { kind: "main-view", view: "visual-interface", label: dorm.label };
    const dormArtId = dorm.providerId ? `provider-dorm-${normalizeBuildingId(dorm.providerId)}` : "";
    if (dormArtId && drawVisualGameFloorplanBuilding(context, hitAreas, {
      ...dorm,
      label: dorm.label,
      meta,
      action,
    }, dormArtId)) {
      continue;
    }
    const { x, y, width, height } = dorm.rect;
    drawVisualGameSleepRoom(context, {
      x,
      y,
      width,
      height,
      label: dorm.label,
      meta,
      beds: getVisualGameDormBeds(dorm),
      entrance: getVisualGameRenderedEntrance(dorm),
      palette: getAgentTownProviderDormPalette(dorm.providerId),
    });
    pushAgentTownPlaceHit(hitAreas, dorm, action);
  }
}

function drawVisualGameSleepRoom(context, room) {
  const { x, y, width, height, label, meta, beds, entrance } = room;
  const palette = room.palette || getAgentTownProviderDormPalette("");
  drawVisualGameRoomFloor(context, x, y, width, height, {
    floor: palette.floor,
    wall: palette.wall,
    trim: palette.trim,
    entrance,
    floorPattern: palette.floorPattern,
    floorPatternColor: palette.floorPatternColor,
    floorPatternAlpha: palette.floorPatternAlpha,
  });
  drawVisualGameBuildingSign(context, x + 8, y + 7, Math.min(width - 16, 88), 23, label, meta);
  for (const bed of beds) {
    const bedWidth = Math.max(12, Number(bed.width || 20));
    context.fillStyle = "#493628";
    context.fillRect(bed.x, bed.y + 7, bedWidth, 8);
    context.fillStyle = palette.pillow;
    context.fillRect(bed.x + 2, bed.y + 2, 7, 5);
    context.fillStyle = palette.blanket;
    context.fillRect(bed.x + 8, bed.y + 2, Math.max(6, bedWidth - 10), 11);
    context.fillStyle = "rgba(255, 244, 198, 0.18)";
    context.fillRect(bed.x + 10, bed.y + 4, Math.max(4, bedWidth - 14), 2);
  }
}

function getVisualGameDormBeds(dorm) {
  const rect = dorm?.rect || { x: 0, y: 0, width: 52, height: 52 };
  const bedWidth = Math.max(14, Math.min(20, Math.floor(rect.width * 0.32)));
  const bedY = rect.y + Math.max(22, rect.height - 22);
  return [
    { x: rect.x + 8, y: bedY, width: bedWidth },
    { x: rect.x + rect.width - bedWidth - 8, y: bedY, width: bedWidth },
  ];
}

