function getGuidedOnboardingStep() {
  return GUIDED_ONBOARDING_STEPS[state.guidedOnboarding.stepIndex] || null;
}

function isGuidedOnboardingForced() {
  try {
    return new URLSearchParams(window.location.search).get("tutorial") === "1";
  } catch {
    return false;
  }
}

function shouldStartGuidedOnboarding() {
  if (state.guidedTutorial?.active) {
    return false;
  }
  const forced = isGuidedOnboardingForced();
  if (!forced) {
    return false;
  }
  if (isBrainSetupRequired() || isAgentSetupRequired()) {
    return false;
  }
  return true;
}

function ensureGuidedOnboardingStarted() {
  if (!shouldStartGuidedOnboarding()) {
    return false;
  }
  if (state.guidedOnboarding.active) {
    return false;
  }

  if (isGuidedOnboardingForced()) {
    state.guidedOnboarding.completed = false;
    state.guidedOnboarding.dismissed = false;
  }

  state.guidedOnboarding.active = true;
  state.guidedOnboarding.stepIndex = 0;
  state.guidedOnboarding.startedAt = Date.now();
  state.guidedOnboarding.baselineAgentClickedCount = Number(state.agentTown?.signals?.agentClickedCount) || 0;
  state.guidedOnboarding.inputBuffer = "";
  state.guidedOnboarding.inputSessionId = "";
  state.guidedOnboarding.awaitingHelloResponseSessionId = "";
  state.guidedOnboarding.localEvents = {};
  state.guidedOnboarding.lastRouteRequestAt = 0;
  state.guidedOnboarding.focusSignature = "";
  return true;
}

function isGuidedOnboardingRouteSatisfied(step) {
  if (step?.ensureView) {
    if (step.ensureView === "visual-interface") {
      if (!isVisualInterfaceView()) {
        return false;
      }
    } else if (step.ensureView === "plugins") {
      if (state.currentView !== "plugins") {
        return false;
      }

      if (step.ensurePluginDetail) {
        if (state.pluginDetailId !== normalizeBuildingId(step.ensurePluginDetail)) {
          return false;
        }
      } else if (state.pluginDetailId) {
        return false;
      }
    } else if (state.currentView !== step.ensureView) {
      return false;
    }
  }

  if (step?.requireBuilderOpen) {
    if (!isVisualInterfaceView() || !isAgentTownBuilderOpen()) {
      return false;
    }

    if (
      step.requireBuilderTab &&
      normalizeAgentTownBuilderTab(state.visualGame.builderTab) !== normalizeAgentTownBuilderTab(step.requireBuilderTab)
    ) {
      return false;
    }
  }

  return true;
}

function requestGuidedOnboardingRoute(step) {
  if (!step || isGuidedOnboardingRouteSatisfied(step)) {
    return;
  }

  const now = Date.now();
  if (now - state.guidedOnboarding.lastRouteRequestAt < 900) {
    return;
  }
  state.guidedOnboarding.lastRouteRequestAt = now;

  if (step.ensureView === "visual-interface") {
    void openMainView("visual-interface").then(() => {
      if (step.autoOpenBuilder && step.requireBuilderOpen) {
        openAgentTownBuilder({
          tab: step.requireBuilderTab ? normalizeAgentTownBuilderTab(step.requireBuilderTab) : state.visualGame.builderTab,
          render: true,
        });
      }
    });
    return;
  }

  if (step.ensureView === "plugins") {
    const buildingId = step.ensurePluginDetail ? normalizeBuildingId(step.ensurePluginDetail) : "";
    void openMainView("plugins", { buildingId });
    return;
  }

  if (step.autoOpenBuilder && step.requireBuilderOpen && isVisualInterfaceView()) {
    openAgentTownBuilder({
      tab: step.requireBuilderTab ? normalizeAgentTownBuilderTab(step.requireBuilderTab) : state.visualGame.builderTab,
      render: true,
    });
    return;
  }

  if (step.ensureView) {
    void openMainView(step.ensureView);
  }
}

function normalizeGuidedOnboardingInputText(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getGuidedOnboardingStartTime() {
  return Number(state.guidedOnboarding.startedAt) || 0;
}

function hasGuidedOnboardingEvent(type) {
  if (!type) {
    return false;
  }

  if (state.guidedOnboarding.localEvents?.[type]) {
    return true;
  }

  const startTime = getGuidedOnboardingStartTime();
  return (Array.isArray(state.agentTown?.events) ? state.agentTown.events : []).some((event) => {
    if (!event || event.type !== type) {
      return false;
    }

    if (!startTime) {
      return true;
    }

    const eventTime = Date.parse(String(event.createdAt || ""));
    return Number.isFinite(eventTime) && eventTime >= startTime - 250;
  });
}

function markGuidedOnboardingEvent(type, detail = {}) {
  if (!type) {
    return;
  }

  if (!state.guidedOnboarding.localEvents || typeof state.guidedOnboarding.localEvents !== "object") {
    state.guidedOnboarding.localEvents = {};
  }
  if (state.guidedOnboarding.localEvents[type]) {
    return;
  }

  state.guidedOnboarding.localEvents[type] = true;
  void recordAgentTownEvent(type, detail);
  scheduleGuidedOnboardingSyncSafe();
}

function isGuidedOnboardingHelloText(normalizedText) {
  return normalizedText === "hello" || normalizedText.startsWith("hello ");
}

function isGuidedOnboardingBuildRequestText(normalizedText) {
  return /\blet(?:\s+s|\s+us)?\s+build\s+our\s+first\s+building\b/.test(normalizedText);
}

function isGuidedOnboardingFirstDayCalendarRequestText(normalizedText) {
  const mentionsFirstDay = /\b(first\s+day|day\s+one|commemorat(?:e|ing|ion))\b/.test(normalizedText);
  const mentionsCalendarIntent = /\b(calendar|event|schedule)\b/.test(normalizedText);
  return mentionsFirstDay && mentionsCalendarIntent;
}

function trackGuidedOnboardingInputLine(line, sessionId) {
  if (!state.guidedOnboarding.active || !line) {
    return;
  }

  const normalized = normalizeGuidedOnboardingInputText(line);
  if (!normalized) {
    return;
  }

  if (!hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.helloSent) && isGuidedOnboardingHelloText(normalized)) {
    state.guidedOnboarding.awaitingHelloResponseSessionId = sessionId;
    markGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.helloSent, {
      label: "hello",
      metadata: { sessionId },
    });
  }

  if (!hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.buildRequestSent) && isGuidedOnboardingBuildRequestText(normalized)) {
    markGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.buildRequestSent, {
      label: "lets build our first building",
      metadata: { sessionId },
    });
  }

  if (
    !hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.firstDayCalendarRequest)
    && isGuidedOnboardingFirstDayCalendarRequestText(normalized)
  ) {
    markGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.firstDayCalendarRequest, {
      label: "first day calendar request",
      metadata: { sessionId },
    });
  }
}

function trackGuidedOnboardingInput(data) {
  if (!state.guidedOnboarding.active) {
    return;
  }

  const sessionId = String(state.activeSessionId || state.connectedSessionId || "").trim();
  if (!sessionId) {
    return;
  }

  if (state.guidedOnboarding.inputSessionId !== sessionId) {
    state.guidedOnboarding.inputSessionId = sessionId;
    state.guidedOnboarding.inputBuffer = "";
  }

  let buffer = String(state.guidedOnboarding.inputBuffer || "");
  for (const char of String(data || "")) {
    if (char === "\r" || char === "\n") {
      const line = buffer.trim();
      buffer = "";
      if (line) {
        trackGuidedOnboardingInputLine(line, sessionId);
      }
      continue;
    }

    if (char === "\u007f" || char === "\b") {
      buffer = buffer.slice(0, -1);
      continue;
    }

    if (char >= " " && char !== "\u007f") {
      buffer = `${buffer}${char}`;
      if (buffer.length > 512) {
        buffer = buffer.slice(-512);
      }
    }
  }

  state.guidedOnboarding.inputBuffer = buffer;
}

function stripGuidedOnboardingTerminalOutput(value) {
  return String(value || "")
    .replace(/\u001b\[[0-9;?]*[ -/]*[@-~]/g, "")
    .replace(/\u001b\][^\u0007]*(?:\u0007|\u001b\\)/g, "")
    .replace(/[\u0000-\u001f\u007f]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function trackGuidedOnboardingOutput(data, sessionId) {
  if (!state.guidedOnboarding.active) {
    return;
  }

  if (hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.helloResponse)) {
    return;
  }

  const awaitingSessionId = String(state.guidedOnboarding.awaitingHelloResponseSessionId || "");
  if (!awaitingSessionId || awaitingSessionId !== String(sessionId || "")) {
    return;
  }

  const normalizedOutput = normalizeGuidedOnboardingInputText(stripGuidedOnboardingTerminalOutput(data));
  if (!normalizedOutput || normalizedOutput === "hello") {
    return;
  }

  state.guidedOnboarding.awaitingHelloResponseSessionId = "";
  markGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.helloResponse, {
    label: "hello response",
    metadata: { sessionId },
  });
}

function isGuidedOnboardingStepComplete(step) {
  if (!step || step.manualAdvance) {
    return false;
  }

  switch (step.id) {
    case "click-agent":
      return Number(state.agentTown?.signals?.agentClickedCount || 0) >= Number(state.guidedOnboarding.baselineAgentClickedCount || 0) + 1;
    case "say-hello":
      return hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.helloSent);
    case "say-build-first-building":
      return hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.helloResponse)
        && hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.buildRequestSent);
    case "open-buildinghub":
      return isVisualInterfaceView() && isAgentTownBuilderOpen();
    case "search-google-calendar": {
      const query = String(state.visualGame.builderFunctionalSearchQuery || "").toLowerCase();
      return query.includes("google") && query.includes("calendar");
    }
    case "install-google-calendar":
      return Boolean(
        isPluginInstallPlacementPending("google-calendar")
        || (state.visualGame.builderPlacement?.kind === "functional" && state.visualGame.builderPlacement?.pluginId === "google-calendar")
        || isPluginIdInstalled("google-calendar"),
      );
    case "place-google-calendar":
      return Boolean(getAgentTownFunctionalPlacement("google-calendar"));
    case "signin-google-calendar": {
      const plugin = getPluginById("google-calendar");
      return Boolean(plugin && isPluginBuildingAccessConfirmed(plugin));
    }
    case "tap-agent-again":
      return Number(state.agentTown?.signals?.agentClickedCount || 0) >= Number(state.guidedOnboarding.baselineAgentClickedCount || 0) + 2;
    case "first-event":
      return hasGuidedOnboardingEvent(GUIDED_ONBOARDING_EVENT_TYPES.firstDayCalendarRequest);
    default:
      return false;
  }
}

function getGuidedOnboardingSessionPointerTarget() {
  const selectedSessionId = String(state.visualGame.selectedSessionId || "").trim();
  if (selectedSessionId) {
    return `session:${selectedSessionId}`;
  }

  if ((state.visualGame.hitAreas || []).some((area) => area.kind === "session")) {
    return "session:any";
  }

  return "selector-fallback:[data-start-new-agent=\"town\"]||[data-start-new-agent]";
}

function getGuidedOnboardingTerminalPointerTarget() {
  return "terminal-input";
}

function getGuidedOnboardingPointerTarget(step) {
  if (!step) {
    return "";
  }

  switch (step.id) {
    case "click-agent":
    case "tap-agent-again":
      return getGuidedOnboardingSessionPointerTarget();
    case "say-hello":
    case "say-build-first-building":
    case "first-event":
      return getGuidedOnboardingTerminalPointerTarget();
    case "open-buildinghub":
      return "selector:[data-agent-town-builder-toggle]";
    case "search-google-calendar":
      return "selector:[data-agent-town-builder-search=\"functional\"]";
    case "install-google-calendar":
      return "selector:[data-agent-town-builder-install-functional=\"google-calendar\"]";
    case "place-google-calendar":
      return state.visualGame.builderPlacement?.cursorRect ? "placement-preview" : "selector:#visual-game-canvas";
    case "signin-google-calendar":
      return "selector-fallback:[data-plugin-confirm-access=\"google-calendar\"]||[data-plugin-open=\"google-calendar\"]";
    default:
      return "";
  }
}

function getGuidedOnboardingSessionFocusRect() {
  const selectedSessionId = String(state.visualGame.selectedSessionId || "").trim();
  const hit = (state.visualGame.hitAreas || []).find((area) => (
    area.kind === "session" && (!selectedSessionId || area.sessionId === selectedSessionId)
  ));
  return hit || null;
}

function getGuidedOnboardingFocusRect(step) {
  if (!step || !isVisualInterfaceView()) {
    return null;
  }

  switch (step.id) {
    case "click-agent":
    case "tap-agent-again":
      return getGuidedOnboardingSessionFocusRect();
    case "place-google-calendar":
      return state.visualGame.builderPlacement?.cursorRect || null;
    default:
      return null;
  }
}

function getGuidedOnboardingFocusSignature(step, rect) {
  if (!step || !rect) {
    return "";
  }

  return [
    step.id,
    Math.round(Number(rect.x) || 0),
    Math.round(Number(rect.y) || 0),
    Math.round(Number(rect.width) || 0),
    Math.round(Number(rect.height) || 0),
  ].join(":");
}

function syncGuidedOnboardingVisualFocus(step = getGuidedOnboardingStep()) {
  if (!state.guidedOnboarding.active || !isVisualInterfaceView()) {
    state.guidedOnboarding.focusSignature = "";
    return;
  }

  const rect = getGuidedOnboardingFocusRect(step);
  const signature = getGuidedOnboardingFocusSignature(step, rect);
  if (!signature || signature === state.guidedOnboarding.focusSignature) {
    return;
  }

  centerVisualGameCameraOnWorldRect(
    rect,
    step?.id === "place-google-calendar"
      ? { paddingWorld: 84, maxZoom: 1.28 }
      : { paddingWorld: 56, maxZoom: 1.7 },
  );
  state.guidedOnboarding.focusSignature = signature;
}

function syncGuidedOnboardingPointer() {
  const step = getGuidedOnboardingStep();
  const target = state.guidedOnboarding.active ? getGuidedOnboardingPointerTarget(step) : "";
  const current = state.agentPointer;

  if (!target) {
    if (current?.source === "guided-onboarding") {
      state.agentPointer = null;
      clearAgentPointerOverlay();
    }
    return;
  }

  const nextPointer = {
    id: `guided-onboarding-${step.id}`,
    source: "guided-onboarding",
    target,
    reason: "",
    expiresAt: Date.now() + 60 * 60 * 1000,
  };

  if (current?.source === "guided-onboarding" && current.id === nextPointer.id && current.target === nextPointer.target) {
    return;
  }

  clearAgentPointerOverlay();
  state.agentPointer = nextPointer;
  startAgentPointerOverlay();
}

function completeGuidedOnboarding({ render = true } = {}) {
  state.guidedOnboarding.active = false;
  state.guidedOnboarding.completed = true;
  state.guidedOnboarding.stepIndex = GUIDED_ONBOARDING_STEPS.length;
  state.guidedOnboarding.startedAt = 0;
  state.guidedOnboarding.inputBuffer = "";
  state.guidedOnboarding.awaitingHelloResponseSessionId = "";
  state.guidedOnboarding.localEvents = {};
  state.guidedOnboarding.lastRouteRequestAt = 0;
  state.guidedOnboarding.focusSignature = "";
  saveGuidedOnboardingCompletedPreference(true);
  syncGuidedOnboardingPointer();
  if (render) {
    renderShell();
  }
}

function skipGuidedOnboarding() {
  state.guidedOnboarding.dismissed = true;
  completeGuidedOnboarding();
}

function advanceGuidedOnboardingStep() {
  if (!state.guidedOnboarding.active) {
    return;
  }

  state.guidedOnboarding.stepIndex += 1;
  state.guidedOnboarding.lastRouteRequestAt = 0;
  state.guidedOnboarding.focusSignature = "";
  if (state.guidedOnboarding.stepIndex >= GUIDED_ONBOARDING_STEPS.length) {
    completeGuidedOnboarding();
    return;
  }
  renderShell();
}

function rewindGuidedOnboardingStep() {
  if (!state.guidedOnboarding.active || state.guidedOnboarding.stepIndex <= 0) {
    return;
  }

  state.guidedOnboarding.stepIndex -= 1;
  state.guidedOnboarding.lastRouteRequestAt = 0;
  state.guidedOnboarding.focusSignature = "";
  renderShell();
}

function runGuidedOnboardingAutoProgress() {
  if (!state.guidedOnboarding.active) {
    return false;
  }

  let advanced = false;
  let safety = 0;
  while (safety < GUIDED_ONBOARDING_STEPS.length) {
    safety += 1;
    const step = getGuidedOnboardingStep();
    if (!step) {
      completeGuidedOnboarding({ render: false });
      break;
    }
    if (!isGuidedOnboardingStepComplete(step)) {
      break;
    }
    state.guidedOnboarding.stepIndex += 1;
    state.guidedOnboarding.lastRouteRequestAt = 0;
    state.guidedOnboarding.focusSignature = "";
    advanced = true;
  }

  if (state.guidedOnboarding.stepIndex >= GUIDED_ONBOARDING_STEPS.length) {
    completeGuidedOnboarding({ render: false });
    advanced = true;
  }

  return advanced;
}

function renderGuidedOnboardingOverlay() {
  if (!state.guidedOnboarding.active) {
    return "";
  }

  const step = getGuidedOnboardingStep();
  if (!step) {
    return "";
  }

  const index = state.guidedOnboarding.stepIndex + 1;
  const total = GUIDED_ONBOARDING_STEPS.length;
  const nextLabel = step.manualLabel || "Continue";

  return `
    <section class="guided-onboarding-overlay" data-guided-onboarding-overlay>
      <article class="guided-onboarding-bubble" aria-label="Onboarding tutorial">
        <span class="main-search-kind">tutorial ${escapeHtml(`${index}/${total}`)}</span>
        <strong>${escapeHtml(step.title)}</strong>
        <p>${escapeHtml(step.body)}</p>
        ${step.note ? `<p class="guided-onboarding-note">${escapeHtml(step.note)}</p>` : ""}
        <div class="plugin-onboarding-actions guided-onboarding-actions">
          ${
            state.guidedOnboarding.stepIndex > 0
              ? `<button class="ghost-button toolbar-control" type="button" data-guided-onboarding-back>Back</button>`
              : ""
          }
          ${
            step.manualAdvance
              ? `<button class="primary-button toolbar-control" type="button" data-guided-onboarding-next>${escapeHtml(nextLabel)}</button>`
              : `<button class="ghost-button toolbar-control" type="button" data-guided-onboarding-next>Skip step</button>`
          }
          <button class="ghost-button toolbar-control" type="button" data-guided-onboarding-skip>Skip tutorial</button>
        </div>
      </article>
    </section>
  `;
}

function scheduleGuidedOnboardingSync() {
  if (state.guidedOnboarding.syncFrameHandle) {
    window.cancelAnimationFrame(state.guidedOnboarding.syncFrameHandle);
    state.guidedOnboarding.syncFrameHandle = 0;
  }

  state.guidedOnboarding.syncFrameHandle = window.requestAnimationFrame(() => {
    state.guidedOnboarding.syncFrameHandle = 0;
    syncGuidedOnboarding();
  });
}

function syncGuidedOnboarding() {
  const started = ensureGuidedOnboardingStarted();
  const autoAdvanced = runGuidedOnboardingAutoProgress();
  if (started || autoAdvanced) {
    renderShell();
    return;
  }

  const step = getGuidedOnboardingStep();
  if (!state.guidedOnboarding.active || !step) {
    syncGuidedOnboardingPointer();
    return;
  }

  requestGuidedOnboardingRoute(step);
  syncGuidedOnboardingPointer();
  syncGuidedOnboardingVisualFocus(step);
}

function getGuidedTutorialConfig(tutorialId = state.guidedTutorial.tutorialId) {
  const id = String(tutorialId || "").trim();
  return GUIDED_TUTORIALS[id] || GUIDED_QUEST_TUTORIALS[id] || null;
}

function getGuidedTutorialSteps(tutorialId = state.guidedTutorial.tutorialId) {
  return getGuidedTutorialConfig(tutorialId)?.steps || [];
}

function getGuidedTutorialStep() {
  return getGuidedTutorialSteps()[state.guidedTutorial.stepIndex] || null;
}

function startGuidedTutorial(tutorialId, { actionItemId = "", render = true } = {}) {
  const tutorial = getGuidedTutorialConfig(tutorialId);
  if (!tutorial) {
    return false;
  }

  closeTutorialOverlay();
  if (state.guidedOnboarding.syncFrameHandle) {
    window.cancelAnimationFrame(state.guidedOnboarding.syncFrameHandle);
    state.guidedOnboarding.syncFrameHandle = 0;
  }
  if (state.guidedOnboarding.active) {
    state.guidedOnboarding.active = false;
    state.guidedOnboarding.focusSignature = "";
    syncGuidedOnboardingPointer();
  }

  state.guidedTutorial.active = true;
  state.guidedTutorial.tutorialId = tutorialId;
  state.guidedTutorial.actionItemId = String(actionItemId || "").trim();
  state.guidedTutorial.stepIndex = 0;
  state.guidedTutorial.startedAt = Date.now();
  state.guidedTutorial.localEvents = {};
  state.guidedTutorial.lastRouteRequestAt = 0;
  state.guidedTutorial.focusSignature = "";

  if (render) {
    renderShell();
  }

  return true;
}

function hasGuidedTutorialEvent(type) {
  if (!type) {
    return false;
  }

  return Boolean(state.guidedTutorial.localEvents?.[type]);
}

function markGuidedTutorialEvent(type) {
  if (!type) {
    return;
  }

  if (!state.guidedTutorial.localEvents || typeof state.guidedTutorial.localEvents !== "object") {
    state.guidedTutorial.localEvents = {};
  }
  if (state.guidedTutorial.localEvents[type]) {
    return;
  }

  state.guidedTutorial.localEvents[type] = true;
  scheduleGuidedTutorialSyncSafe();
}

function isGuidedTutorialRouteSatisfied(step) {
  if (step?.ensureView) {
    if (step.ensureView === "visual-interface") {
      if (!isVisualInterfaceView()) {
        return false;
      }
    } else if (step.ensureView === "plugins") {
      if (state.currentView !== "plugins") {
        return false;
      }

      if (step.ensurePluginDetail) {
        if (state.pluginDetailId !== normalizeBuildingId(step.ensurePluginDetail)) {
          return false;
        }
      } else if (state.pluginDetailId) {
        return false;
      }
    } else if (state.currentView !== step.ensureView) {
      return false;
    }
  }

  if (step?.requireBuilderOpen) {
    if (!isVisualInterfaceView() || !isAgentTownBuilderOpen()) {
      return false;
    }

    if (
      step.requireBuilderTab &&
      normalizeAgentTownBuilderTab(state.visualGame.builderTab) !== normalizeAgentTownBuilderTab(step.requireBuilderTab)
    ) {
      return false;
    }
  }

  return true;
}

function requestGuidedTutorialRoute(step) {
  if (!step || isGuidedTutorialRouteSatisfied(step)) {
    return;
  }

  const now = Date.now();
  if (now - state.guidedTutorial.lastRouteRequestAt < 900) {
    return;
  }
  state.guidedTutorial.lastRouteRequestAt = now;

  if (step.ensureView === "visual-interface") {
    void openMainView("visual-interface").then(() => {
      if (step.autoOpenBuilder && step.requireBuilderOpen) {
        openAgentTownBuilder({
          tab: step.requireBuilderTab ? normalizeAgentTownBuilderTab(step.requireBuilderTab) : state.visualGame.builderTab,
          render: true,
        });
      }
    });
    return;
  }

  if (step.ensureView === "plugins") {
    const buildingId = step.ensurePluginDetail ? normalizeBuildingId(step.ensurePluginDetail) : "";
    void openMainView("plugins", { buildingId });
    return;
  }

  if (step.ensureView) {
    void openMainView(step.ensureView);
  }
}

function getGuidedTutorialFieldValue(selectors = []) {
  for (const selector of selectors) {
    const node = findAgentPointerTargetBySelector(selector, { visibleOnly: true });
    if (node instanceof HTMLInputElement || node instanceof HTMLTextAreaElement || node instanceof HTMLSelectElement) {
      const value = String(node.value || "").trim();
      if (value) {
        return value;
      }
    }
  }

  for (const selector of selectors) {
    if (!selector) {
      continue;
    }

    const node = document.querySelector(selector);
    if (node instanceof HTMLInputElement || node instanceof HTMLTextAreaElement || node instanceof HTMLSelectElement) {
      const value = String(node.value || "").trim();
      if (value) {
        return value;
      }
    }
  }

  return "";
}

function getGuidedTutorialCheckboxState(selectors = []) {
  for (const selector of selectors) {
    const node = findAgentPointerTargetBySelector(selector, { visibleOnly: true });
    if (node instanceof HTMLInputElement && node.type === "checkbox") {
      return node.checked;
    }
  }

  return null;
}

function isGuidedTutorialStepComplete(step) {
  if (!step || step.manualAdvance) {
    return false;
  }

  switch (step.id) {
    case "enter-token":
      return Boolean(
        state.settings.telegramBotTokenConfigured
        || getGuidedTutorialFieldValue(["#install-telegram-bot-token", "#telegram-bot-token"]),
      );
    case "enable-telegram": {
      const checked = getGuidedTutorialCheckboxState(['input[type="checkbox"][name="telegramEnabled"]']);
      return checked === null || checked || state.settings.telegramEnabled;
    }
    case "save-telegram":
      return Boolean(
        (state.settings.telegramEnabled && state.settings.telegramBotTokenConfigured)
        || isPluginInstallPlacementPending("telegram")
        || (state.visualGame.builderPlacement?.kind === "functional" && state.visualGame.builderPlacement?.pluginId === "telegram"),
      );
    case "place-telegram":
      return Boolean(getAgentTownFunctionalPlacement("telegram"));
    case "open-telegram-room":
      return state.visualGame.selectedBuildingId === "telegram";
    case "request-camera-permission":
      return Boolean(
        hasGuidedTutorialEvent(GUIDED_TUTORIAL_EVENT_TYPES.videoMemoryPermissionRequested)
        || state.settings.videoMemoryStatus?.devicesKnown,
      );
    case "enable-videomemory": {
      const checked = getGuidedTutorialCheckboxState(['input[type="checkbox"][name="videoMemoryEnabled"]']);
      return checked === null || checked || state.settings.videoMemoryEnabled;
    }
    case "save-videomemory":
      return Boolean(state.settings.videoMemoryEnabled && isVideoMemoryPluginInstalled());
    case "open-camera-room":
      return state.visualGame.selectedBuildingId === "videomemory";
    case "try-hand-monitor":
      return false;
    case "quest-open-builder":
      return isVisualInterfaceView() && isAgentTownBuilderOpen();
    case "quest-pick-cosmetic":
      return Boolean(state.visualGame.builderPlacement?.kind === "cosmetic");
    case "quest-place-first-building":
      return Boolean((state.agentTown?.layoutSummary?.cosmeticCount || 0) + (state.agentTown?.layoutSummary?.functionalCount || 0) >= 1);
    case "quest-open-functional-builder":
      return isVisualInterfaceView()
        && isAgentTownBuilderOpen()
        && normalizeAgentTownBuilderTab(state.visualGame.builderTab) === "functional";
    case "quest-install-functional":
      return Boolean(
        state.pluginInstallPlacementPendingIds?.size > 0
        || state.visualGame.builderPlacement?.kind === "functional"
        || (state.agentTown?.layoutSummary?.pendingFunctionalIds || []).length > 0
      );
    case "quest-place-functional-building":
      return Boolean(state.agentTown?.layoutSummary?.functionalCount >= 1);
    case "quest-canvas-open-agent":
      return Boolean(state.activeSessionId || state.visualGame.selectedSessionId);
    case "quest-canvas-button":
      return Boolean(state.agentCanvas.open || state.agentCanvas.helpOpen || (state.agentTown?.canvases || []).length > 0);
    case "quest-open-library":
      return state.currentView === "knowledge-base";
    case "quest-library-save-note":
      return Boolean(state.agentTown?.signals?.libraryNoteSavedCount >= 1);
    case "quest-open-automations":
      return state.currentView === "automations";
    case "quest-create-automation-form":
      return Boolean(state.agentTown?.signals?.automationCreatedCount >= 1);
    default:
      return false;
  }
}

function getGuidedTutorialPointerTarget(step) {
  if (!step) {
    return "";
  }

  switch (step.id) {
    case "enter-token":
      return "selector-fallback:#install-telegram-bot-token||#telegram-bot-token";
    case "enable-telegram":
      return 'selector:input[type="checkbox"][name="telegramEnabled"]';
    case "save-telegram":
      return "selector:[data-communications-action]";
    case "place-telegram":
      return state.visualGame.builderPlacement?.cursorRect ? "placement-preview" : "selector:#visual-game-canvas";
    case "open-telegram-room":
      return "building:telegram";
    case "request-camera-permission":
      return "selector:[data-videomemory-request-camera-permission]";
    case "enable-videomemory":
      return 'selector:input[type="checkbox"][name="videoMemoryEnabled"]';
    case "save-videomemory":
      return "selector:[data-videomemory-action]";
    case "open-camera-room":
      return "building:videomemory";
    case "try-hand-monitor":
      return "selector:[data-guided-tutorial-next]";
    case "quest-open-builder":
      return "selector:[data-agent-town-builder-toggle]";
    case "quest-pick-cosmetic":
      return "selector:[data-agent-town-builder-place-cosmetic]";
    case "quest-place-first-building":
      return state.visualGame.builderPlacement?.cursorRect ? "placement-preview" : "selector:#visual-game-canvas";
    case "quest-open-functional-builder":
      return "selector:[data-agent-town-builder-toggle]";
    case "quest-install-functional":
      return "selector:[data-agent-town-builder-install-functional]";
    case "quest-place-functional-building":
      return state.visualGame.builderPlacement?.cursorRect ? "placement-preview" : "selector:#visual-game-canvas";
    case "quest-canvas-open-agent":
      return getGuidedOnboardingSessionPointerTarget();
    case "quest-canvas-button":
      return "selector-fallback:#view-agent-canvas||[data-start-new-agent=\"town\"]||[data-start-new-agent]";
    case "quest-open-library":
      return "selector:[data-open-main-view=\"knowledge-base\"]";
    case "quest-library-save-note":
      return "selector-fallback:[data-knowledge-base-new-note]||#knowledge-base-search||[data-main-view=\"knowledge-base\"]";
    case "quest-open-automations":
      return "selector:[data-open-main-view=\"automations\"]";
    case "quest-create-automation-form":
      return "selector-fallback:#automation-prompt||[data-main-view=\"automations\"]";
    default:
      return "";
  }
}

function getGuidedTutorialBuildingFocusRect(buildingId) {
  return (
    (state.visualGame.hitAreas || []).find(
      (area) => area.kind === "building" && area.buildingId === normalizeBuildingId(buildingId),
    )
    || null
  );
}

function getGuidedTutorialFocusRect(step) {
  if (!step || !isVisualInterfaceView()) {
    return null;
  }

  switch (step.id) {
    case "place-telegram":
    case "quest-place-first-building":
    case "quest-place-functional-building":
      return state.visualGame.builderPlacement?.cursorRect || null;
    case "open-telegram-room":
      return getGuidedTutorialBuildingFocusRect("telegram");
    case "open-camera-room":
      return getGuidedTutorialBuildingFocusRect("videomemory");
    default:
      return null;
  }
}

function getGuidedTutorialFocusSignature(step, rect) {
  if (!step || !rect) {
    return "";
  }

  return [
    state.guidedTutorial.tutorialId,
    step.id,
    Math.round(Number(rect.x) || 0),
    Math.round(Number(rect.y) || 0),
    Math.round(Number(rect.width) || 0),
    Math.round(Number(rect.height) || 0),
  ].join(":");
}

function syncGuidedTutorialVisualFocus(step = getGuidedTutorialStep()) {
  if (!state.guidedTutorial.active || !isVisualInterfaceView()) {
    state.guidedTutorial.focusSignature = "";
    return;
  }

  const rect = getGuidedTutorialFocusRect(step);
  const signature = getGuidedTutorialFocusSignature(step, rect);
  if (!signature || signature === state.guidedTutorial.focusSignature) {
    return;
  }

  centerVisualGameCameraOnWorldRect(
    rect,
    step?.id === "place-telegram"
      ? { paddingWorld: 84, maxZoom: 1.28 }
      : { paddingWorld: 64, maxZoom: 1.55 },
  );
  state.guidedTutorial.focusSignature = signature;
}

function syncGuidedTutorialPointer() {
  const step = getGuidedTutorialStep();
  const target = state.guidedTutorial.active ? getGuidedTutorialPointerTarget(step) : "";
  const current = state.agentPointer;

  if (!target) {
    if (current?.source === "guided-tutorial") {
      state.agentPointer = null;
      clearAgentPointerOverlay();
    }
    return;
  }

  const nextPointer = {
    id: `guided-tutorial-${state.guidedTutorial.tutorialId}-${step.id}`,
    source: "guided-tutorial",
    target,
    reason: "",
    expiresAt: Date.now() + 60 * 60 * 1000,
  };

  if (current?.source === "guided-tutorial" && current.id === nextPointer.id && current.target === nextPointer.target) {
    return;
  }

  clearAgentPointerOverlay();
  state.agentPointer = nextPointer;
  startAgentPointerOverlay();
}

function completeGuidedTutorial({ render = true, markActionItemComplete = true } = {}) {
  const actionItemId = String(state.guidedTutorial.actionItemId || "").trim();
  state.guidedTutorial.active = false;
  state.guidedTutorial.tutorialId = "";
  state.guidedTutorial.actionItemId = "";
  state.guidedTutorial.stepIndex = 0;
  state.guidedTutorial.startedAt = 0;
  state.guidedTutorial.localEvents = {};
  state.guidedTutorial.lastRouteRequestAt = 0;
  state.guidedTutorial.focusSignature = "";
  syncGuidedTutorialPointer();
  if (markActionItemComplete && actionItemId) {
    void updateAgentTownActionItemStatus(actionItemId, "completed");
  }
  if (render) {
    renderShell();
  }
}

function skipGuidedTutorial() {
  completeGuidedTutorial({ markActionItemComplete: false });
}

function advanceGuidedTutorialStep() {
  if (!state.guidedTutorial.active) {
    return;
  }

  const steps = getGuidedTutorialSteps();
  state.guidedTutorial.stepIndex += 1;
  state.guidedTutorial.lastRouteRequestAt = 0;
  state.guidedTutorial.focusSignature = "";
  if (state.guidedTutorial.stepIndex >= steps.length) {
    completeGuidedTutorial();
    return;
  }
  renderShell();
}

function rewindGuidedTutorialStep() {
  if (!state.guidedTutorial.active || state.guidedTutorial.stepIndex <= 0) {
    return;
  }

  state.guidedTutorial.stepIndex -= 1;
  state.guidedTutorial.lastRouteRequestAt = 0;
  state.guidedTutorial.focusSignature = "";
  renderShell();
}

function runGuidedTutorialAutoProgress() {
  if (!state.guidedTutorial.active) {
    return false;
  }

  const steps = getGuidedTutorialSteps();
  let advanced = false;
  let safety = 0;
  while (safety < steps.length) {
    safety += 1;
    const step = getGuidedTutorialStep();
    if (!step) {
      completeGuidedTutorial({ render: false });
      break;
    }
    if (!isGuidedTutorialStepComplete(step)) {
      break;
    }
    state.guidedTutorial.stepIndex += 1;
    state.guidedTutorial.lastRouteRequestAt = 0;
    state.guidedTutorial.focusSignature = "";
    advanced = true;
  }

  if (state.guidedTutorial.stepIndex >= steps.length) {
    completeGuidedTutorial({ render: false });
    advanced = true;
  }

  return advanced;
}

function renderGuidedTutorialOverlay() {
  if (!state.guidedTutorial.active) {
    return "";
  }

  const tutorial = getGuidedTutorialConfig();
  const step = getGuidedTutorialStep();
  if (!tutorial || !step) {
    return "";
  }

  const index = state.guidedTutorial.stepIndex + 1;
  const total = getGuidedTutorialSteps().length;
  const nextLabel = step.manualLabel || "Continue";

  return `
    <section class="guided-onboarding-overlay" data-guided-tutorial-overlay>
      <article class="guided-onboarding-bubble" aria-label="${escapeHtml(tutorial.title || "Guided tutorial")}">
        <span class="main-search-kind">tutorial ${escapeHtml(`${index}/${total}`)}</span>
        <strong>${escapeHtml(step.title)}</strong>
        <p>${escapeHtml(step.body)}</p>
        ${step.note ? `<p class="guided-onboarding-note">${escapeHtml(step.note)}</p>` : ""}
        <div class="plugin-onboarding-actions guided-onboarding-actions">
          ${
            state.guidedTutorial.stepIndex > 0
              ? `<button class="ghost-button toolbar-control" type="button" data-guided-tutorial-back>Back</button>`
              : ""
          }
          ${
            step.manualAdvance
              ? `<button class="primary-button toolbar-control" type="button" data-guided-tutorial-next>${escapeHtml(nextLabel)}</button>`
              : `<button class="ghost-button toolbar-control" type="button" data-guided-tutorial-next>Skip step</button>`
          }
          <button class="ghost-button toolbar-control" type="button" data-guided-tutorial-skip>Skip tutorial</button>
        </div>
      </article>
    </section>
  `;
}

function scheduleGuidedTutorialSync() {
  if (state.guidedTutorial.syncFrameHandle) {
    window.cancelAnimationFrame(state.guidedTutorial.syncFrameHandle);
    state.guidedTutorial.syncFrameHandle = 0;
  }

  state.guidedTutorial.syncFrameHandle = window.requestAnimationFrame(() => {
    state.guidedTutorial.syncFrameHandle = 0;
    syncGuidedTutorial();
  });
}

function syncGuidedTutorial() {
  const autoAdvanced = runGuidedTutorialAutoProgress();
  if (autoAdvanced) {
    renderShell();
    return;
  }

  const step = getGuidedTutorialStep();
  if (!state.guidedTutorial.active || !step) {
    syncGuidedTutorialPointer();
    return;
  }

  requestGuidedTutorialRoute(step);
  syncGuidedTutorialPointer();
  syncGuidedTutorialVisualFocus(step);
}

function getUiNow() {
  return globalThis.performance?.now ? globalThis.performance.now() : Date.now();
}

function isNodeInsideApp(node) {
  return Boolean(node && app && (node === app || app.contains(node)));
}

function hasSelectedTextInActiveControl() {
  const activeElement = document.activeElement;
  if (!(activeElement instanceof HTMLInputElement) && !(activeElement instanceof HTMLTextAreaElement)) {
    return false;
  }

  if (!isNodeInsideApp(activeElement)) {
    return false;
  }

  const selectionStart = Number(activeElement.selectionStart);
  const selectionEnd = Number(activeElement.selectionEnd);
  return Number.isFinite(selectionStart) && Number.isFinite(selectionEnd) && selectionStart !== selectionEnd;
}

function hasSelectedDocumentText() {
  const selection = window.getSelection?.();
  if (!selection || selection.isCollapsed || selection.rangeCount === 0 || !selection.toString()) {
    return false;
  }

  return isNodeInsideApp(selection.anchorNode) || isNodeInsideApp(selection.focusNode);
}

function hasSelectedDocumentTextWithin(element) {
  const selection = window.getSelection?.();
  if (!(element instanceof Element) || !selection || selection.isCollapsed || selection.rangeCount === 0 || !selection.toString()) {
    return false;
  }

  for (let index = 0; index < selection.rangeCount; index += 1) {
    try {
      if (selection.getRangeAt(index).intersectsNode(element)) {
        return true;
      }
    } catch {
      // A detached node can throw while the DOM is being replaced.
    }
  }

  return false;
}

function hasActiveUserTextSelection() {
  return (
    hasSelectedTextInActiveControl()
    || hasSelectedDocumentText()
    || Boolean(state.terminal?.hasSelection?.())
  );
}

function scheduleSelectableRefreshFlush(delay = SELECTION_REFRESH_RETRY_MS) {
  if (state.deferredSelectableRefreshTimer) {
    window.clearTimeout(state.deferredSelectableRefreshTimer);
  }

  state.deferredSelectableRefreshTimer = window.setTimeout(() => {
    state.deferredSelectableRefreshTimer = null;
    flushDeferredSelectableRefreshes();
  }, delay);
}

function deferSelectableRefresh(kind) {
  if (!kind) {
    return;
  }

  state.deferredSelectableRefreshes.add(kind);
  scheduleSelectableRefreshFlush();
}

function shouldDeferSelectableRefresh({ force = false } = {}) {
  return !force && hasActiveUserTextSelection();
}

function flushDeferredSelectableRefreshes({ force = false } = {}) {
  if (!state.deferredSelectableRefreshes.size) {
    return;
  }

  if (!force && hasActiveUserTextSelection()) {
    scheduleSelectableRefreshFlush();
    return;
  }

  const refreshes = new Set(state.deferredSelectableRefreshes);
  state.deferredSelectableRefreshes.clear();

  if (refreshes.has("system-view") && state.currentView === "system") {
    renderShell();
    return;
  }

  if (refreshes.has("sessions") || refreshes.has("agent-inbox")) {
    if (refreshes.has("sessions")) {
      refreshSessionsList({ force: true, bindEvents: false });
    }
    if (refreshes.has("agent-inbox")) {
      refreshAgentInboxUi({ force: true, bindEvents: false });
    }
    bindSessionEvents();
  }

  if (refreshes.has("ports")) {
    refreshPortsList({ force: true });
  }

  if (refreshes.has("update")) {
    refreshUpdateUi({ force: true });
  }

  if (refreshes.has("toasts")) {
    refreshSystemToastsUi({ force: true });
  }

  if (refreshes.has("browser-use")) {
    refreshBrowserUsePluginUi({ force: true });
  }

  if (refreshes.has("ottoauth")) {
    refreshOttoAuthPluginUi({ force: true });
  }

  if (refreshes.has("videomemory")) {
    refreshVideoMemoryPluginUi({ force: true });
  }

  if (refreshes.has("scaffold-recipes")) {
    refreshScaffoldRecipesPluginUi({ force: true });
  }
}

function bindSelectableRefreshEvents() {
  document.addEventListener("selectionchange", () => {
    if (!hasActiveUserTextSelection()) {
      scheduleSelectableRefreshFlush(40);
    }
  });

  document.addEventListener("paste", handleTerminalDocumentPaste);
  document.addEventListener("copy", handleTerminalDocumentCopy);
  installDesktopPasteFallback();

  window.addEventListener("copy", () => {
    scheduleSelectableRefreshFlush(400);
  });

  const scheduleGuidedOverlaySync = (event) => {
    if (!isNodeInsideApp(event?.target)) {
      return;
    }
    scheduleGuidedOnboardingSyncSafe();
    scheduleGuidedTutorialSyncSafe();
  };

  document.addEventListener("input", scheduleGuidedOverlaySync, true);
  document.addEventListener("change", scheduleGuidedOverlaySync, true);
}

function isSessionListTemporarilyProtected() {
  return getUiNow() < state.sessionListInteractionUntil;
}

function isSessionListHoveredOrFocused() {
  const sessionsList = document.querySelector("#sessions-list");
  return Boolean(
    sessionsList
    && (sessionsList.matches(":hover") || (document.activeElement instanceof HTMLElement && sessionsList.contains(document.activeElement))),
  );
}

function isSessionListInteractionActive() {
  return isSessionListTemporarilyProtected() || isSessionListHoveredOrFocused();
}

function scheduleDeferredSessionRefreshFlush(delay = 120) {
  if (state.sessionRefreshFlushTimer) {
    window.clearTimeout(state.sessionRefreshFlushTimer);
  }

  state.sessionRefreshFlushTimer = window.setTimeout(() => {
    state.sessionRefreshFlushTimer = null;
    flushDeferredSessionRefresh();
  }, delay);
}

function markSessionListInteractionActive(duration = 700) {
  state.sessionListInteractionUntil = Math.max(state.sessionListInteractionUntil, getUiNow() + duration);
  scheduleDeferredSessionRefreshFlush(duration + 40);
}

function flushDeferredSessionRefresh() {
  if (!state.sessionsRefreshDeferred) {
    return;
  }

  if (isSessionListTemporarilyProtected()) {
    const delay = Math.max(80, state.sessionListInteractionUntil - getUiNow() + 40);
    scheduleDeferredSessionRefreshFlush(delay);
    return;
  }

  if (isSessionListHoveredOrFocused()) {
    return;
  }

  state.sessionsRefreshDeferred = false;
  refreshSessionsList({ force: true });
}

function toggleSessionProject(projectKey) {
  if (!projectKey) {
    return;
  }

  state.sessionProjectInteractionSeen = true;
  markSessionListInteractionActive();

  if (state.sessionProjectExpanded.has(projectKey)) {
    state.sessionProjectExpanded.delete(projectKey);
  } else {
    state.sessionProjectExpanded.add(projectKey);
  }

  refreshSessionsList({ force: true });
}

function suppressNextSessionProjectClick(projectKey) {
  state.sessionProjectSuppressClickKey = projectKey || "";
  state.sessionProjectSuppressClickUntil = getUiNow() + 350;
  window.setTimeout(() => {
    if (getUiNow() >= state.sessionProjectSuppressClickUntil) {
      state.sessionProjectSuppressClickKey = "";
      state.sessionProjectSuppressClickUntil = 0;
    }
  }, 380);
}

function consumeSuppressedSessionProjectClick(projectKey) {
  if (
    projectKey
    && projectKey === state.sessionProjectSuppressClickKey
    && getUiNow() < state.sessionProjectSuppressClickUntil
  ) {
    state.sessionProjectSuppressClickKey = "";
    state.sessionProjectSuppressClickUntil = 0;
    return true;
  }

  return false;
}

async function loadProjectFileTree(root, relativePath = "", { force = false } = {}) {
  if (!root) return;
  const pathKey = normalizeFileTreePath(relativePath);
  if (!state.projectFileTreeLoading[root]) state.projectFileTreeLoading[root] = new Set();
  if (!state.projectFileTreeEntries[root]) state.projectFileTreeEntries[root] = {};

  const loadingSet = state.projectFileTreeLoading[root];
  const entriesByPath = state.projectFileTreeEntries[root];

  if (!force && (loadingSet.has(pathKey) || entriesByPath[pathKey])) {
    return;
  }

  loadingSet.add(pathKey);
  if (pathKey === "") {
    state.projectFileTreeErrors[root] = "";
  }
  refreshSessionsList({ force: true });

  try {
    const params = new URLSearchParams();
    params.set("root", root);
    if (pathKey) params.set("path", pathKey);
    const payload = await fetchJson(`/api/files?${params.toString()}`);
    entriesByPath[pathKey] = payload.entries;
    state.projectFileTreeErrors[root] = "";
  } catch (error) {
    if (pathKey) {
      const expandedSet = state.projectFileTreeExpanded[root];
      if (expandedSet) expandedSet.delete(pathKey);
    }
    state.projectFileTreeErrors[root] = error.message;
  } finally {
    loadingSet.delete(pathKey);
    refreshSessionsList({ force: true });
  }
}

function toggleProjectFileTreeOpen(root) {
  if (!root) return;
  const currentlyOpen = !!state.projectFileTreeOpen[root];
  if (currentlyOpen) {
    state.projectFileTreeOpen[root] = false;
    refreshSessionsList({ force: true });
    return;
  }
  state.projectFileTreeOpen[root] = true;
  if (!state.projectFileTreeExpanded[root]) {
    state.projectFileTreeExpanded[root] = new Set();
  }
  refreshSessionsList({ force: true });
  if (!state.projectFileTreeEntries[root]?.[""]) {
    void loadProjectFileTree(root, "");
  }
}

function toggleProjectFileTreeNode(root, relativePath) {
  if (!root || !relativePath) return;
  if (!state.projectFileTreeExpanded[root]) {
    state.projectFileTreeExpanded[root] = new Set();
  }
  const expandedSet = state.projectFileTreeExpanded[root];
  if (expandedSet.has(relativePath)) {
    expandedSet.delete(relativePath);
    refreshSessionsList({ force: true });
    return;
  }
  expandedSet.add(relativePath);
  refreshSessionsList({ force: true });
  void loadProjectFileTree(root, relativePath);
}

async function openProjectFileFromTree(root, relativePath, mode) {
  if (!root || !relativePath) return;
  const normalizedRoot = normalizeWorkspaceRoot(root);
  if (normalizedRoot && normalizedRoot !== state.filesRoot) {
    await applyFilesRoot(normalizedRoot, { force: true });
  }
  await openWorkspaceFilePreview(relativePath, { mode });
}

function bindSessionEvents() {
  const sessionsList = document.querySelector("#sessions-list");
  if (sessionsList && !sessionsList.dataset.sessionRefreshBound) {
    sessionsList.dataset.sessionRefreshBound = "true";
    sessionsList.addEventListener("pointerdown", (event) => {
      const target = event.target;
      if (!(target instanceof Element)) {
        return;
      }

      const browserUseButton = target.closest("[data-open-browser-use-session]");
      if (!browserUseButton) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      markSessionListInteractionActive();
      const browserUseSessionId = browserUseButton.getAttribute("data-open-browser-use-session") || "";
      void openBrowserUseSession(browserUseSessionId);
    });
    sessionsList.addEventListener("pointerleave", () => {
      window.setTimeout(flushDeferredSessionRefresh, 80);
    });
    sessionsList.addEventListener("focusout", () => {
      window.setTimeout(flushDeferredSessionRefresh, 80);
    });
  }

  document.querySelectorAll("[data-session-project-toggle]").forEach((button) => {
    button.addEventListener("pointerdown", (event) => {
      if (event.button != null && event.button !== 0) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      button.dataset.sessionProjectPointerToggle = "true";
      const projectKey = button.getAttribute("data-session-project-toggle");
      suppressNextSessionProjectClick(projectKey);
      toggleSessionProject(projectKey);
    });

    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const projectKey = button.getAttribute("data-session-project-toggle");
      if (button.dataset.sessionProjectPointerToggle === "true") {
        delete button.dataset.sessionProjectPointerToggle;
        consumeSuppressedSessionProjectClick(projectKey);
        return;
      }

      if (consumeSuppressedSessionProjectClick(projectKey)) {
        return;
      }

      toggleSessionProject(projectKey);
    });
  });

  document.querySelectorAll("[data-session-project]").forEach((section) => {
    section.addEventListener("contextmenu", (event) => {
      const projectKey = section.getAttribute("data-session-project") || "";
      if (!projectKey) return;
      const group = getSessionProjectGroups().find((entry) => entry.key === projectKey);
      if (!group) return;
      // Only fire when the right-click happens on the header row, not deeper
      // (so right-clicking a session card / file row inside still gets its
      // own context menu).
      const target = event.target;
      if (target instanceof Element) {
        if (target.closest(".session-project-sessions") || target.closest(".session-project-files")) {
          return;
        }
      }
      event.preventDefault();
      event.stopPropagation();
      openProjectContextMenu(group, event.clientX, event.clientY);
    });
  });

  document.querySelectorAll("[data-create-session-in-cwd]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.stopPropagation();
      const cwd = button.getAttribute("data-create-session-in-cwd") || "";
      if (!cwd) {
        return;
      }

      try {
        await createSessionInFolder(cwd);
      } catch (error) {
        window.alert(error.message);
      }
    });
  });

  document.querySelectorAll("[data-session-project-files-toggle]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const root = button.getAttribute("data-session-project-files-toggle") || "";
      toggleProjectFileTreeOpen(root);
    });
  });

  document.querySelectorAll("[data-project-file-toggle]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const root = button.getAttribute("data-project-file-root") || "";
      const relativePath = normalizeFileTreePath(button.getAttribute("data-project-file-toggle"));
      if (!relativePath) return;
      toggleProjectFileTreeNode(root, relativePath);
    });
    button.addEventListener("contextmenu", (event) => {
      const root = button.getAttribute("data-project-file-root") || "";
      const relativePath = normalizeFileTreePath(button.getAttribute("data-project-file-toggle"));
      if (!relativePath) return;
      event.preventDefault();
      event.stopPropagation();
      openProjectFileContextMenu({ root, relativePath, isDirectory: true }, event.clientX, event.clientY);
    });
  });

  document.querySelectorAll("[data-project-file-open]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();
      const root = button.getAttribute("data-project-file-root") || "";
      const relativePath = normalizeFileTreePath(button.getAttribute("data-project-file-open"));
      const mode = button.getAttribute("data-file-open-mode") || "text";
      if (!relativePath) return;
      await openProjectFileFromTree(root, relativePath, mode);
    });
    button.addEventListener("contextmenu", (event) => {
      const root = button.getAttribute("data-project-file-root") || "";
      const relativePath = normalizeFileTreePath(button.getAttribute("data-project-file-open"));
      const mode = button.getAttribute("data-file-open-mode") || "text";
      if (!relativePath) return;
      event.preventDefault();
      event.stopPropagation();
      openProjectFileContextMenu({ root, relativePath, isDirectory: false, mode }, event.clientX, event.clientY);
    });
  });

  document.querySelectorAll("[data-open-swarm-graph]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const sessionId = button.getAttribute("data-open-swarm-graph") || "";
      void openSwarmGraph(sessionId);
    });
  });

  document.querySelectorAll("[data-open-swarm-project]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const projectCwd = button.getAttribute("data-open-swarm-project") || "";
      const fallbackSessionId = button.getAttribute("data-swarm-project-fallback-session") || "";
      const projectName = button.getAttribute("data-swarm-project-name") || "";
      void openSwarmProjectGraph(projectCwd, { fallbackSessionId, projectName });
    });
  });

  document.querySelectorAll("[data-open-paper-for-project]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();
      const notePath = button.getAttribute("data-open-paper-for-project") || "";
      if (!notePath) return;
      setCurrentView("knowledge-base", { notePath });
      closeMobileSidebar();
      if (!state.knowledgeBase.notes.length && !state.knowledgeBase.loading) {
        await loadKnowledgeBaseIndex();
      }
      await openKnowledgeBaseNote(notePath);
    });
  });

  document.querySelectorAll("[data-open-wandb-for-project]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const wandbUrl = button.getAttribute("data-open-wandb-for-project") || "";
      if (!wandbUrl) return;
      window.open(wandbUrl, "_blank", "noopener,noreferrer");
    });
  });

  document.querySelectorAll("[data-open-browser-use-session]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const browserUseSessionId = button.getAttribute("data-open-browser-use-session") || "";
      void openBrowserUseSession(browserUseSessionId);
    });
  });

  document.querySelectorAll("[data-delete-browser-use-session]").forEach((button) => {
    button.addEventListener("click", async (event) => {
      event.preventDefault();
      event.stopPropagation();
      const browserUseSessionId = button.getAttribute("data-delete-browser-use-session") || "";
      if (!browserUseSessionId) {
        return;
      }

      if (button instanceof HTMLButtonElement) {
        button.disabled = true;
      }

      try {
        await deleteBrowserUseSession(browserUseSessionId);
      } catch (error) {
        if (button instanceof HTMLButtonElement) {
          button.disabled = false;
        }
        window.alert(error.message);
      }
    });
  });

  document.querySelectorAll("[data-agent-profile-session]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      openAgentProfileForSession(button.getAttribute("data-agent-profile-session") || "", {
        subagentId: button.getAttribute("data-agent-profile-subagent") || "",
        browserUseSessionId: button.getAttribute("data-agent-profile-browser-use") || "",
      });
    });
  });

  document.querySelectorAll("[data-mark-session-read]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      const sessionId = button.getAttribute("data-mark-session-read") || "";
      if (!sessionId) {
        return;
      }

      if (markSessionRead(sessionId, { refresh: false })) {
        refreshSessionsList({ force: true, bindEvents: false });
        refreshAgentInboxUi({ force: true, bindEvents: false });
        bindSessionEvents();
      }
    });
  });

  document.querySelectorAll("[data-agent-town-action-open]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      openAgentTownActionHref(button.getAttribute("data-agent-town-action-open") || "");
    });
  });

  document.querySelectorAll("[data-tutorial-open]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void openTutorialOverlay(
        button.getAttribute("data-tutorial-open") || "",
        button.getAttribute("data-tutorial-action-item") || "",
      );
    });
  });

  document.querySelectorAll("[data-agent-town-action-complete]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void updateAgentTownActionItemStatus(button.getAttribute("data-agent-town-action-complete") || "", "completed");
    });
  });

  document.querySelectorAll("[data-agent-town-action-dismiss]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      void updateAgentTownActionItemStatus(button.getAttribute("data-agent-town-action-dismiss") || "", "dismissed");
    });
  });

  document.querySelectorAll("[data-agent-town-alert-open]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      openAgentTownAlertHref(button.getAttribute("data-agent-town-alert-open") || "");
    });
  });

  document.querySelectorAll("[data-session-id]").forEach((element) => {
    element.addEventListener("click", (event) => {
      if (hasSelectedDocumentTextWithin(element)) {
        return;
      }

      if (state.questHint?.anchor === "sidebar-session") {
        setQuestHint("chat-canvas-button", "Click here to see the canvas your agent publishes");
      }

      const nextSessionId = element.getAttribute("data-session-id");
      openAgentProfileForSession(nextSessionId || "");
    });

    element.addEventListener("contextmenu", (event) => {
      const sessionId = element.getAttribute("data-session-id") || "";
      if (!sessionId) {
        return;
      }
      event.preventDefault();
      event.stopPropagation();
      openSessionContextMenu(sessionId, event.clientX, event.clientY);
    });
  });
}

async function renameSessionPrompt(sessionId) {
  const session = state.sessions.find((entry) => entry.id === sessionId);
  if (!sessionId || !session) {
    return;
  }

  const nextName = window.prompt("Rename session", session.name);
  if (nextName === null) {
    return;
  }

  if (!nextName.trim()) {
    window.alert("Session name cannot be empty.");
    return;
  }

  try {
    const payload = await fetchJson(`/api/sessions/${sessionId}`, {
      method: "PATCH",
      body: JSON.stringify({ name: nextName }),
    });
    updateSession(payload.session);
    refreshShellUi({ sessions: true, ports: false, files: false });
  } catch (error) {
    window.alert(error.message);
  }
}

async function forkSessionAction(sessionId) {
  if (!sessionId) {
    return;
  }

  try {
    const payload = await fetchJson(`/api/sessions/${sessionId}/fork`, {
      method: "POST",
    });

    state.sessions = [payload.session, ...state.sessions.filter((session) => session.id !== payload.session.id)];
    state.activeSessionId = payload.session.id;
    expandSessionProject(payload.session.cwd);
    setCurrentView("shell");
    renderShell();
    connectToSession(payload.session.id);
    closeMobileSidebar();
  } catch (error) {
    window.alert(error.message);
  }
}

async function deleteSessionAction(sessionId) {
  if (!sessionId) {
    return;
  }

  try {
    try {
      await fetchJson(`/api/sessions/${sessionId}`, { method: "DELETE" });
    } catch (error) {
      if (error?.status !== 404) {
        throw error;
      }
    }
    state.sessions = state.sessions.filter((session) => session.id !== sessionId);
    const visualSelectionPruned = pruneVisualGameSessionSelection();

    if (state.activeSessionId === sessionId) {
      closeWebsocket();
      state.activeSessionId = state.sessions[0]?.id ?? null;
      const nextSession = state.sessions.find((session) => session.id === state.activeSessionId);
      if (nextSession) {
        expandSessionProject(nextSession.cwd);
      }
      renderShell();

      if (state.activeSessionId) {
        connectToSession(state.activeSessionId);
      }
      return;
    }

    if (visualSelectionPruned && isVisualInterfaceView()) {
      renderShell();
      return;
    }

    refreshShellUi();
  } catch (error) {
    window.alert(error.message);
  }
}

function ensureContextMenuElement() {
  let menu = document.querySelector("#session-context-menu");
  if (menu instanceof HTMLElement) {
    return menu;
  }

  menu = document.createElement("div");
  menu.id = "session-context-menu";
  menu.className = "session-context-menu";
  menu.setAttribute("role", "menu");
  menu.setAttribute("aria-hidden", "true");
  document.body.appendChild(menu);

  menu.addEventListener("click", async (event) => {
    const target = event.target;
    if (!(target instanceof Element)) {
      return;
    }
    const item = target.closest("[data-context-menu-index]");
    if (!(item instanceof HTMLElement) || !menu.contains(item)) {
      return;
    }
    event.preventDefault();
    event.stopPropagation();
    const idx = Number(item.getAttribute("data-context-menu-index"));
    const items = state.contextMenuItems;
    closeContextMenu();
    const action = items?.[idx];
    if (action?.onClick) {
      try {
        await action.onClick();
      } catch (error) {
        window.alert(error?.message || String(error));
      }
    }
  });

  return menu;
}

function bindContextMenuDismissOnce() {
  if (state.sessionContextMenuDismissBound) {
    return;
  }
  state.sessionContextMenuDismissBound = true;
  document.addEventListener("pointerdown", (event) => {
    if (!state.sessionContextMenu) {
      return;
    }
    const target = event.target;
    if (target instanceof Element && target.closest("#session-context-menu")) {
      return;
    }
    closeContextMenu();
  }, true);
  document.addEventListener("keydown", (event) => {
    if (event.key === "Escape" && state.sessionContextMenu) {
      closeContextMenu();
    }
  });
  window.addEventListener("blur", () => {
    if (state.sessionContextMenu) {
      closeContextMenu();
    }
  });
  window.addEventListener("resize", () => {
    if (state.sessionContextMenu) {
      closeContextMenu();
    }
  });
  window.addEventListener("scroll", () => {
    if (state.sessionContextMenu) {
      closeContextMenu();
    }
  }, true);
}

function openContextMenu(items, x, y) {
  const visibleItems = (items || []).filter((item) => item && !item.hidden);
  if (!visibleItems.length) {
    return;
  }
  const menu = ensureContextMenuElement();
  bindContextMenuDismissOnce();

  state.sessionContextMenu = { x, y };
  state.contextMenuItems = visibleItems;

  menu.innerHTML = visibleItems.map((item, idx) => `
    <button class="session-context-menu-item ${item.danger ? "is-danger" : ""}" type="button" role="menuitem" data-context-menu-index="${idx}">
      ${item.icon ? renderIcon(item.icon) : ""}<span>${escapeHtml(item.label)}</span>
    </button>
  `).join("");

  menu.classList.add("is-open");
  menu.setAttribute("aria-hidden", "false");
  menu.style.left = "0px";
  menu.style.top = "0px";

  const menuRect = menu.getBoundingClientRect();
  const viewportWidth = window.innerWidth || document.documentElement.clientWidth;
  const viewportHeight = window.innerHeight || document.documentElement.clientHeight;
  const left = Math.max(4, Math.min(x, viewportWidth - menuRect.width - 4));
  const top = Math.max(4, Math.min(y, viewportHeight - menuRect.height - 4));
  menu.style.left = `${left}px`;
  menu.style.top = `${top}px`;
}

function closeContextMenu() {
  state.sessionContextMenu = null;
  state.contextMenuItems = null;
  const menu = document.querySelector("#session-context-menu");
  if (menu instanceof HTMLElement) {
    menu.classList.remove("is-open");
    menu.setAttribute("aria-hidden", "true");
    menu.innerHTML = "";
  }
}

function openSessionContextMenu(sessionId, x, y) {
  const session = state.sessions.find((entry) => entry.id === sessionId);
  if (!session) {
    return;
  }
  openContextMenu([
    { label: "Rename", icon: Pencil, onClick: () => renameSessionPrompt(sessionId) },
    { label: "Fork", icon: GitFork, onClick: () => forkSessionAction(sessionId) },
    { label: "Delete", icon: Trash2, danger: true, onClick: () => deleteSessionAction(sessionId) },
  ], x, y);
}

function openProjectContextMenu(group, x, y) {
  if (!group) return;
  const items = [
    {
      label: "New session here",
      icon: MessageSquarePlus,
      onClick: async () => {
        try {
          await createSessionInFolder(group.cwd);
        } catch (error) {
          window.alert(error.message);
        }
      },
    },
  ];

  const paperPath = getProjectPaperNotePathForCwd(group.cwd);
  if (paperPath) {
    items.push({
      label: "Open paper",
      icon: FileText,
      onClick: async () => {
        setCurrentView("knowledge-base", { notePath: paperPath });
        closeMobileSidebar();
        if (!state.knowledgeBase.notes.length && !state.knowledgeBase.loading) {
          await loadKnowledgeBaseIndex();
        }
        await openKnowledgeBaseNote(paperPath);
      },
    });
  }

  const wandbUrl = getProjectWandbUrlForCwd(group.cwd);
  if (wandbUrl) {
    items.push({
      label: "Open W&B project",
      icon: LineChart,
      onClick: () => window.open(wandbUrl, "_blank", "noopener,noreferrer"),
    });
  }

  items.push({
    label: "Copy folder path",
    icon: FolderOpen,
    onClick: () => writeTextToClipboard(group.cwd || ""),
  });

  const sessionCount = group.sessions?.length || 0;
  items.push({
    label: sessionCount === 0 ? "Remove from sidebar" : `Remove from sidebar (${sessionCount} session${sessionCount === 1 ? "" : "s"})`,
    icon: Trash2,
    danger: true,
    onClick: async () => {
      if (sessionCount > 0) {
        const confirmed = window.confirm(
          `Remove "${group.name}" from the sidebar? This will delete ${sessionCount} session${sessionCount === 1 ? "" : "s"} in this folder.`,
        );
        if (!confirmed) return;
      }
      // Snapshot ids — deleteSessionAction mutates state.sessions on each call
      const ids = (group.sessions || []).map((session) => session.id);
      for (const id of ids) {
        await deleteSessionAction(id);
      }
      // Also forget any expand/files state for this folder
      state.sessionProjectExpanded.delete(group.key);
      const root = normalizeWorkspaceRoot(group.cwd || "");
      if (root) {
        delete state.projectFileTreeOpen[root];
        delete state.projectFileTreeEntries[root];
        delete state.projectFileTreeExpanded[root];
        delete state.projectFileTreeLoading[root];
        delete state.projectFileTreeErrors[root];
      }
      refreshSessionsList({ force: true });
    },
  });

  openContextMenu(items, x, y);
}

function openProjectFileContextMenu({ root, relativePath, isDirectory, mode }, x, y) {
  if (!relativePath) return;
  const items = [];

  if (!isDirectory) {
    items.push({
      label: "Open",
      icon: FileText,
      onClick: () => openProjectFileFromTree(root, relativePath, mode || "text"),
    });
    items.push({
      label: "Open raw",
      icon: File,
      onClick: () => openProjectFileFromTree(root, relativePath, "raw"),
    });
  } else {
    items.push({
      label: state.projectFileTreeExpanded[root]?.has(relativePath) ? "Collapse" : "Expand",
      icon: Folder,
      onClick: () => toggleProjectFileTreeNode(root, relativePath),
    });
  }

  const absolutePath = joinWorkspacePath(root, relativePath);
  items.push({
    label: "Copy path",
    icon: Copy,
    onClick: () => writeTextToClipboard(absolutePath || relativePath),
  });
  items.push({
    label: "Copy relative path",
    icon: Copy,
    onClick: () => writeTextToClipboard(relativePath),
  });

  openContextMenu(items, x, y);
}

function openGlobalFileContextMenu({ relativePath, isDirectory, mode }, x, y) {
  if (!relativePath) return;
  const items = [];

  if (!isDirectory) {
    items.push({
      label: "Open",
      icon: FileText,
      onClick: () => openWorkspaceFilePreview(relativePath, { mode: mode || "text" }),
    });
    items.push({
      label: "Open raw",
      icon: File,
      onClick: () => openWorkspaceFilePreview(relativePath, { mode: "raw" }),
    });
  } else {
    items.push({
      label: state.fileTreeExpanded.has(relativePath) ? "Collapse" : "Expand",
      icon: Folder,
      onClick: () => {
        if (state.fileTreeExpanded.has(relativePath)) {
          state.fileTreeExpanded.delete(relativePath);
          refreshFileTreeUi();
        } else {
          state.fileTreeExpanded.add(relativePath);
          refreshFileTreeUi();
          void loadFileTree(relativePath);
        }
      },
    });
  }

  const absolutePath = joinWorkspacePath(state.filesRoot, relativePath);
  items.push({
    label: "Copy path",
    icon: Copy,
    onClick: () => writeTextToClipboard(absolutePath || relativePath),
  });
  items.push({
    label: "Copy relative path",
    icon: Copy,
    onClick: () => writeTextToClipboard(relativePath),
  });

  openContextMenu(items, x, y);
}

function refreshSessionsList({ force = false, bindEvents = true } = {}) {
  const sessionsList = document.querySelector("#sessions-list");
  if (!sessionsList) {
    return;
  }

  if (shouldDeferSelectableRefresh({ force })) {
    deferSelectableRefresh("sessions");
    return;
  }

  if (!force && isSessionListInteractionActive()) {
    state.sessionsRefreshDeferred = true;
    if (isSessionListTemporarilyProtected()) {
      const delay = Math.max(80, state.sessionListInteractionUntil - getUiNow() + 40);
      scheduleDeferredSessionRefreshFlush(delay);
    }
    return;
  }

  state.sessionsRefreshDeferred = false;
  sessionsList.innerHTML = renderSessionCards();
  if (bindEvents) {
    bindSessionEvents();
  }
}

function refreshAgentInboxUi({ force = false, bindEvents = true } = {}) {
  const inboxList = document.querySelector("#agent-inbox-list");
  if (!inboxList) {
    return;
  }

  if (shouldDeferSelectableRefresh({ force })) {
    deferSelectableRefresh("agent-inbox");
    return;
  }

  inboxList.innerHTML = renderAgentInboxCards();
  if (bindEvents) {
    bindSessionEvents();
  }
}

function refreshPortsList({ force = false } = {}) {
  const portsList = document.querySelector("#ports-list");
  if (!portsList) {
    return;
  }

  if (!isLocalhostAppsEnabled()) {
    portsList.innerHTML = "";
    return;
  }

  if (shouldDeferSelectableRefresh({ force })) {
    deferSelectableRefresh("ports");
    return;
  }

  portsList.innerHTML = renderPortCards();
  bindPortEvents();
}

