function bindBuildingHubCatalogControls() {
  document.querySelectorAll("[data-buildinghub-tab]").forEach((button) => {
    button.addEventListener("click", () => {
      const nextTab = normalizeBuildingHubTab(button.getAttribute("data-buildinghub-tab") || "");
      if (state.buildingHubTab === nextTab) {
        return;
      }
      state.buildingHubTab = nextTab;
      updateRoute({ view: "plugins", buildingId: "", buildingHubTab: nextTab });
      renderShell();
      if (nextTab === "bundles") {
        fetchBundleHubCatalog({ force: false }).catch(() => {});
      }
    });
  });

  document.querySelectorAll("[data-bundle-hub-refresh]").forEach((button) => {
    button.addEventListener("click", () => {
      fetchBundleHubCatalog({ force: true }).catch(() => {});
    });
  });

  document.querySelectorAll("[data-bundle-hub-preview]").forEach((button) => {
    button.addEventListener("click", () => {
      const id = button.getAttribute("data-bundle-hub-preview") || "";
      previewBundleHubEntry(id).catch(() => {});
    });
  });

  document.querySelectorAll("[data-bundle-hub-close-preview]").forEach((button) => {
    button.addEventListener("click", () => {
      closeBundleHubPreview();
    });
  });

  document.querySelectorAll("[data-bundle-hub-import]").forEach((button) => {
    button.addEventListener("click", () => {
      const id = button.getAttribute("data-bundle-hub-import") || "";
      importBundleHubEntry(id).catch(() => {});
    });
  });

  document.querySelectorAll("[data-bundle-hub-confirm-import]").forEach((button) => {
    button.addEventListener("click", () => {
      const id = button.getAttribute("data-bundle-hub-confirm-import") || "";
      importBundleHubEntry(id).catch(() => {});
    });
  });

  document.querySelectorAll("[data-buildinghub-advanced-toggle]").forEach((button) => {
    button.addEventListener("click", () => {
      state.buildingHubAdvancedOpen = !state.buildingHubAdvancedOpen;
      renderShell();
    });
  });

  document.querySelectorAll("[data-buildinghub-community-toggle]").forEach((input) => {
    input.addEventListener("change", async () => {
      const form = input.closest("form");
      if (!(form instanceof HTMLFormElement)) {
        return;
      }

      if (input instanceof HTMLInputElement) {
        input.disabled = true;
      }

      try {
        await saveSettingsFromForm(form);
        renderShell();
      } catch (error) {
        window.alert(error.message);
        renderShell();
      }
    });
  });
}

async function setPluginInstalled(pluginId, installed, { force = false, placeAfterInstall = false } = {}) {
  const plugin = getPluginById(pluginId);
  if (!plugin) {
    return;
  }
  const normalizedPluginId = getPluginId(plugin);
  const wasInstalled = isPluginInstalled(plugin);
  const detailOpen = state.currentView === "plugins" && state.pluginDetailId === normalizedPluginId;
  const buildingOpen = isVisualInterfaceView() && state.visualGame.selectedBuildingId === normalizedPluginId;
  const surfaceOpen = detailOpen || buildingOpen;

  if (isPluginSystemApp(plugin)) {
    state.pluginOnboardingOpenId = "";
    if (surfaceOpen) {
      renderShell();
    } else {
      refreshPluginSearchUi();
    }
    return;
  }

  if (installed && hasPluginSetupFlow(plugin) && !force) {
    if (buildingOpen) {
      renderShell();
      return;
    }
    openPluginDetail(pluginId);
    return;
  }

  if (installed && getPluginOnboarding(plugin)) {
    state.pluginOnboardingOpenId = "";
  } else if (!installed && state.pluginOnboardingOpenId === normalizedPluginId) {
    state.pluginOnboardingOpenId = "";
  }

  if (!installed) {
    setPluginInstallPlacementPending(normalizedPluginId, false);
  }

  state.pluginInstallActions = {
    ...state.pluginInstallActions,
    [normalizedPluginId]: installed ? "installing" : "uninstalling",
  };
  if (surfaceOpen) {
    renderShell();
  } else {
    refreshPluginSearchUi();
  }

  try {
    const body = {
      installedPluginIds: getUpdatedInstalledPluginIds(normalizedPluginId, installed),
    };
    const enabledSetting = String(plugin.install?.enabledSetting || "").trim();
    if (enabledSetting) {
      body[enabledSetting] = installed;
    }

    const [payload] = await Promise.all([
      fetchJson("/api/settings", {
        method: "PATCH",
        body: JSON.stringify(body),
      }),
      sleep(520),
    ]);

    applySettingsState(payload.settings);
    if (payload.agentPrompt) {
      applyAgentPromptState(payload.agentPrompt);
    }
    setPluginInstallPlacementPending(normalizedPluginId, false);
    delete state.pluginInstallActions[normalizedPluginId];

    // Kick off the one-click install plan after the settings flip succeeds so
    // the catalog shows the building as installed during the long-running
    // install (CLI install + auth flow can take 30+ s). The plan handler
    // streams progress into state.buildingInstallJobs which the system-toast
    // layer renders.
    if (installed && plugin.install?.plan) {
      runBuildingInstallPlan(plugin).catch(() => {});
    }

    if (normalizedPluginId === "localhost-apps") {
      if (!installed) {
        clearLocalhostAppsSurfaces();
      }
      renderShell();
      if (installed) {
        void loadPorts();
      }
      return;
    }

    if (normalizedPluginId === "buildinghub") {
      await loadBuildingHubCatalog({ force: true, renderOnComplete: false });
    }

    if (!installed && isAgentTownFunctionalPlugin(plugin)) {
      removeAgentTownFunctionalPlacement(normalizedPluginId);
      saveAgentTownLayoutPreferences();
    }

    if (installed && isAgentTownFunctionalPlugin(plugin) && !wasInstalled) {
      const hasPlacement = Boolean(getAgentTownFunctionalPlacement(normalizedPluginId));
      if (placeAfterInstall && !hasPlacement) {
        startAgentTownFunctionalPlacement(normalizedPluginId, { markPending: true });
        return;
      }
      if (!hasPlacement) {
        setAgentTownFunctionalPending(normalizedPluginId, true);
        saveAgentTownLayoutPreferences();
      } else if (isAgentTownFunctionalPending(normalizedPluginId)) {
        setAgentTownFunctionalPending(normalizedPluginId, false);
        saveAgentTownLayoutPreferences();
      }
    }

    if (surfaceOpen) {
      renderShell();
    } else {
      refreshPluginSearchUi();
    }

    refreshBrowserUsePluginUi({ force: true });
    refreshOttoAuthPluginUi({ force: true });
    refreshCommunicationsPluginUi({ force: true });
    refreshVideoMemoryPluginUi({ force: true });
  } catch (error) {
    delete state.pluginInstallActions[normalizedPluginId];
    if (surfaceOpen) {
      renderShell();
    } else {
      refreshPluginSearchUi();
    }
    window.alert(error.message);
  }
}

const BUILDINGHUB_GITHUB_OAUTH_START_PATH = "/buildinghub/auth/github/start";
const BUILDINGHUB_GITHUB_OAUTH_DISCONNECT_PATH = "/buildinghub/auth/github/disconnect";
const GITHUB_OAUTH_RESULT_MESSAGE_TYPE = "buildinghub-github-oauth-result";
const GITHUB_OAUTH_POPUP_TIMEOUT_MS = 3 * 60 * 1000;
const GOOGLE_OAUTH_RESULT_MESSAGE_TYPE = "vibe-research-google-oauth-result";
const GOOGLE_OAUTH_POPUP_TIMEOUT_MS = 3 * 60 * 1000;
const GOOGLE_OAUTH_BUILDING_IDS = new Set(["google-drive", "google-calendar", "gmail"]);

function usesGoogleOAuthSetup(buildingId) {
  return GOOGLE_OAUTH_BUILDING_IDS.has(normalizeBuildingId(buildingId));
}

async function completeGoogleOAuthSetup(buildingId) {
  const normalizedBuildingId = normalizeBuildingId(buildingId);
  const startUrl = new URL("/api/google/oauth/start", window.location.origin);
  startUrl.searchParams.set("buildingId", normalizedBuildingId);

  const popup = window.open(
    startUrl.toString(),
    `vibe-research-google-oauth-${normalizedBuildingId}`,
    "popup,width=520,height=700,resizable=yes,scrollbars=yes,toolbar=no,menubar=no,status=no",
  );

  if (!popup) {
    throw new Error("Google authorization popup was blocked. Allow popups and try again.");
  }

  popup.focus?.();

  await new Promise((resolve, reject) => {
    let settled = false;

    const cleanup = () => {
      window.removeEventListener("message", handleMessage);
      window.clearTimeout(timeoutId);
      window.clearInterval(popupPollId);
    };

    const finish = (error = null) => {
      if (settled) {
        return;
      }

      settled = true;
      cleanup();
      if (error) {
        reject(error);
      } else {
        resolve();
      }
    };

    const handleMessage = (event) => {
      if (event.origin !== window.location.origin) {
        return;
      }

      const payload = event.data && typeof event.data === "object" ? event.data : null;
      if (!payload || payload.type !== GOOGLE_OAUTH_RESULT_MESSAGE_TYPE) {
        return;
      }

      const payloadBuildingId = normalizeBuildingId(payload.buildingId || "");
      if (payloadBuildingId !== normalizedBuildingId) {
        return;
      }

      if (payload.status === "success") {
        finish();
        return;
      }

      finish(new Error(String(payload.message || "Google access was not completed.")));
    };

    const timeoutId = window.setTimeout(() => {
      finish(new Error("Google authorization timed out. Please try again."));
    }, GOOGLE_OAUTH_POPUP_TIMEOUT_MS);

    const popupPollId = window.setInterval(() => {
      if (popup.closed) {
        finish(new Error("Google authorization window was closed before completion."));
      }
    }, 350);

    window.addEventListener("message", handleMessage);
  });

  const payload = await fetchJson("/api/settings");
  applySettingsState(payload.settings);
}

async function completeGitHubOAuthSetup() {
  const popup = window.open(
    BUILDINGHUB_GITHUB_OAUTH_START_PATH,
    "buildinghub-github-oauth",
    "popup,width=520,height=700,resizable=yes,scrollbars=yes,toolbar=no,menubar=no,status=no",
  );

  if (!popup) {
    throw new Error("GitHub authorization popup was blocked. Allow popups and try again.");
  }

  popup.focus?.();

  await new Promise((resolve, reject) => {
    let settled = false;

    const cleanup = () => {
      window.removeEventListener("message", handleMessage);
      window.clearTimeout(timeoutId);
      window.clearInterval(popupPollId);
    };

    const finish = (error = null) => {
      if (settled) {
        return;
      }

      settled = true;
      cleanup();
      if (error) {
        reject(error);
      } else {
        resolve();
      }
    };

    const handleMessage = (event) => {
      if (event.origin !== window.location.origin) {
        return;
      }

      const payload = event.data && typeof event.data === "object" ? event.data : null;
      if (!payload || payload.type !== GITHUB_OAUTH_RESULT_MESSAGE_TYPE) {
        return;
      }

      if (payload.status === "success") {
        finish();
        return;
      }

      finish(new Error(String(payload.message || "GitHub sign-in was not completed.")));
    };

    const timeoutId = window.setTimeout(() => {
      finish(new Error("GitHub authorization timed out. Please try again."));
    }, GITHUB_OAUTH_POPUP_TIMEOUT_MS);

    const popupPollId = window.setInterval(() => {
      if (popup.closed) {
        finish(new Error("GitHub authorization window was closed before completion."));
      }
    }, 350);

    window.addEventListener("message", handleMessage);
  });

  const payload = await fetchJson("/api/settings");
  applySettingsState(payload.settings);
}

async function saveBuildingHubAuthState(provider = "") {
  const normalizedProvider = normalizeBuildingHubAuthProvider(provider);
  const confirmedIds = getBuildingAccessConfirmedIds();
  if (normalizedProvider) {
    confirmedIds.add("buildinghub");
  } else {
    confirmedIds.delete("buildinghub");
  }

  const payload = await fetchJson("/api/settings", {
    method: "PATCH",
    body: JSON.stringify({
      buildingAccessConfirmedIds: [...confirmedIds].sort(),
      buildingHubAuthProvider: normalizedProvider,
    }),
  });

  applySettingsState(payload.settings);
  if (payload.agentPrompt) {
    applyAgentPromptState(payload.agentPrompt);
  }

  if (normalizedProvider && state.settings.buildingHubEnabled) {
    await loadBuildingHubCatalog({ force: true, renderOnComplete: false });
  }

  renderShell();
}

async function loginToBuildingHub(provider) {
  if (normalizeBuildingHubAuthProvider(provider) === "github") {
    await completeGitHubOAuthSetup();
    if (state.settings.buildingHubEnabled) {
      await loadBuildingHubCatalog({ force: true, renderOnComplete: false });
    }
    renderShell();
    return;
  }

  await saveBuildingHubAuthState(provider);
}

async function logoutFromBuildingHub() {
  if (normalizeBuildingHubAuthProvider(state.settings.buildingHubAuthProvider) === "github") {
    const payload = await fetchJson(BUILDINGHUB_GITHUB_OAUTH_DISCONNECT_PATH, {
      method: "POST",
      body: "{}",
    });
    applySettingsState(payload.settings);
    renderShell();
    return;
  }

  await saveBuildingHubAuthState("");
}

async function confirmPluginBuildingAccess(pluginId, setupUrl = "") {
  const normalizedPluginId = normalizeBuildingId(pluginId);
  const plugin = getPluginById(normalizedPluginId);
  if (!plugin) {
    return;
  }

  if (usesGoogleOAuthSetup(normalizedPluginId)) {
    await completeGoogleOAuthSetup(normalizedPluginId);
    renderShell();
    return;
  }

  const url = normalizePluginSetupUrl(setupUrl);
  if (url) {
    window.open(url, "_blank", "noopener,noreferrer");
  }

  const confirmedIds = getBuildingAccessConfirmedIds();
  confirmedIds.add(normalizedPluginId);
  const payload = await fetchJson("/api/settings", {
    method: "PATCH",
    body: JSON.stringify({
      buildingAccessConfirmedIds: [...confirmedIds].sort(),
    }),
  });

  applySettingsState(payload.settings);
  if (payload.agentPrompt) {
    applyAgentPromptState(payload.agentPrompt);
  }
  renderShell();
}

function findNamedSetupControl(setting, root = document) {
  if (!setting) {
    return null;
  }

  const controls = root.querySelectorAll("input, select, textarea, button");
  for (const control of controls) {
    if (control.getAttribute("name") === setting) {
      return control;
    }
  }

  return null;
}

function isSetupTargetUsable(element) {
  return Boolean(element && !element.closest?.("[inert]") && element.getClientRects?.().length);
}

function findPluginSetupTarget({ pluginId = "", setting = "", selector = "" } = {}) {
  const roots = [
    ...document.querySelectorAll(`[data-plugin-setup-root="${pluginId}"]`),
    document,
  ];

  for (const root of roots) {
    if (selector) {
      try {
        const target = root.querySelector(selector);
        if (isSetupTargetUsable(target)) {
          return target;
        }
      } catch {
        // Manifest selectors are optional hints; an invalid one should not break setup navigation.
      }
    }

    const namedControl = findNamedSetupControl(setting, root);
    if (isSetupTargetUsable(namedControl)) {
      return namedControl;
    }
  }

  return null;
}

function getSetupHighlightTargets(target) {
  const targets = new Set([target]);
  const label = target.closest?.("label");
  if (label) {
    targets.add(label);
  }
  const id = target.getAttribute?.("id");
  if (id) {
    const labelForTarget = [...document.querySelectorAll("label")].find((candidate) => candidate.htmlFor === id);
    if (labelForTarget) {
      targets.add(labelForTarget);
    }
  }
  return [...targets];
}

function highlightSetupTarget(target) {
  const targets = getSetupHighlightTargets(target);
  for (const element of targets) {
    element.classList.remove("setup-target-highlight");
    // Restart the animation if the same field is clicked twice.
    void element.offsetWidth;
    element.classList.add("setup-target-highlight");
  }

  window.setTimeout(() => {
    for (const element of targets) {
      element.classList.remove("setup-target-highlight");
    }
  }, 2400);
}

function focusPluginSetupTarget(target) {
  const element = findPluginSetupTarget(target);
  if (!element) {
    return false;
  }

  element.scrollIntoView({ behavior: "smooth", block: "center", inline: "nearest" });
  window.setTimeout(() => {
    if (typeof element.focus === "function") {
      element.focus({ preventScroll: true });
    }
    highlightSetupTarget(element);
  }, 180);
  return true;
}

function schedulePendingPluginSetupFocus() {
  if (!state.pendingPluginSetupFocus) {
    return;
  }

  window.requestAnimationFrame(() => {
    window.requestAnimationFrame(() => {
      const pending = state.pendingPluginSetupFocus;
      if (!pending) {
        return;
      }

      if (focusPluginSetupTarget(pending)) {
        state.pendingPluginSetupFocus = null;
        return;
      }

      pending.attempts = (pending.attempts || 0) + 1;
      if (pending.attempts > 4) {
        state.pendingPluginSetupFocus = null;
      } else {
        schedulePendingPluginSetupFocus();
      }
    });
  });
}

function handlePluginSetupFocus(button) {
  const pluginId = normalizeBuildingId(button.getAttribute("data-plugin-setup-focus") || "");
  const target = {
    pluginId,
    selector: button.getAttribute("data-plugin-setup-selector") || "",
    setting: button.getAttribute("data-plugin-setup-setting") || "",
  };

  if (focusPluginSetupTarget(target)) {
    return;
  }

  const plugin = getPluginById(pluginId);
  if (!plugin) {
    return;
  }

  state.pendingPluginSetupFocus = {
    ...target,
    attempts: 0,
  };
  openPluginDetail(pluginId);
  schedulePendingPluginSetupFocus();
}

function bindPluginCardEvents() {
  document.querySelectorAll("[data-plugin-confirm-access]").forEach((button) => {
    button.addEventListener("click", () => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }

      button.disabled = true;
      button.querySelector("span:last-child")?.replaceChildren(document.createTextNode("Opening..."));
      void confirmPluginBuildingAccess(
        button.getAttribute("data-plugin-confirm-access") || "",
        button.getAttribute("data-plugin-setup-url") || "",
      ).catch((error) => {
        window.alert(error.message);
        renderShell();
      });
    });
  });

  document.querySelectorAll("[data-plugin-setup-focus]").forEach((button) => {
    button.addEventListener("click", () => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }

      handlePluginSetupFocus(button);
    });
  });

  document.querySelectorAll("[data-plugin-open]").forEach((button) => {
    button.addEventListener("click", () => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }

      openPluginDetail(button.getAttribute("data-plugin-open") || "");
    });
  });

  document.querySelectorAll("[data-plugin-detail-back]").forEach((button) => {
    button.addEventListener("click", () => {
      closePluginDetail();
    });
  });

  document.querySelectorAll("[data-plugin-cancel-install]").forEach((button) => {
    button.addEventListener("click", () => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }

      const pluginId = button.getAttribute("data-plugin-cancel-install") || "";
      resetPluginInstallProgression(pluginId);
      if (isVisualInterfaceView() && state.visualGame.selectedBuildingId === pluginId) {
        clearVisualGameSelection();
        return;
      }

      if (state.pluginDetailId === pluginId) {
        closePluginDetail();
        return;
      }

      if (state.pluginOnboardingOpenId === pluginId) {
        state.pluginOnboardingOpenId = "";
      }
      refreshPluginSearchUi();
    });
  });

  document.querySelectorAll("[data-plugin-finish-install]").forEach((button) => {
    button.addEventListener("click", () => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }

      const pluginId = button.getAttribute("data-plugin-finish-install") || "";
      const plugin = getPluginById(pluginId);
      if (plugin && isAgentTownFunctionalPlugin(plugin) && !isPluginInstalled(plugin)) {
        if (!startFunctionalPluginPlacementInstall(pluginId)) {
          window.alert(`Could not start placement for ${plugin.name}.`);
        }
        return;
      }
      void setPluginInstalled(pluginId, true, { force: true });
    });
  });

  document.querySelectorAll("[data-plugin-install]").forEach((button) => {
    button.addEventListener("click", () => {
      if (!(button instanceof HTMLButtonElement)) {
        return;
      }

      const pluginId = button.getAttribute("data-plugin-install") || "";
      const installed = button.getAttribute("data-plugin-next-installed") === "true";
      const plugin = getPluginById(pluginId);
      if (!installed && plugin && isAgentTownFunctionalPlugin(plugin)) {
        if (!startFunctionalPluginPlacementInstall(pluginId)) {
          window.alert(`Could not start placement for ${plugin.name}.`);
        }
        return;
      }
      void setPluginInstalled(pluginId, installed);
    });
  });

  bindPluginInstallStepEvents();
}

function createClientId(prefix) {
  const randomId =
    typeof window.crypto?.randomUUID === "function"
      ? window.crypto.randomUUID()
      : `${Date.now()}-${Math.random().toString(16).slice(2)}`;
  return `${prefix}-${randomId}`.toLowerCase().replace(/[^a-z0-9_-]+/g, "-");
}

function getAgentAutomations() {
  return Array.isArray(state.settings.agentAutomations) ? state.settings.agentAutomations : [];
}

async function saveAgentAutomations(agentAutomations) {
  const payload = await fetchJson("/api/settings", {
    method: "PATCH",
    body: JSON.stringify({ agentAutomations }),
  });
  applySettingsState(payload.settings);
  if (payload.agentPrompt) {
    applyAgentPromptState(payload.agentPrompt);
  }
}

async function createAgentAutomationFromForm(form) {
  const formData = new FormData(form);
  const prompt = String(formData.get("prompt") || "").trim();
  if (!prompt) {
    throw new Error("Add a prompt for the agent first.");
  }

  const automation = {
    cadence: String(formData.get("cadence") || "daily"),
    createdAt: new Date().toISOString(),
    enabled: true,
    id: createClientId("automation"),
    prompt,
    time: String(formData.get("time") || "09:00"),
    weekday: String(formData.get("weekday") || "monday"),
  };

  await saveAgentAutomations([...getAgentAutomations(), automation]);
  void recordAgentTownEvent("automation_created", {
    label: automation.prompt.slice(0, 120),
    metadata: { automationId: automation.id, cadence: automation.cadence, time: automation.time },
  });
}

async function deleteAgentAutomation(automationId) {
  await saveAgentAutomations(getAgentAutomations().filter((automation) => automation.id !== automationId));
}

function bindAutomationEvents() {
  document.querySelectorAll("[data-toggle-automation]").forEach((button) => {
    button.addEventListener("click", async () => {
      const automation = button.getAttribute("data-toggle-automation");
      if (automation !== "wiki-backup" || !(button instanceof HTMLButtonElement)) {
        return;
      }

      const nextEnabled = !state.settings.wikiGitBackupEnabled;
      const previousText = button.textContent;
      button.disabled = true;
      button.textContent = nextEnabled ? "enabling..." : "disabling...";

      try {
        await updateWikiBackupAutomation(nextEnabled);
        renderShell();
      } catch (error) {
        button.disabled = false;
        button.textContent = previousText;
        window.alert(error.message);
      }
    });
  });

  document.querySelectorAll(".automation-create-form").forEach((formElement) => {
    formElement.addEventListener("submit", async (event) => {
      event.preventDefault();
      const form = event.currentTarget;
      if (!(form instanceof HTMLFormElement)) {
        return;
      }

      const button = form.querySelector("button[type='submit']");
      if (button instanceof HTMLButtonElement) {
        button.disabled = true;
        button.textContent = "creating...";
      }
      clearQuestHintFor("automation-create", { render: false });

      try {
        await createAgentAutomationFromForm(form);
        renderShell();
      } catch (error) {
        if (button instanceof HTMLButtonElement) {
          button.disabled = false;
          button.textContent = "create automation";
        }
        window.alert(error.message);
      }
    });
  });

  document.querySelectorAll("[data-delete-agent-automation]").forEach((button) => {
    button.addEventListener("click", async () => {
      const automationId = button.getAttribute("data-delete-agent-automation") || "";
      if (!automationId || !(button instanceof HTMLButtonElement)) {
        return;
      }

      button.disabled = true;
      button.textContent = "deleting...";
      try {
        await deleteAgentAutomation(automationId);
        renderShell();
      } catch (error) {
        button.disabled = false;
        button.textContent = "delete";
        window.alert(error.message);
      }
    });
  });
}

function capturePluginInstallFormDraft(pluginId, form) {
  if (!pluginId || !(form instanceof HTMLFormElement)) return;
  const formData = new FormData(form);
  const draft = {};
  for (const [key, value] of formData.entries()) {
    if (typeof value === "string") {
      draft[key] = value;
    }
  }
  setPluginInstallDraft(pluginId, draft);
}

function bindPluginInstallStepEvents() {
  document.querySelectorAll("[data-plugin-install-advance]").forEach((element) => {
    element.addEventListener("click", (event) => {
      const pluginId = element.getAttribute("data-plugin-install-advance") || "";
      const nextStep = Number(element.getAttribute("data-plugin-install-next-step"));
      if (!pluginId || !Number.isFinite(nextStep)) return;
      const form = element.closest("form");
      if (form instanceof HTMLFormElement) {
        capturePluginInstallFormDraft(pluginId, form);
      }
      if (!(element instanceof HTMLAnchorElement)) {
        event.preventDefault();
      }
      setPluginInstallStep(pluginId, nextStep);
      renderShell();
    });
  });

  document.querySelectorAll("[data-plugin-install-capture-advance]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      const pluginId = button.getAttribute("data-plugin-install-capture-advance") || "";
      const nextStep = Number(button.getAttribute("data-plugin-install-next-step"));
      if (!pluginId || !Number.isFinite(nextStep)) return;
      const form = button.closest("form");
      if (form instanceof HTMLFormElement) {
        const requiredName = button.getAttribute("data-plugin-install-require") || "";
        if (requiredName) {
          const requiredInput = form.querySelector(`[name="${requiredName}"]`);
          if (requiredInput instanceof HTMLInputElement && !requiredInput.value.trim() && requiredInput.required) {
            requiredInput.focus();
            if (typeof requiredInput.reportValidity === "function") {
              requiredInput.reportValidity();
            }
            return;
          }
        }
        capturePluginInstallFormDraft(pluginId, form);
      }
      setPluginInstallStep(pluginId, nextStep);
      renderShell();
    });
  });

  document.querySelectorAll("[data-plugin-install-advance-after]").forEach((button) => {
    button.addEventListener("click", () => {
      const pluginId = button.getAttribute("data-plugin-install-advance-after") || "";
      const nextStep = Number(button.getAttribute("data-plugin-install-next-step"));
      if (!pluginId || !Number.isFinite(nextStep)) return;
      window.setTimeout(() => {
        setPluginInstallStep(pluginId, nextStep);
        renderShell();
      }, 1200);
    });
  });
}

