function bindKnowledgeBaseEvents() {
  bindKnowledgeBaseNoteOpenEvents();
  bindSystemToastEvents();

  bindKnowledgeBaseSearchInputEvents();

  document.querySelector("#edit-knowledge-base-note")?.addEventListener("click", () => {
    startKnowledgeBaseNoteEdit();
  });

  document.querySelector("#cancel-knowledge-base-edit")?.addEventListener("click", () => {
    cancelKnowledgeBaseNoteEdit();
  });

  document.querySelector("#save-knowledge-base-note")?.addEventListener("click", async () => {
    clearQuestHintFor("knowledge-base", { render: false });
    await saveKnowledgeBaseNote();
  });

  document.querySelector("#knowledge-base-note-editor")?.addEventListener("input", (event) => {
    const textarea = event.currentTarget;
    if (!(textarea instanceof HTMLTextAreaElement)) {
      return;
    }

    state.knowledgeBase.selectedNoteDraft = textarea.value;
    refreshKnowledgeBaseEditStateUi();
  });

  const refreshButton = document.querySelector("#refresh-knowledge-base");
  if (refreshButton instanceof HTMLButtonElement) {
    refreshButton.onclick = async () => {
      await loadKnowledgeBaseIndex();
      await ensureKnowledgeBaseSelectionLoaded({ force: true });
      updateRoute({ view: "knowledge-base", notePath: state.knowledgeBase.selectedNotePath });
      renderShell();
    };
  }

  document.querySelectorAll("[data-kb-graph-toggle]").forEach((button) => {
    if (!(button instanceof HTMLElement)) return;
    button.addEventListener("click", () => {
      const action = button.dataset.kbGraphToggle;
      setKnowledgeBaseGraphCollapsed(action !== "show");
    });
  });

  document.querySelectorAll("[data-kb-mobile-back]").forEach((button) => {
    if (!(button instanceof HTMLElement)) return;
    button.addEventListener("click", () => {
      clearKnowledgeBaseNoteSelection();
    });
  });

  bindPaperSinceLastUpdateEvents();
}

function bindPaperSinceLastUpdateEvents() {
  document.querySelectorAll("[data-mark-paper-read]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement)) return;
    if (button.dataset.paperReadBound === "true") return;
    button.dataset.paperReadBound = "true";
    button.addEventListener("click", () => {
      const paperPath = button.dataset.paperPath || state.knowledgeBase.selectedNotePath || "";
      const banner = button.closest(".paper-since-banner");
      const firstBullet = banner?.querySelector(".paper-since-list .paper-since-bullet");
      const raw = firstBullet instanceof HTMLElement ? firstBullet.dataset.paperBullet || "" : "";
      if (paperPath && raw) {
        writePaperLastSeenBullet(paperPath, raw);
      }
      renderShell();
    });
  });

  document.querySelectorAll("[data-paper-spawn-agent]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement)) return;
    if (button.dataset.paperSpawnBound === "true") return;
    button.dataset.paperSpawnBound = "true";
    button.addEventListener("click", async () => {
      const cwd = button.dataset.projectCwd || "";
      if (!cwd) {
        window.alert("library path is not configured; cannot spawn agent in project folder");
        return;
      }
      button.disabled = true;
      const original = button.textContent;
      button.textContent = "spawning…";
      try {
        await createSessionInFolder(cwd, {});
      } catch (error) {
        window.alert(error?.message || "failed to spawn agent");
        button.textContent = original;
        button.disabled = false;
      }
    });
  });
}

function refreshKnowledgeBaseUi() {
  if (state.currentView !== "knowledge-base") {
    teardownKnowledgeBaseGraphInteractions();
    return;
  }

  bindKnowledgeBaseEvents();

  const graphElement = document.querySelector("#knowledge-base-graph");
  if (state.knowledgeBase.graphLayout.refs?.svg === graphElement) {
    if (!state.knowledgeBase.graphLayout.cameraInitialized) {
      fitKnowledgeBaseGraphCamera();
    } else {
      syncKnowledgeBaseGraphDom();
    }
    applyPendingKnowledgeBaseGraphFocus();
    return;
  }

  bindKnowledgeBaseGraphInteractions();
}

function bindFileTreeEvents() {
  const filesTree = document.querySelector("#files-tree");
  if (!(filesTree instanceof HTMLElement) || filesTree.dataset.fileTreeBound === "true") {
    return;
  }

  filesTree.dataset.fileTreeBound = "true";
  filesTree.addEventListener("pointerdown", (event) => {
    const target = event.target;
    if (!(target instanceof Element)) {
      return;
    }

    const fileControl = target.closest("[data-file-toggle], [data-file-open]");
    if (!(fileControl instanceof HTMLElement) || !filesTree.contains(fileControl)) {
      return;
    }

    if (document.querySelector("#terminal-mount")?.contains(document.activeElement)) {
      // Sidebar tree redraws should not make xterm blur/redraw while an agent is running.
      event.preventDefault();
    }
  });
  filesTree.addEventListener("click", async (event) => {
    const target = event.target;
    if (!(target instanceof Element)) {
      return;
    }

    const toggleButton = target.closest("[data-file-toggle]");
    if (toggleButton instanceof HTMLElement && filesTree.contains(toggleButton)) {
      event.preventDefault();
      event.stopPropagation();
      const relativePath = normalizeFileTreePath(toggleButton.getAttribute("data-file-toggle"));

      if (!relativePath) {
        return;
      }

      if (state.fileTreeExpanded.has(relativePath)) {
        state.fileTreeExpanded.delete(relativePath);
        refreshFileTreeUi();
        return;
      }

      state.fileTreeExpanded.add(relativePath);
      refreshFileTreeUi();
      void loadFileTree(relativePath);
      return;
    }

    const openButton = target.closest("[data-file-open]");
    if (!(openButton instanceof HTMLElement) || !filesTree.contains(openButton)) {
      return;
    }

    event.preventDefault();
    event.stopPropagation();
    const relativePath = normalizeFileTreePath(openButton.getAttribute("data-file-open"));
    const openMode = openButton.getAttribute("data-file-open-mode");

    if (!relativePath) {
      return;
    }

    const openedInKnowledgeBase = await selectKnowledgeBaseNoteForWorkspaceFile(relativePath, {
      openInKnowledgeBase: state.currentView === "knowledge-base",
    });
    if (openedInKnowledgeBase && state.currentView === "knowledge-base") {
      return;
    }

    void openWorkspaceFilePreview(relativePath, { mode: openMode });
  });

  filesTree.addEventListener("contextmenu", (event) => {
    const target = event.target;
    if (!(target instanceof Element)) {
      return;
    }

    const toggleButton = target.closest("[data-file-toggle]");
    if (toggleButton instanceof HTMLElement && filesTree.contains(toggleButton)) {
      const relativePath = normalizeFileTreePath(toggleButton.getAttribute("data-file-toggle"));
      if (!relativePath) return;
      event.preventDefault();
      event.stopPropagation();
      openGlobalFileContextMenu({ relativePath, isDirectory: true }, event.clientX, event.clientY);
      return;
    }

    const openButton = target.closest("[data-file-open]");
    if (openButton instanceof HTMLElement && filesTree.contains(openButton)) {
      const relativePath = normalizeFileTreePath(openButton.getAttribute("data-file-open"));
      const mode = openButton.getAttribute("data-file-open-mode") || "text";
      if (!relativePath) return;
      event.preventDefault();
      event.stopPropagation();
      openGlobalFileContextMenu({ relativePath, isDirectory: false, mode }, event.clientX, event.clientY);
    }
  });
}

function refreshFileTreeUi() {
  const filesRootInput = document.querySelector("#files-root-input");
  const filesTree = document.querySelector("#files-tree");
  const autoFilesRootButton = document.querySelector("#auto-files-root");
  const nextRoot = state.filesRoot || state.defaultCwd || "";
  const filesTreeScrollSnapshot = captureScrollSnapshot("#files-tree");

  if (filesRootInput instanceof HTMLInputElement) {
    if (document.activeElement !== filesRootInput) {
      filesRootInput.value = nextRoot;
    }

    filesRootInput.setAttribute("title", nextRoot);
    filesRootInput.placeholder = state.defaultCwd || "workspace path";
  }

  if (autoFilesRootButton instanceof HTMLButtonElement) {
    autoFilesRootButton.disabled = !state.filesRootOverride;
  }

  if (!filesTree) {
    return;
  }

  const previousRenderedRoot = filesTree instanceof HTMLElement ? filesTree.dataset.filesRoot || "" : "";
  filesTree.innerHTML = renderFileTree();
  if (filesTree instanceof HTMLElement) {
    filesTree.dataset.filesRoot = state.filesRoot || "";
  }
  if (previousRenderedRoot === (state.filesRoot || "")) {
    restoreScrollSnapshot("#files-tree", filesTreeScrollSnapshot);
  }
  bindFileTreeEvents();
}

function refreshOpenFileUi() {
  const previewPane = document.querySelector("#file-preview-pane");
  if (previewPane) {
    const workspaceSplit = document.querySelector("#workspace-split");
    workspaceSplit?.classList.toggle("has-file-preview", state.openFileTabs.length > 0);
    previewPane.outerHTML = renderFilePreviewPane();
    bindFileEditorEvents();
    refreshLayoutUi();
    fitTerminalSoon();
    return;
  }

  const fileEditor = document.querySelector("#file-editor");
  if (!fileEditor) {
    return;
  }

  fileEditor.innerHTML = renderOpenFilePanel();
  bindFileEditorEvents();
}

function syncOpenFileEditorStateUi() {
  syncOpenFileStateFromTab();
  const status = document.querySelector("#open-file-status");
  const saveButton = document.querySelector("#save-open-file");
  const previewButton = document.querySelector("#preview-open-file");
  const activeTab = getActiveOpenFileTab();

  if (status) {
    status.textContent = activeTab?.saving
      ? "saving changes..."
      : isOpenFileDirty(activeTab)
        ? "unsaved changes"
        : "saved";
  }

  if (saveButton instanceof HTMLButtonElement) {
    const dirty = isOpenFileDirty(activeTab);
    saveButton.disabled = !dirty || Boolean(activeTab?.saving);
    saveButton.textContent = activeTab?.saving ? "saving..." : dirty ? "save" : "saved";
    saveButton.classList.toggle("primary-button", dirty);
    saveButton.classList.toggle("ghost-button", !dirty);
  }

  if (previewButton instanceof HTMLButtonElement) {
    previewButton.disabled = isOpenFileDirty(activeTab) || Boolean(activeTab?.saving);
  }
}

function syncOpenImageTransformDom(tab = getActiveOpenFileTab()) {
  if (!tab || tab.status !== "image") {
    return;
  }

  const preview = document.querySelector("[data-image-preview]");
  const image = preview?.querySelector("img");
  const label = document.querySelector(".file-image-zoom-label");
  const zoom = getOpenImageZoom(tab);
  const offset = getOpenImageOffset(tab);

  if (image instanceof HTMLElement) {
    image.style.setProperty("--image-zoom", String(zoom));
    image.style.setProperty("--image-x", `${offset.x}px`);
    image.style.setProperty("--image-y", `${offset.y}px`);
  }

  if (label) {
    label.textContent = getOpenImageZoomLabel(tab);
  }

  document.querySelectorAll("[data-image-zoom]").forEach((button) => {
    if (!(button instanceof HTMLButtonElement)) {
      return;
    }

    const action = button.getAttribute("data-image-zoom");
    button.disabled =
      (action === "out" && zoom <= FILE_IMAGE_MIN_ZOOM + 0.001) ||
      (action === "in" && zoom >= FILE_IMAGE_MAX_ZOOM - 0.001);
  });
}

function updateOpenImageTransform(tab, { zoom, offsetX, offsetY } = {}) {
  if (!tab || tab.status !== "image") {
    return;
  }

  const nextZoom = getOpenImageZoom({ imageZoom: zoom ?? tab.imageZoom });
  const shouldResetPan = nextZoom <= FILE_IMAGE_MIN_ZOOM + 0.001;
  setOpenImageTransform(tab, {
    zoom: nextZoom,
    offsetX: shouldResetPan ? 0 : offsetX ?? tab.imageOffsetX,
    offsetY: shouldResetPan ? 0 : offsetY ?? tab.imageOffsetY,
  });
  syncOpenFileStateFromTab(tab);
  syncOpenImageTransformDom(tab);
}

function zoomOpenImage(tab, nextZoom, anchorClientPoint = null) {
  if (!tab || tab.status !== "image") {
    return;
  }

  const preview = document.querySelector("[data-image-preview]");
  const currentZoom = getOpenImageZoom(tab);
  const zoom = getOpenImageZoom({ imageZoom: nextZoom });
  const currentOffset = getOpenImageOffset(tab);

  if (
    zoom <= FILE_IMAGE_MIN_ZOOM + 0.001 ||
    !(preview instanceof HTMLElement) ||
    !anchorClientPoint
  ) {
    updateOpenImageTransform(tab, {
      zoom,
      offsetX: zoom <= FILE_IMAGE_MIN_ZOOM + 0.001 ? 0 : currentOffset.x,
      offsetY: zoom <= FILE_IMAGE_MIN_ZOOM + 0.001 ? 0 : currentOffset.y,
    });
    return;
  }

  const rect = preview.getBoundingClientRect();
  const anchorX = anchorClientPoint.clientX - rect.left - rect.width / 2;
  const anchorY = anchorClientPoint.clientY - rect.top - rect.height / 2;
  const ratio = zoom / currentZoom;
  const nextOffsetX = anchorX - (anchorX - currentOffset.x) * ratio;
  const nextOffsetY = anchorY - (anchorY - currentOffset.y) * ratio;
  updateOpenImageTransform(tab, { zoom, offsetX: nextOffsetX, offsetY: nextOffsetY });
}

function bindImagePreviewEvents() {
  const preview = document.querySelector("[data-image-preview]");
  if (!(preview instanceof HTMLElement) || preview.dataset.bound === "true") {
    return;
  }

  preview.dataset.bound = "true";
  syncOpenImageTransformDom();
  preview.addEventListener(
    "wheel",
    (event) => {
      const activeTab = getActiveOpenFileTab();
      if (!activeTab || activeTab.status !== "image") {
        return;
      }

      event.preventDefault();
      const direction = event.deltaY > 0 ? -1 : 1;
      const multiplier = direction > 0 ? 1.12 : 1 / 1.12;
      zoomOpenImage(activeTab, getOpenImageZoom(activeTab) * multiplier, {
        clientX: event.clientX,
        clientY: event.clientY,
      });
    },
    { passive: false },
  );

  preview.addEventListener("pointerdown", (event) => {
    const activeTab = getActiveOpenFileTab();
    if (!activeTab || activeTab.status !== "image" || event.button !== 0) {
      return;
    }

    event.preventDefault();
    const startOffset = getOpenImageOffset(activeTab);
    const dragState = {
      pointerId: event.pointerId,
      clientX: event.clientX,
      clientY: event.clientY,
      offsetX: startOffset.x,
      offsetY: startOffset.y,
    };
    preview.dataset.dragging = JSON.stringify(dragState);
    preview.classList.add("is-panning");
    preview.setPointerCapture?.(event.pointerId);
  });

  preview.addEventListener("pointermove", (event) => {
    const activeTab = getActiveOpenFileTab();
    if (!activeTab || activeTab.status !== "image" || !preview.dataset.dragging) {
      return;
    }

    let dragState;
    try {
      dragState = JSON.parse(preview.dataset.dragging);
    } catch {
      dragState = null;
    }

    if (!dragState || dragState.pointerId !== event.pointerId) {
      return;
    }

    updateOpenImageTransform(activeTab, {
      zoom: getOpenImageZoom(activeTab),
      offsetX: dragState.offsetX + event.clientX - dragState.clientX,
      offsetY: dragState.offsetY + event.clientY - dragState.clientY,
    });
  });

  const endPan = (event) => {
    if (preview.dataset.dragging) {
      preview.releasePointerCapture?.(event.pointerId);
    }
    preview.dataset.dragging = "";
    preview.classList.remove("is-panning");
  };

  preview.addEventListener("pointerup", endPan);
  preview.addEventListener("pointercancel", endPan);
  preview.addEventListener("lostpointercapture", () => {
    preview.dataset.dragging = "";
    preview.classList.remove("is-panning");
  });
}

let openFileTabDragState = null;
let openFileTabClickSuppressPath = "";
let openFileTabClickSuppressUntil = 0;

function getOpenFileTabPathFromElement(element) {
  if (!(element instanceof HTMLElement)) {
    return "";
  }

  return normalizeFileTreePath(element.getAttribute("data-file-tab-item"));
}

function clearOpenFileTabDropMarkers() {
  document.querySelectorAll(".file-preview-tab.is-drop-before, .file-preview-tab.is-drop-after").forEach((tab) => {
    tab.classList.remove("is-drop-before", "is-drop-after");
  });
}

function setOpenFileTabDropMarker(target) {
  clearOpenFileTabDropMarkers();
  if (!target?.path) {
    return;
  }

  document.querySelectorAll("[data-file-tab-item]").forEach((tab) => {
    if (!(tab instanceof HTMLElement) || getOpenFileTabPathFromElement(tab) !== target.path) {
      return;
    }

    tab.classList.add(target.position === "after" ? "is-drop-after" : "is-drop-before");
  });
}

function getOpenFileTabDropTarget(clientX, clientY, draggedPath) {
  const strip = document.querySelector(".file-preview-tab-strip");
  if (!(strip instanceof HTMLElement)) {
    return null;
  }

  const draggedTabPath = normalizeFileTreePath(draggedPath);
  const items = Array.from(strip.querySelectorAll("[data-file-tab-item]")).filter((item) => {
    const path = getOpenFileTabPathFromElement(item);
    return item instanceof HTMLElement && path && path !== draggedTabPath;
  });
  if (!items.length) {
    return null;
  }

  const hoveredElement = document.elementFromPoint(clientX, clientY);
  const hoveredTab = hoveredElement instanceof Element ? hoveredElement.closest("[data-file-tab-item]") : null;
  if (hoveredTab instanceof HTMLElement && strip.contains(hoveredTab)) {
    const path = getOpenFileTabPathFromElement(hoveredTab);
    if (path && path !== draggedTabPath) {
      const rect = hoveredTab.getBoundingClientRect();
      return {
        path,
        position: clientX > rect.left + rect.width / 2 ? "after" : "before",
      };
    }
  }

  for (const item of items) {
    if (!(item instanceof HTMLElement)) {
      continue;
    }

    const rect = item.getBoundingClientRect();
    if (clientX < rect.left + rect.width / 2) {
      return {
        path: getOpenFileTabPathFromElement(item),
        position: "before",
      };
    }
  }

  const lastItem = items[items.length - 1];
  return {
    path: getOpenFileTabPathFromElement(lastItem),
    position: "after",
  };
}

function suppressOpenFileTabClick(relativePath) {
  openFileTabClickSuppressPath = normalizeFileTreePath(relativePath);
  openFileTabClickSuppressUntil = getUiNow() + 350;
}

function shouldSuppressOpenFileTabClick(relativePath) {
  return (
    openFileTabClickSuppressPath === normalizeFileTreePath(relativePath) &&
    getUiNow() < openFileTabClickSuppressUntil
  );
}

function finishOpenFileTabReorder(event, { cancel = false } = {}) {
  const dragState = openFileTabDragState;
  if (!dragState || dragState.pointerId !== event.pointerId) {
    return;
  }

  openFileTabDragState = null;
  dragState.controller?.abort();
  dragState.item?.classList.remove("is-dragging");
  dragState.strip?.classList.remove("is-reordering");
  document.body.classList.remove("is-reordering-file-tabs");
  clearOpenFileTabDropMarkers();

  try {
    dragState.item?.releasePointerCapture?.(event.pointerId);
  } catch {
    // Pointer capture release is best-effort; the drag has already ended.
  }

  if (!dragState.dragging) {
    return;
  }

  suppressOpenFileTabClick(dragState.path);
  event.preventDefault();

  if (cancel) {
    return;
  }

  const target =
    dragState.target ||
    getOpenFileTabDropTarget(event.clientX, event.clientY, dragState.path);
  if (target?.path) {
    reorderOpenFileTab(dragState.path, target.path, target.position);
  }
}

function beginOpenFileTabReorder(event) {
  if (event.button !== undefined && event.button !== 0) {
    return;
  }

  const target = event.target;
  if (!(target instanceof Element) || target.closest("[data-close-file-tab]")) {
    return;
  }

  const item = target.closest("[data-file-tab-item]");
  const strip = event.currentTarget;
  if (!(item instanceof HTMLElement) || !(strip instanceof HTMLElement) || !strip.contains(item)) {
    return;
  }

  const path = getOpenFileTabPathFromElement(item);
  if (!path || state.openFileTabs.length < 2) {
    return;
  }

  const controller = new AbortController();
  openFileTabDragState = {
    captured: false,
    controller,
    dragging: false,
    item,
    path,
    pointerId: event.pointerId,
    startClientX: event.clientX,
    startClientY: event.clientY,
    strip,
    target: null,
  };

  const onPointerMove = (moveEvent) => {
    const dragState = openFileTabDragState;
    if (!dragState || dragState.pointerId !== moveEvent.pointerId) {
      return;
    }

    const deltaX = moveEvent.clientX - dragState.startClientX;
    const deltaY = moveEvent.clientY - dragState.startClientY;
    if (!dragState.dragging && Math.hypot(deltaX, deltaY) < FILE_PREVIEW_TAB_REORDER_DRAG_SLOP_PX) {
      return;
    }

    if (!dragState.dragging) {
      dragState.dragging = true;
      dragState.item.classList.add("is-dragging");
      dragState.strip.classList.add("is-reordering");
      document.body.classList.add("is-reordering-file-tabs");
      try {
        dragState.item.setPointerCapture(moveEvent.pointerId);
        dragState.captured = true;
      } catch {
        // Window listeners keep the drag alive if capture is unavailable.
      }
    }

    dragState.target = getOpenFileTabDropTarget(moveEvent.clientX, moveEvent.clientY, dragState.path);
    setOpenFileTabDropMarker(dragState.target);
    moveEvent.preventDefault();
  };

  const onPointerUp = (upEvent) => finishOpenFileTabReorder(upEvent);
  const onPointerCancel = (cancelEvent) => finishOpenFileTabReorder(cancelEvent, { cancel: true });

  window.addEventListener("pointermove", onPointerMove, { signal: controller.signal });
  window.addEventListener("pointerup", onPointerUp, { signal: controller.signal });
  window.addEventListener("pointercancel", onPointerCancel, { signal: controller.signal });

}

function bindOpenFileTabReorderEvents() {
  const strip = document.querySelector(".file-preview-tab-strip");
  if (!(strip instanceof HTMLElement) || strip.dataset.reorderBound === "true") {
    return;
  }

  strip.dataset.reorderBound = "true";
  strip.addEventListener("pointerdown", beginOpenFileTabReorder);
}

let workspaceTabDragState = null;
let workspaceTabClickSuppressKey = "";
let workspaceTabClickSuppressUntil = 0;
let workspaceGroupResizeState = null;

function getWorkspaceTabKeyFromElement(element) {
  if (!(element instanceof HTMLElement)) {
    return "";
  }

  return String(element.getAttribute("data-workspace-tab-item") || "");
}

function clearWorkspaceTabDropMarkers() {
  document
    .querySelectorAll(
      ".workspace-tab.is-drop-before, .workspace-tab.is-drop-after, .workspace-group.is-split-before, .workspace-group.is-split-after",
    )
    .forEach((tab) => {
      tab.classList.remove("is-drop-before", "is-drop-after", "is-split-before", "is-split-after");
    });
}

function setWorkspaceTabDropMarker(target) {
  clearWorkspaceTabDropMarkers();
  if (!target) {
    return;
  }

  if (target.type === "split" && target.groupId) {
    document.querySelectorAll("[data-workspace-group]").forEach((group) => {
      if (!(group instanceof HTMLElement) || group.dataset.workspaceGroup !== target.groupId) {
        return;
      }

      group.classList.add(target.side === "before" ? "is-split-before" : "is-split-after");
    });
    return;
  }

  document.querySelectorAll("[data-workspace-tab-item]").forEach((tab) => {
    if (!(tab instanceof HTMLElement) || getWorkspaceTabKeyFromElement(tab) !== target.key) {
      return;
    }

    tab.classList.add(target.position === "after" ? "is-drop-after" : "is-drop-before");
  });
}

function getWorkspaceTabDropTarget(clientX, clientY, draggedKey) {
  const hoveredElement = document.elementFromPoint(clientX, clientY);
  const hoveredTab = hoveredElement instanceof Element ? hoveredElement.closest("[data-workspace-tab-item]") : null;
  if (hoveredTab instanceof HTMLElement) {
    const key = getWorkspaceTabKeyFromElement(hoveredTab);
    if (key && key !== draggedKey) {
      const rect = hoveredTab.getBoundingClientRect();
      return {
        type: "tab",
        key,
        position: clientX > rect.left + rect.width / 2 ? "after" : "before",
      };
    }
  }

  const hoveredContent = hoveredElement instanceof Element ? hoveredElement.closest("[data-workspace-group-content]") : null;
  if (hoveredContent instanceof HTMLElement) {
    const groupId = normalizeWorkspaceGroupId(hoveredContent.dataset.workspaceGroupContent);
    if (groupId) {
      const rect = hoveredContent.getBoundingClientRect();
      return {
        type: "split",
        groupId,
        side: clientX < rect.left + rect.width / 2 ? "before" : "after",
      };
    }
  }

  const hoveredStrip = hoveredElement instanceof Element ? hoveredElement.closest("[data-workspace-tab-strip]") : null;
  if (hoveredStrip instanceof HTMLElement) {
    const groupId = normalizeWorkspaceGroupId(hoveredStrip.dataset.workspaceTabStrip);
    const group = getWorkspaceGroupById(groupId);
    const tabKey = group?.tabs.filter((key) => key !== draggedKey).at(-1) || "";
    if (tabKey) {
      return { type: "tab", key: tabKey, position: "after" };
    }
  }

  const items = Array.from(document.querySelectorAll("[data-workspace-tab-item]")).filter((item) => {
    const key = getWorkspaceTabKeyFromElement(item);
    return item instanceof HTMLElement && key && key !== draggedKey;
  });
  for (const item of items) {
    if (!(item instanceof HTMLElement)) {
      continue;
    }

    const rect = item.getBoundingClientRect();
    if (clientX < rect.left + rect.width / 2) {
      return {
        type: "tab",
        key: getWorkspaceTabKeyFromElement(item),
        position: "before",
      };
    }
  }

  const lastItem = items[items.length - 1];
  if (!(lastItem instanceof HTMLElement)) {
    return null;
  }
  return {
    type: "tab",
    key: getWorkspaceTabKeyFromElement(lastItem),
    position: "after",
  };
}

function suppressWorkspaceTabClick(key) {
  workspaceTabClickSuppressKey = String(key || "");
  workspaceTabClickSuppressUntil = getUiNow() + 350;
}

function shouldSuppressWorkspaceTabClick(key) {
  return workspaceTabClickSuppressKey === String(key || "") && getUiNow() < workspaceTabClickSuppressUntil;
}

function finishWorkspaceTabReorder(event, { cancel = false } = {}) {
  const dragState = workspaceTabDragState;
  if (!dragState || dragState.pointerId !== event.pointerId) {
    return;
  }

  workspaceTabDragState = null;
  dragState.controller?.abort();
  dragState.item?.classList.remove("is-dragging");
  dragState.strip?.classList.remove("is-reordering");
  document.body.classList.remove("is-reordering-workspace-tabs");
  clearWorkspaceTabDropMarkers();

  try {
    dragState.item?.releasePointerCapture?.(event.pointerId);
  } catch {
    // Pointer capture release is best-effort; the drag has already ended.
  }

  if (!dragState.dragging) {
    return;
  }

  suppressWorkspaceTabClick(dragState.key);
  event.preventDefault();

  if (cancel) {
    return;
  }

  const target =
    dragState.target ||
    getWorkspaceTabDropTarget(event.clientX, event.clientY, dragState.key);
  if (target?.type === "split") {
    splitWorkspaceTab(dragState.key, target.groupId, target.side);
  } else if (target?.key) {
    reorderWorkspaceTab(dragState.key, target.key, target.position);
  }
}

function beginWorkspaceTabReorder(event) {
  if (event.button !== undefined && event.button !== 0) {
    return;
  }

  const target = event.target;
  if (!(target instanceof Element) || target.closest("[data-close-workspace-tab]")) {
    return;
  }

  const item = target.closest("[data-workspace-tab-item]");
  const strip = event.currentTarget;
  if (!(item instanceof HTMLElement) || !(strip instanceof HTMLElement) || !strip.contains(item)) {
    return;
  }

  const key = getWorkspaceTabKeyFromElement(item);
  if (!key || state.workspaceTabs.length < 2) {
    return;
  }

  const controller = new AbortController();
  workspaceTabDragState = {
    captured: false,
    controller,
    dragging: false,
    item,
    key,
    pointerId: event.pointerId,
    startClientX: event.clientX,
    startClientY: event.clientY,
    strip,
    target: null,
  };

  const onPointerMove = (moveEvent) => {
    const dragState = workspaceTabDragState;
    if (!dragState || dragState.pointerId !== moveEvent.pointerId) {
      return;
    }

    const deltaX = moveEvent.clientX - dragState.startClientX;
    const deltaY = moveEvent.clientY - dragState.startClientY;
    if (!dragState.dragging && Math.hypot(deltaX, deltaY) < WORKSPACE_TAB_REORDER_DRAG_SLOP_PX) {
      return;
    }

    if (!dragState.dragging) {
      dragState.dragging = true;
      dragState.item.classList.add("is-dragging");
      dragState.strip.classList.add("is-reordering");
      document.body.classList.add("is-reordering-workspace-tabs");
      try {
        dragState.item.setPointerCapture(moveEvent.pointerId);
        dragState.captured = true;
      } catch {
        // Window listeners keep the drag alive if capture is unavailable.
      }
    }

    dragState.target = getWorkspaceTabDropTarget(moveEvent.clientX, moveEvent.clientY, dragState.key);
    setWorkspaceTabDropMarker(dragState.target);
    moveEvent.preventDefault();
  };

  const onPointerUp = (upEvent) => finishWorkspaceTabReorder(upEvent);
  const onPointerCancel = (cancelEvent) => finishWorkspaceTabReorder(cancelEvent, { cancel: true });

  window.addEventListener("pointermove", onPointerMove, { signal: controller.signal });
  window.addEventListener("pointerup", onPointerUp, { signal: controller.signal });
  window.addEventListener("pointercancel", onPointerCancel, { signal: controller.signal });

}

function setWorkspaceGroupActiveTab(key, groupId = "") {
  const normalizedKey = String(key || "");
  if (!normalizedKey) {
    return false;
  }

  const groups = normalizeWorkspaceGroups(state.workspaceGroups);
  const group =
    groups.find((entry) => entry.id === normalizeWorkspaceGroupId(groupId) && entry.tabs.includes(normalizedKey)) ||
    groups.find((entry) => entry.tabs.includes(normalizedKey));
  if (!group) {
    return false;
  }

  group.activeKey = normalizedKey;
  state.activeWorkspaceGroupId = group.id;
  state.workspaceGroups = groups;
  saveWorkspaceGroupsState();
  return true;
}

async function activateWorkspaceTab(key, { groupId = "" } = {}) {
  const tab = normalizeWorkspaceTabs(state.workspaceTabs).find((entry) => entry.key === String(key || ""));
  if (!tab) {
    return;
  }

  setWorkspaceGroupActiveTab(tab.key, groupId);

  if (tab.type === "session") {
    const session = getSessionWorkspaceTab(tab.sessionId);
    if (!session) {
      closeWorkspaceTab(tab.key, groupId);
      return;
    }

    state.activeSessionId = tab.sessionId;
    expandSessionProject(session.cwd);
    setCurrentView("shell");
    markSessionRead(tab.sessionId, { refresh: false });
    closeMobileSidebar();
    renderShell();
    connectToSession(tab.sessionId);
    return;
  }

  if (tab.type === "browser-use") {
    await loadBrowserUseSession(tab.browserUseSessionId);
    return;
  }

  await openMainView(tab.view);
}

function closeWorkspaceTab(key, groupId = "") {
  const normalizedKey = String(key || "");
  const tabIndex = state.workspaceTabs.findIndex((tab) => tab.key === normalizedKey);
  if (tabIndex < 0) {
    return;
  }

  const group = getWorkspaceGroupById(groupId) || getWorkspaceGroupContainingTab(normalizedKey);
  const groupTabIndex = group ? group.tabs.indexOf(normalizedKey) : -1;
  const closingActive = normalizedKey === getActiveWorkspaceTabKey() && (!group || group.id === state.activeWorkspaceGroupId);
  const fallbackKey =
    group && groupTabIndex >= 0
      ? group.tabs[groupTabIndex + 1] || group.tabs[groupTabIndex - 1] || ""
      : "";
  state.workspaceTabs.splice(tabIndex, 1);
  removeWorkspaceTabFromGroups(normalizedKey);
  saveWorkspaceTabsState();
  saveWorkspaceGroupsState();

  if (state.workspaceTabs.length === 0) {
    state.workspaceEmpty = true;
  }

  if (closingActive) {
    const nextTab =
      (fallbackKey ? getWorkspaceTabByKey(fallbackKey) : null) ||
      state.workspaceTabs[Math.min(tabIndex, state.workspaceTabs.length - 1)] ||
      state.workspaceTabs[tabIndex - 1] ||
      null;
    if (nextTab) {
      void activateWorkspaceTab(nextTab.key, { groupId: group?.id || "" });
      return;
    }

    renderShell();
    if (state.currentView === "shell" && state.activeSessionId) {
      connectToSession(state.activeSessionId);
    }
    return;
  }

  renderShell();
}

function applyWorkspaceGroupGridStyle() {
  const groups = normalizeWorkspaceGroups(state.workspaceGroups);
  const grid = document.querySelector(".workspace-groups");
  if (grid instanceof HTMLElement) {
    grid.setAttribute("style", renderWorkspaceGroupsGridStyle(groups));
  }
}

function beginWorkspaceGroupResize(event) {
  if (event.button !== undefined && event.button !== 0) {
    return;
  }

  const handle = event.currentTarget;
  if (!(handle instanceof HTMLElement)) {
    return;
  }

  const leftGroupId = normalizeWorkspaceGroupId(handle.dataset.leftWorkspaceGroup);
  const rightGroupId = normalizeWorkspaceGroupId(handle.dataset.rightWorkspaceGroup);
  const groups = normalizeWorkspaceGroups(state.workspaceGroups);
  const leftGroup = groups.find((group) => group.id === leftGroupId);
  const rightGroup = groups.find((group) => group.id === rightGroupId);
  const grid = document.querySelector(".workspace-groups");
  if (!leftGroup || !rightGroup || !(grid instanceof HTMLElement)) {
    return;
  }

  const controller = new AbortController();
  workspaceGroupResizeState = {
    controller,
    leftGroupId,
    rightGroupId,
    pointerId: event.pointerId,
    startClientX: event.clientX,
    startLeftWidth: leftGroup.width || 1,
    startRightWidth: rightGroup.width || 1,
    containerWidth: Math.max(1, grid.getBoundingClientRect().width),
  };
  handle.classList.add("is-dragging");
  document.body.classList.add("is-resizing-workspace-groups");

  const onPointerMove = (moveEvent) => {
    const dragState = workspaceGroupResizeState;
    if (!dragState || dragState.pointerId !== moveEvent.pointerId) {
      return;
    }

    const nextGroups = normalizeWorkspaceGroups(state.workspaceGroups);
    const nextLeft = nextGroups.find((group) => group.id === dragState.leftGroupId);
    const nextRight = nextGroups.find((group) => group.id === dragState.rightGroupId);
    if (!nextLeft || !nextRight) {
      return;
    }

    const total = dragState.startLeftWidth + dragState.startRightWidth;
    const delta = ((moveEvent.clientX - dragState.startClientX) / dragState.containerWidth) * total;
    const nextLeftWidth = clamp(dragState.startLeftWidth + delta, WORKSPACE_GROUP_MIN_FRACTION, total - WORKSPACE_GROUP_MIN_FRACTION);
    nextLeft.width = nextLeftWidth;
    nextRight.width = total - nextLeftWidth;
    state.workspaceGroups = nextGroups;
    applyWorkspaceGroupGridStyle();
    moveEvent.preventDefault();
  };

  const onPointerEnd = (endEvent) => {
    const dragState = workspaceGroupResizeState;
    if (!dragState || dragState.pointerId !== endEvent.pointerId) {
      return;
    }

    workspaceGroupResizeState = null;
    controller.abort();
    handle.classList.remove("is-dragging");
    document.body.classList.remove("is-resizing-workspace-groups");
    saveWorkspaceGroupsState();
  };

  window.addEventListener("pointermove", onPointerMove, { signal: controller.signal });
  window.addEventListener("pointerup", onPointerEnd, { signal: controller.signal });
  window.addEventListener("pointercancel", onPointerEnd, { signal: controller.signal });
  event.preventDefault();
}

function bindWorkspaceTabEvents() {
  document.querySelectorAll("[data-workspace-tab-strip]").forEach((strip) => {
    if (strip instanceof HTMLElement && strip.dataset.workspaceTabsBound !== "true") {
      strip.dataset.workspaceTabsBound = "true";
      strip.addEventListener("pointerdown", beginWorkspaceTabReorder);
    }
  });

  document.querySelectorAll("[data-workspace-tab]").forEach((button) => {
    button.addEventListener("click", (event) => {
      const key = button.getAttribute("data-workspace-tab") || "";
      const groupId = button.getAttribute("data-workspace-tab-group") || "";
      if (shouldSuppressWorkspaceTabClick(key)) {
        event.preventDefault();
        event.stopPropagation();
        return;
      }

      void activateWorkspaceTab(key, { groupId });
    });

    button.addEventListener("keydown", (event) => {
      if (!event.altKey || (event.key !== "ArrowLeft" && event.key !== "ArrowRight")) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      const direction =
        event.key === "ArrowLeft"
          ? -WORKSPACE_TAB_REORDER_KEYBOARD_STEP
          : WORKSPACE_TAB_REORDER_KEYBOARD_STEP;
      moveWorkspaceTabByOffset(
        button.getAttribute("data-workspace-tab"),
        direction,
        button.getAttribute("data-workspace-tab-group"),
      );
    });
  });

  document.querySelectorAll("[data-close-workspace-tab]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      closeWorkspaceTab(
        button.getAttribute("data-close-workspace-tab") || "",
        button.getAttribute("data-close-workspace-tab-group") || "",
      );
    });
  });

  document.querySelectorAll("[data-split-workspace-tab]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      splitWorkspaceTab(
        button.getAttribute("data-split-workspace-tab") || "",
        button.getAttribute("data-split-workspace-tab-group") || "",
        "after",
      );
    });
  });

  document.querySelectorAll("[data-activate-workspace-group]").forEach((button) => {
    button.addEventListener("click", () => {
      const group = getWorkspaceGroupById(button.getAttribute("data-activate-workspace-group") || "");
      if (group?.activeKey) {
        void activateWorkspaceTab(group.activeKey, { groupId: group.id });
      }
    });
  });

  document.querySelectorAll("[data-workspace-group-resizer]").forEach((handle) => {
    if (handle instanceof HTMLElement && handle.dataset.workspaceResizeBound !== "true") {
      handle.dataset.workspaceResizeBound = "true";
      handle.addEventListener("pointerdown", beginWorkspaceGroupResize);
    }
  });

  document.querySelectorAll("[data-workspace-new-session]").forEach((button) => {
    button.addEventListener("click", async () => {
      const group = button.closest("[data-workspace-group]");
      if (group instanceof HTMLElement) {
        state.activeWorkspaceGroupId = group.dataset.workspaceGroup || state.activeWorkspaceGroupId;
        saveWorkspaceGroupsState();
      }
      await startNewAgentFromUi();
    });
  });
}

function refreshWorkspaceTabsUi({ focusKey = "" } = {}) {
  syncWorkspaceTabs({ persist: true });
  syncWorkspaceTabGroups({ persist: true });
  document.querySelectorAll("[data-workspace-group]").forEach((groupElement) => {
    if (!(groupElement instanceof HTMLElement)) {
      return;
    }

    const group = getWorkspaceGroupById(groupElement.dataset.workspaceGroup || "");
    const tabs = groupElement.querySelector(".workspace-tabs");
    if (group && tabs instanceof HTMLElement) {
      tabs.outerHTML = renderWorkspaceTabs(group);
    }
  });
  bindWorkspaceTabEvents();
  if (focusKey) {
    focusWorkspaceTab(focusKey);
  }
}

function bindFileEditorEvents() {
  bindLineNumberEditors();
  bindImagePreviewEvents();
  bindOpenFileTabReorderEvents();
  bindPaperSinceLastUpdateEvents();

  document.querySelectorAll("[data-file-tab]").forEach((button) => {
    button.addEventListener("click", (event) => {
      if (shouldSuppressOpenFileTabClick(button.getAttribute("data-file-tab"))) {
        event.preventDefault();
        event.stopPropagation();
        return;
      }

      activateOpenFileTab(button.getAttribute("data-file-tab"));
    });

    button.addEventListener("keydown", (event) => {
      if (!event.altKey || (event.key !== "ArrowLeft" && event.key !== "ArrowRight")) {
        return;
      }

      event.preventDefault();
      event.stopPropagation();
      const direction =
        event.key === "ArrowLeft"
          ? -FILE_PREVIEW_TAB_REORDER_KEYBOARD_STEP
          : FILE_PREVIEW_TAB_REORDER_KEYBOARD_STEP;
      moveOpenFileTabByOffset(button.getAttribute("data-file-tab"), direction);
    });
  });

  document.querySelectorAll("[data-close-file-tab]").forEach((button) => {
    button.addEventListener("click", (event) => {
      event.stopPropagation();
      closeOpenFileTab(button.getAttribute("data-close-file-tab"));
    });
  });

  document.querySelector("#close-file-preview")?.addEventListener("click", () => {
    if (!confirmCloseOpenFileTabs(state.openFileTabs)) {
      return;
    }

    resetOpenFile();
    refreshFileTreeUi();
    refreshOpenFileUi();
  });

  document.querySelector("#open-file-editor")?.addEventListener("input", (event) => {
    const textarea = event.currentTarget;
    if (!(textarea instanceof HTMLTextAreaElement)) {
      return;
    }

    const activeTab = getActiveOpenFileTab();
    if (!activeTab) {
      return;
    }

    activeTab.draft = textarea.value;
    syncOpenFileStateFromTab(activeTab);
    syncOpenFileEditorStateUi();
  });

  document.querySelector("#edit-open-file")?.addEventListener("click", () => {
    const activeTab = getActiveOpenFileTab();
    if (!activeTab) {
      return;
    }

    activeTab.viewMode = "edit";
    syncOpenFileStateFromTab(activeTab);
    refreshOpenFileUi();
  });

  document.querySelector("#preview-open-file")?.addEventListener("click", () => {
    const activeTab = getActiveOpenFileTab();
    if (!activeTab || isOpenFileDirty(activeTab)) {
      return;
    }

    activeTab.viewMode = "preview";
    syncOpenFileStateFromTab(activeTab);
    refreshOpenFileUi();
  });

  document.querySelector("#save-open-file")?.addEventListener("click", async () => {
    await saveOpenFile();
  });

  document.querySelector("#reload-open-file")?.addEventListener("click", async () => {
    await reloadOpenFile();
  });

  document.querySelector("#try-open-file-text")?.addEventListener("click", async () => {
    if (!state.openFileRelativePath) {
      return;
    }

    await openWorkspaceFile(state.openFileRelativePath, { force: true });
  });

  document.querySelectorAll("[data-image-zoom]").forEach((button) => {
    button.addEventListener("click", () => {
      const activeTab = getActiveOpenFileTab();
      if (!activeTab || activeTab.status !== "image") {
        return;
      }

      const action = button.getAttribute("data-image-zoom");
      if (action === "reset") {
        updateOpenImageTransform(activeTab, { zoom: 1, offsetX: 0, offsetY: 0 });
        return;
      }

      const nextZoom =
        action === "in"
          ? getOpenImageZoom(activeTab) + FILE_IMAGE_ZOOM_STEP
          : getOpenImageZoom(activeTab) - FILE_IMAGE_ZOOM_STEP;
      zoomOpenImage(activeTab, nextZoom);
    });
  });
}

function refreshToolbarUi() {
  const activeSession = state.sessions.find((session) => session.id === state.activeSessionId) || null;
  const title = document.querySelector("#toolbar-title");
  const meta = document.querySelector("#toolbar-meta");
  const emptyState = document.querySelector("#empty-state");
  const canSend = Boolean(activeSession && activeSession.status !== "exited");

  if (title) {
    title.textContent = activeSession ? activeSession.name : "new session";
  }

  if (meta) {
    meta.textContent = activeSession
      ? `${activeSession.providerLabel} · ${activeSession.cwd}`
      : state.defaultCwd;
  }

  if (emptyState) {
    emptyState.classList.toggle("hidden", Boolean(activeSession));
  }

  document.querySelectorAll("[data-terminal-control]").forEach((button) => {
    button.disabled = !canSend;
  });

  refreshShellSurfaceToggleUi(activeSession);
  refreshRichSessionSurfaceUi();
  refreshTerminalJumpUi();
}

function refreshShellUi({ sessions = true, ports = true, files = true } = {}) {
  refreshUpdateUi();
  refreshSystemToastsUi();
  refreshKnowledgeSettingsUi();

  if (sessions) {
    refreshSessionsList({ bindEvents: false });
    refreshAgentInboxUi({ bindEvents: false });
    bindSessionEvents();
  }

  if (ports) {
    refreshPortsList();
  }

  if (files) {
    refreshFileTreeUi();
    refreshOpenFileUi();
  }

  refreshKnowledgeBaseUi();
  refreshToolbarUi();
  refreshWorkspaceTabsUi();
}

// Resolves a path the user clicked inside the rich session feed and either
// opens it in the workspace preview tab (path lives under the active root)
// or copies it to the clipboard with a toast (path lives elsewhere — we
// can't read it remotely, so the most useful action is "give me the path").
async function openRichSessionPath(rawPath) {
  const trimmed = String(rawPath || "").trim();
  if (!trimmed) {
    return;
  }

  // Strip ":line[:col]" suffixes that came from compiler-style locations.
  const locationMatch = trimmed.match(/^(.+?)(?::(\d+)(?::\d+)?)?$/u);
  const pathOnly = locationMatch ? locationMatch[1] : trimmed;

  const root = normalizeWorkspaceRoot(state.filesRoot || state.defaultCwd || "");
  let relativePath = "";

  if (pathOnly.startsWith("/")) {
    if (root && (pathOnly === root || pathOnly.startsWith(`${root}/`))) {
      relativePath = pathOnly === root ? "" : pathOnly.slice(root.length + 1);
    }
  } else {
    relativePath = pathOnly;
  }

  if (!relativePath) {
    if (typeof navigator !== "undefined" && navigator.clipboard?.writeText) {
      try {
        await navigator.clipboard.writeText(pathOnly);
      } catch {
        // clipboard isn't always available (insecure context); fall through.
      }
    }
    return;
  }

  await openWorkspaceFilePreview(relativePath, { force: false });
}

async function openWorkspaceFile(relativePath, { force = false } = {}) {
  const normalizedPath = normalizeFileTreePath(relativePath);
  const root = state.filesRoot;
  const tab = ensureOpenFileTab(normalizedPath, { mode: "text" });

  if (!root || !normalizedPath || !tab) {
    return;
  }

  if (!force && tab.status === "text") {
    syncOpenFileStateFromTab(tab);
    refreshOpenFileUi();
    return;
  }

  const requestId = state.openFileRequestId + 1;
  state.openFileRequestId = requestId;
  tab.requestId = requestId;
  tab.status = "loading";
  tab.content = "";
  tab.draft = "";
  tab.message = "";
  tab.saving = false;
  syncOpenFileStateFromTab(tab);
  refreshFileTreeUi();
  refreshOpenFileUi();

  try {
    const payload = await fetchJson(`/api/files/text?${getFileTextRequestParams(normalizedPath).toString()}`);

    if (tab.requestId !== requestId || state.filesRoot !== root) {
      return;
    }

    tab.status = "text";
    tab.content = payload.file.content;
    tab.draft = payload.file.content;
    tab.message = "";
    tab.saving = false;
    if (state.openFileRelativePath === normalizedPath) {
      syncOpenFileStateFromTab(tab);
      refreshOpenFileUi();
    }
  } catch (error) {
    if (tab.requestId !== requestId || state.filesRoot !== root) {
      return;
    }

    if (error.status === 400 || error.status === 413) {
      tab.status = "external";
      tab.content = "";
      tab.draft = "";
      tab.message = "this file is not editable as UTF-8 text, but you can still open it raw";
      if (state.openFileRelativePath === normalizedPath) {
        syncOpenFileStateFromTab(tab);
        refreshOpenFileUi();
      }
      return;
    }

    tab.status = "error";
    tab.message = error.message;
    if (state.openFileRelativePath === normalizedPath) {
      syncOpenFileStateFromTab(tab);
      refreshOpenFileUi();
    }
  }
}

async function openWorkspaceFilePreview(relativePath, { mode = "text", force = false } = {}) {
  const normalizedPath = normalizeFileTreePath(relativePath);

  if (normalizedPath && state.currentView !== "shell") {
    setCurrentView("shell");
    renderShell();
  }

  const tab = ensureOpenFileTab(normalizedPath, { mode });

  if (!tab) {
    return;
  }

  if (mode === "image") {
    tab.status = "image";
    tab.content = "";
    tab.draft = "";
    tab.message = "";
    tab.saving = false;
    syncOpenFileStateFromTab(tab);
    refreshFileTreeUi();
    refreshOpenFileUi();
    return;
  }

  if (mode === "raw") {
    tab.status = "external";
    tab.content = "";
    tab.draft = "";
    tab.message = "preview is not available for this file type, but you can still open it raw";
    tab.saving = false;
    syncOpenFileStateFromTab(tab);
    refreshFileTreeUi();
    refreshOpenFileUi();
    return;
  }

  await openWorkspaceFile(normalizedPath, { force });
}

function openPortPreview(portNumber) {
  if (!isLocalhostAppsEnabled()) {
    return;
  }

  const port = state.ports.find((entry) => entry.port === Number(portNumber));
  if (!port) {
    return;
  }

  const tab = ensureOpenFileTab(getPortPreviewTabId(port), {
    mode: "web",
    name: getPortDisplayName(port),
    url: getPortProxyUrl(port),
    externalUrl: getPortPrimaryUrl(port),
    port: port.port,
  });

  if (!tab) {
    return;
  }

  tab.status = "web";
  tab.content = "";
  tab.draft = "";
  tab.message = "";
  tab.saving = false;
  syncOpenFileStateFromTab(tab);
  refreshFileTreeUi();
  refreshOpenFileUi();
}

function activateOpenFileTab(relativePath) {
  const normalizedPath = normalizeFileTreePath(relativePath);
  const tab = state.openFileTabs.find((entry) => entry.relativePath === normalizedPath);
  if (!tab) {
    return;
  }

  syncOpenFileStateFromTab(tab);
  refreshFileTreeUi();
  refreshOpenFileUi();
}

function confirmCloseOpenFileTabs(tabs) {
  const dirtyTabs = tabs.filter((tab) => isOpenFileDirty(tab));
  if (!dirtyTabs.length) {
    return true;
  }

  const label = dirtyTabs.length === 1 ? dirtyTabs[0].name : `${dirtyTabs.length} files`;
  return window.confirm(`Close ${label} with unsaved changes?`);
}

function closeOpenFileTab(relativePath) {
  const normalizedPath = normalizeFileTreePath(relativePath);
  const tabIndex = state.openFileTabs.findIndex((entry) => entry.relativePath === normalizedPath);
  if (tabIndex < 0) {
    return;
  }

  if (!confirmCloseOpenFileTabs([state.openFileTabs[tabIndex]])) {
    return;
  }

  const closingActiveTab = state.openFileRelativePath === normalizedPath;
  state.openFileTabs.splice(tabIndex, 1);
  rememberOpenFileTabOrder();

  if (closingActiveTab) {
    const nextTab = state.openFileTabs[Math.min(tabIndex, state.openFileTabs.length - 1)] || null;
    syncOpenFileStateFromTab(nextTab);
  }

  refreshFileTreeUi();
  refreshOpenFileUi();
}

async function reloadOpenFile() {
  const activeTab = getActiveOpenFileTab();
  if (!state.openFileRelativePath || activeTab?.saving) {
    return;
  }

  if (activeTab?.status === "image" || activeTab?.status === "web") {
    refreshOpenFileUi();
    return;
  }

  await openWorkspaceFile(state.openFileRelativePath, { force: true });
}

async function saveOpenFile() {
  const activeTab = getActiveOpenFileTab();
  if (
    !state.filesRoot ||
    !state.openFileRelativePath ||
    activeTab?.status !== "text" ||
    activeTab.saving ||
    !isOpenFileDirty(activeTab)
  ) {
    return;
  }

  const root = state.filesRoot;
  const relativePath = state.openFileRelativePath;
  activeTab.saving = true;
  syncOpenFileStateFromTab(activeTab);
  syncOpenFileEditorStateUi();

  try {
    const payload = await fetchJson("/api/files/text", {
      method: "PUT",
      body: JSON.stringify({
        root,
        path: relativePath,
        content: activeTab.draft,
      }),
    });

    if (state.filesRoot !== root || activeTab.relativePath !== relativePath) {
      return;
    }

    activeTab.content = payload.file.content;
    activeTab.draft = payload.file.content;
    activeTab.message = "";
    if (state.openFileRelativePath === relativePath) {
      syncOpenFileStateFromTab(activeTab);
    }
  } catch (error) {
    window.alert(error.message);
  } finally {
    activeTab.saving = false;
    if (state.openFileRelativePath === relativePath) {
      syncOpenFileStateFromTab(activeTab);
    }
    syncOpenFileEditorStateUi();
  }
}

function startKnowledgeBaseNoteEdit() {
  if (!state.knowledgeBase.selectedNotePath || state.knowledgeBase.selectedNoteLoading) {
    return;
  }

  state.knowledgeBase.selectedNoteDraft = state.knowledgeBase.selectedNoteContent;
  state.knowledgeBase.selectedNoteEditing = true;
  state.knowledgeBase.selectedNoteSaving = false;
  renderShell();
}

function cancelKnowledgeBaseNoteEdit() {
  state.knowledgeBase.selectedNoteDraft = state.knowledgeBase.selectedNoteContent;
  state.knowledgeBase.selectedNoteEditing = false;
  state.knowledgeBase.selectedNoteSaving = false;
  renderShell();
}

async function saveKnowledgeBaseNote() {
  if (
    !state.knowledgeBase.rootPath ||
    !state.knowledgeBase.selectedNotePath ||
    !state.knowledgeBase.selectedNoteEditing ||
    state.knowledgeBase.selectedNoteSaving ||
    state.knowledgeBase.selectedNoteDraft === state.knowledgeBase.selectedNoteContent
  ) {
    return;
  }

  const root = state.knowledgeBase.rootPath;
  const relativePath = state.knowledgeBase.selectedNotePath;
  state.knowledgeBase.selectedNoteSaving = true;
  refreshKnowledgeBaseEditStateUi();

  try {
    await fetchJson("/api/files/text", {
      method: "PUT",
      body: JSON.stringify({
        root,
        path: relativePath,
        content: state.knowledgeBase.selectedNoteDraft,
      }),
    });

    if (state.knowledgeBase.rootPath !== root || state.knowledgeBase.selectedNotePath !== relativePath) {
      return;
    }

    await loadKnowledgeBaseIndex();
    await loadKnowledgeBaseNote(relativePath, { force: true });
    updateRoute({ view: "knowledge-base", notePath: relativePath });
    void recordAgentTownEvent("library_note_saved", {
      label: relativePath,
      metadata: { path: relativePath },
    });
    renderShell();
  } catch (error) {
    window.alert(error.message);
  } finally {
    state.knowledgeBase.selectedNoteSaving = false;
    refreshKnowledgeBaseEditStateUi();
  }
}

function refreshKnowledgeBaseEditStateUi() {
  const status = document.querySelector("#knowledge-base-edit-status");
  const saveButton = document.querySelector("#save-knowledge-base-note");
  const dirty = state.knowledgeBase.selectedNoteDraft !== state.knowledgeBase.selectedNoteContent;

  if (status) {
    status.textContent = state.knowledgeBase.selectedNoteSaving
      ? "saving changes..."
      : dirty
        ? "unsaved changes"
        : "saved";
  }

  if (saveButton instanceof HTMLButtonElement) {
    saveButton.disabled = !dirty || state.knowledgeBase.selectedNoteSaving;
    saveButton.textContent = state.knowledgeBase.selectedNoteSaving ? "saving..." : dirty ? "save" : "saved";
    saveButton.classList.toggle("primary-button", dirty);
    saveButton.classList.toggle("ghost-button", !dirty);
  }
}

async function loadFileTree(relativePath = "", { force = false } = {}) {
  const pathKey = normalizeFileTreePath(relativePath);
  const root = state.filesRoot;

  if (!root) {
    return;
  }

  if (!force && (state.fileTreeLoading.has(pathKey) || state.fileTreeEntries[pathKey])) {
    return;
  }

  state.fileTreeLoading.add(pathKey);

  if (pathKey === "") {
    state.fileTreeError = "";
  }

  refreshFileTreeUi();

  try {
    const params = new URLSearchParams();
    params.set("root", root);
    if (pathKey) {
      params.set("path", pathKey);
    }

    const payload = await fetchJson(`/api/files?${params.toString()}`);

    if (state.filesRoot !== root) {
      return;
    }

    state.fileTreeEntries[pathKey] = payload.entries;
    state.fileTreeError = "";
  } catch (error) {
    if (state.filesRoot !== root) {
      return;
    }

    if (pathKey) {
      state.fileTreeExpanded.delete(pathKey);
    }

    state.fileTreeError = error.message;
  } finally {
    if (state.filesRoot === root) {
      state.fileTreeLoading.delete(pathKey);
      refreshFileTreeUi();
    }
  }
}

async function refreshOpenFileTree({ force = false } = {}) {
  if (!state.filesRoot) {
    return;
  }

  const openPaths = Array.from(state.fileTreeExpanded);

  for (const relativePath of openPaths) {
    await loadFileTree(relativePath, { force });
  }
}

function scheduleSessionsRefresh() {
  if (state.sessionRefreshTimer) {
    return;
  }

  state.sessionRefreshTimer = window.setTimeout(() => {
    state.sessionRefreshTimer = null;
    refreshShellUi({ sessions: true, ports: false, files: false });
  }, 180);
}

