async function bootstrapApp() {
  try {
    installTerminalDisposalGuard();
    installDelayedTooltips();
    bindSelectableRefreshEvents();

    if ("virtualKeyboard" in navigator) {
      navigator.virtualKeyboard.overlaysContent = false;
    }
  } catch (error) {
    console.warn("[vibe-research] virtual keyboard API unavailable", error);
  }

  syncViewportMetrics();
  syncViewFromLocation();
  const payload = await fetchJson("/api/state");
  state.providers = payload.providers;
  state.sessions = payload.sessions;
  pruneSessionReadState();
  state.defaultCwd = payload.defaultSessionCwd || payload.cwd;
  state.stateDir = payload.stateDir || "";
  state.defaultProviderId = payload.defaultProviderId;
  applySettingsState(payload.settings);
  applyBuildingHubCatalog(payload.buildingHub || {});
  state.ports = isLocalhostAppsEnabled() ? (payload.ports ?? []) : [];
  state.portsLoadedAt = Date.now();
  state.preferredBaseUrl = payload.preferredUrl ? new URL(payload.preferredUrl).origin : "";
  applyAgentPromptState(payload.agentPrompt);
  applyAgentTownState(payload.agentTown);

  if (maybeRedirectToPreferredOrigin()) {
    return;
  }

  const route = getRouteState();
  state.filesRootOverride = route.root || null;
  state.activeSessionId = payload.sessions[0]?.id ?? null;
  syncFilesRoot({ force: true });
  await loadAgentTownState({ refreshUi: false });

  if (route.view === "file" && !isBrainSetupRequired() && !isAgentSetupRequired()) {
    setOpenFileSelection(route.path, {
      status: route.path ? "loading" : "idle",
      message: "",
    });
    renderFileEditorPage();

    if (route.path) {
      await openWorkspaceFile(route.path, { force: true });
    } else {
      refreshOpenFileUi();
    }
    return;
  }

  if (state.currentView === "knowledge-base" && !isBrainSetupRequired() && !isAgentSetupRequired()) {
    await loadKnowledgeBaseIndex();
    await ensureKnowledgeBaseSelectionLoaded();
    updateRoute({ view: "knowledge-base", notePath: state.knowledgeBase.selectedNotePath });
  }

  renderShell();
  if (state.currentView === "system") {
    void loadSystemMetrics({ forceRender: true });
  }
  if (isVisualInterfaceView()) {
    void openVisualInterface({ refresh: true });
  }
  if (isAgentTownLayoutCustomized()) {
    void mirrorAgentTownState({ refreshUi: false });
  }
  void loadVideoMemoryStatus({ renderOnComplete: state.currentView === "plugins" || state.currentView === "settings" });
  void loadUpdateStatus();

  if (state.updateTimer) {
    window.clearInterval(state.updateTimer);
  }

  state.updateTimer = window.setInterval(() => {
    void loadUpdateStatus({ force: true });
  }, 5 * 60 * 1000);

  if (state.settingsPollTimer) {
    window.clearInterval(state.settingsPollTimer);
  }

  state.settingsPollTimer = window.setInterval(() => {
    void loadSettingsStatus();
  }, 30 * 1000);

  if (state.bundleHubPollTimer) {
    window.clearInterval(state.bundleHubPollTimer);
  }

  state.bundleHubPollTimer = window.setInterval(() => {
    if (state.currentView !== "plugins" || state.buildingHubTab !== "bundles") {
      return;
    }
    void fetchBundleHubCatalog({ force: false });
  }, BUNDLE_HUB_REFRESH_INTERVAL_MS);

  if (state.activeSessionId && state.currentView === "shell") {
    connectToSession(state.activeSessionId);
  }

  window.addEventListener("hashchange", async () => {
    syncViewFromLocation();

    renderShell();
    if (isVisualInterfaceView()) {
      void openVisualInterface();
      return;
    }
    if (state.currentView === "shell" && state.activeSessionId) {
      connectToSession(state.activeSessionId);
    }
  });

  if (state.pollTimer) {
    window.clearInterval(state.pollTimer);
  }

  state.pollTimer = window.setInterval(() => {
    loadSessions();
    void loadAgentTownState({ refreshUi: true });
    if (isLocalhostAppsEnabled() && Date.now() - state.portsLoadedAt > PORTS_BACKGROUND_REFRESH_MS) {
      loadPorts();
    }
    if ((state.currentView === "system" || isVisualInterfaceView()) && !state.systemMetricsLoading) {
      void loadSystemMetrics();
    }
  }, 3000);
}

const AGENT_POINTER_AUTO_DISMISS_ELEMENT_CLICK = true;
const agentPointerRuntime = {
  expiryTimer: 0,
  frameHandle: 0,
  overlay: null,
  lastTargetElement: null,
  cleanupListeners: null,
};

function handleIncomingAgentPointer(pointer) {
  clearAgentPointerOverlay();
  if (!pointer) {
    state.agentPointer = null;
    return;
  }

  state.agentPointer = pointer;

  const autoNavView = getAgentPointerAutoNavView(pointer.target);
  if (autoNavView && state.currentView !== autoNavView) {
    void openMainView(autoNavView).then(() => startAgentPointerOverlay());
  } else {
    startAgentPointerOverlay();
  }

  const remainingMs = Math.max(0, (pointer.expiresAt || 0) - Date.now());
  agentPointerRuntime.expiryTimer = window.setTimeout(() => {
    if (state.agentPointer?.id === pointer.id) {
      clearAgentPointerOverlay();
      state.agentPointer = null;
    }
  }, remainingMs + 200);
}

function getAgentPointerAutoNavView(target) {
  if (!target || typeof target !== "string") return "";
  if (target.startsWith("building:")) return "visual-interface";
  if (target.startsWith("session:")) return "visual-interface";
  if (target === "placement-preview") return "visual-interface";
  if (target === "terminal-input") return "visual-interface";
  if (target.startsWith("plugin-card:")) return "plugins";
  if (target.startsWith("view:")) return target.slice("view:".length);
  return "";
}

function resolveAgentPointerTarget(target) {
  if (!target) return null;

  if (typeof target === "object") {
    const x = Number(target.x);
    const y = Number(target.y);
    if (Number.isFinite(x) && Number.isFinite(y)) {
      return { rect: { left: x - 12, top: y - 12, width: 24, height: 24 }, element: null };
    }
    return null;
  }

  if (target.startsWith("view:")) {
    const view = target.slice("view:".length);
    const node = document.querySelector(`[data-open-main-view="${cssEscape(view)}"]`);
    return node ? { element: node, rect: node.getBoundingClientRect() } : null;
  }

  if (target.startsWith("workspace-tab:")) {
    const key = target.slice("workspace-tab:".length);
    const node =
      document.querySelector(`[data-workspace-tab="${cssEscape(key)}"]`)
      || document.querySelector(`[data-workspace-tab="view:${cssEscape(key)}"]`);
    return node ? { element: node, rect: node.getBoundingClientRect() } : null;
  }

  if (target.startsWith("plugin-card:")) {
    const pluginId = target.slice("plugin-card:".length);
    const node = document.querySelector(`[data-plugin-open="${cssEscape(pluginId)}"]`);
    return node ? { element: node, rect: node.getBoundingClientRect() } : null;
  }

  if (target.startsWith("selector-fallback:")) {
    const selectors = target
      .slice("selector-fallback:".length)
      .split("||")
      .map((selector) => selector.trim())
      .filter(Boolean);
    for (const selector of selectors) {
      const node = findAgentPointerTargetBySelector(selector, { visibleOnly: true });
      if (node) {
        return { element: node, rect: node.getBoundingClientRect() };
      }
    }
    return null;
  }

  if (target.startsWith("selector:")) {
    const selector = target.slice("selector:".length).trim();
    if (!selector) {
      return null;
    }
    const node = findAgentPointerTargetBySelector(selector);
    return node ? { element: node, rect: node.getBoundingClientRect() } : null;
  }

  if (target.startsWith("element:")) {
    const token = target.slice("element:".length);
    const node = document.querySelector(`[data-agent-target="${cssEscape(token)}"]`);
    return node ? { element: node, rect: node.getBoundingClientRect() } : null;
  }

  if (target === "terminal-input") {
    const rect = getAgentPointerTerminalRect();
    return rect ? { element: null, rect } : null;
  }

  if (target.startsWith("session:")) {
    const sessionId = target.slice("session:".length);
    const rect = getAgentPointerSessionRect(sessionId);
    return rect ? { element: null, rect } : null;
  }

  if (target.startsWith("building:")) {
    const buildingId = target.slice("building:".length);
    const rect = getAgentPointerBuildingRect(buildingId);
    return rect ? { element: null, rect } : null;
  }

  if (target === "placement-preview") {
    const rect = getAgentTownBuilderPlacementScreenRect();
    return rect ? { element: null, rect } : null;
  }

  return null;
}

function getAgentPointerWorldRect(rectInput) {
  const canvas = document.querySelector("#visual-game-canvas");
  if (!(canvas instanceof HTMLCanvasElement) || !rectInput) return null;

  const x = Number(rectInput.x);
  const y = Number(rectInput.y);
  const width = Number(rectInput.width);
  const height = Number(rectInput.height);
  if (![x, y, width, height].every(Number.isFinite)) {
    return null;
  }

  const camera = state.visualGame.camera || { x: 0, y: 0, zoom: 1 };
  const canvasRect = canvas.getBoundingClientRect();
  return {
    left: canvasRect.left + (x - camera.x) * camera.zoom,
    top: canvasRect.top + (y - camera.y) * camera.zoom,
    width: Math.max(24, width * camera.zoom),
    height: Math.max(24, height * camera.zoom),
  };
}

function getAgentTownBuilderPlacementScreenRect() {
  return getAgentPointerWorldRect(state.visualGame.builderPlacement?.cursorRect);
}

function getAgentPointerTerminalRect() {
  const richInput = document.querySelector("#rich-session-input");
  if (richInput instanceof HTMLElement && richInput.getClientRects().length) {
    return richInput.getBoundingClientRect();
  }

  const richForm = document.querySelector("#rich-session-form");
  if (richForm instanceof HTMLElement && richForm.getClientRects().length) {
    return richForm.getBoundingClientRect();
  }

  const mount = document.querySelector("#terminal-mount");
  if (!(mount instanceof HTMLElement) || !mount.getClientRects().length) {
    return null;
  }

  const rect = mount.getBoundingClientRect();
  const insetX = Math.max(16, Math.min(36, rect.width * 0.08));
  const height = Math.max(44, Math.min(96, rect.height * 0.24));
  const width = Math.max(72, rect.width - insetX * 2);
  return {
    left: rect.left + insetX,
    top: rect.top + rect.height - height - 18,
    width,
    height,
  };
}

function getAgentPointerSessionRect(sessionId) {
  const requestedSessionId = String(sessionId || "").trim();
  const selectedSessionId = String(state.visualGame.selectedSessionId || "").trim();
  const sessionHits = (state.visualGame.hitAreas || []).filter((area) => area.kind === "session");
  if (!sessionHits.length) {
    return null;
  }

  const hit = (
    (requestedSessionId && requestedSessionId !== "any"
      ? sessionHits.find((area) => area.sessionId === requestedSessionId)
      : null)
    || (selectedSessionId ? sessionHits.find((area) => area.sessionId === selectedSessionId) : null)
    || sessionHits[0]
  );
  return hit ? getAgentPointerWorldRect(hit) : null;
}

function getAgentPointerBuildingRect(buildingId) {
  const hit = (state.visualGame.hitAreas || []).find(
    (area) => area.kind === "building" && area.buildingId === buildingId,
  );
  return hit ? getAgentPointerWorldRect(hit) : null;
}

function cssEscape(value) {
  return String(value).replace(/["\\]/g, "\\$&");
}

function isAgentPointerTargetVisible(node) {
  if (!(node instanceof Element) || !document.contains(node)) {
    return false;
  }

  const rect = node.getBoundingClientRect();
  if (!(rect.width > 0 && rect.height > 0)) {
    return false;
  }

  const style = window.getComputedStyle(node);
  if (!style || style.display === "none" || style.visibility === "hidden" || style.visibility === "collapse") {
    return false;
  }

  return true;
}

function findAgentPointerTargetBySelector(selector, { visibleOnly = false } = {}) {
  if (!selector) {
    return null;
  }

  try {
    const nodes = [...document.querySelectorAll(selector)];
    if (!nodes.length) {
      return null;
    }

    const visibleNode = nodes.find((node) => isAgentPointerTargetVisible(node));
    if (visibleNode) {
      return visibleNode;
    }

    return visibleOnly ? null : nodes[0];
  } catch {
    return null;
  }
}

function ensureAgentPointerOverlay() {
  if (agentPointerRuntime.overlay && document.body.contains(agentPointerRuntime.overlay)) {
    return agentPointerRuntime.overlay;
  }

  const overlay = document.createElement("div");
  overlay.className = "agent-pointer-overlay";
  overlay.setAttribute("aria-hidden", "true");
  overlay.innerHTML = `
    <div class="agent-pointer" role="presentation">
      <svg class="agent-pointer-arrow" viewBox="0 0 48 48" width="56" height="56" aria-hidden="true" focusable="false">
        <path d="M24 4 L44 44 L24 34 L4 44 Z" fill="#ffb951" stroke="#1b1610" stroke-width="2" stroke-linejoin="round"/>
      </svg>
      <div class="agent-pointer-reason"></div>
    </div>
  `;
  document.body.appendChild(overlay);
  agentPointerRuntime.overlay = overlay;
  return overlay;
}

function isStickyAgentPointerSource(source) {
  return source === "guided-onboarding" || source === "guided-tutorial";
}

function startAgentPointerOverlay() {
  stopAgentPointerOverlayLoop();
  const pointer = state.agentPointer;
  if (!pointer) return;

  const overlay = ensureAgentPointerOverlay();
  const reasonNode = overlay.querySelector(".agent-pointer-reason");
  if (reasonNode) {
    reasonNode.textContent = pointer.reason || "";
    reasonNode.style.display = pointer.reason ? "" : "none";
  }
  overlay.classList.add("is-visible");

  const onDocumentClick = (event) => {
    const target = event.target instanceof Element ? event.target : null;
    if (!target) return;
    if (!AGENT_POINTER_AUTO_DISMISS_ELEMENT_CLICK) return;
    if (isStickyAgentPointerSource(state.agentPointer?.source)) return;
    const current = agentPointerRuntime.lastTargetElement;
    if (current && current.contains(target)) {
      void dismissAgentPointer("click");
    }
  };

  const onKeyDown = (event) => {
    if (isStickyAgentPointerSource(state.agentPointer?.source)) {
      return;
    }
    if (event.key === "Escape") {
      void dismissAgentPointer("escape");
    }
  };

  document.addEventListener("click", onDocumentClick, true);
  document.addEventListener("keydown", onKeyDown);
  agentPointerRuntime.cleanupListeners = () => {
    document.removeEventListener("click", onDocumentClick, true);
    document.removeEventListener("keydown", onKeyDown);
  };

  const tick = () => {
    agentPointerRuntime.frameHandle = 0;
    if (!state.agentPointer) {
      overlay.classList.remove("is-visible");
      return;
    }

    const resolved = resolveAgentPointerTarget(state.agentPointer.target);
    if (!resolved || !resolved.rect) {
      overlay.classList.add("is-waiting");
      agentPointerRuntime.lastTargetElement = null;
      agentPointerRuntime.frameHandle = window.requestAnimationFrame(tick);
      return;
    }

    overlay.classList.remove("is-waiting");
    agentPointerRuntime.lastTargetElement = resolved.element || null;
    positionAgentPointerOverlay(overlay, resolved.rect);
    agentPointerRuntime.frameHandle = window.requestAnimationFrame(tick);
  };

  agentPointerRuntime.frameHandle = window.requestAnimationFrame(tick);
}

function positionAgentPointerOverlay(overlay, rect) {
  const pointerNode = overlay.querySelector(".agent-pointer");
  if (!(pointerNode instanceof HTMLElement)) return;

  const viewportWidth = window.innerWidth;
  const viewportHeight = window.innerHeight;
  const targetCenterX = rect.left + rect.width / 2;
  const targetCenterY = rect.top + rect.height / 2;

  const padding = 18;
  const arrowSize = 56;
  const reasonEl = overlay.querySelector(".agent-pointer-reason");
  const reasonHeight = reasonEl instanceof HTMLElement && reasonEl.offsetParent ? reasonEl.offsetHeight : 0;

  let arrowX = targetCenterX - arrowSize / 2;
  let arrowY = rect.top - arrowSize - padding;
  let direction = "down";

  if (arrowY < 8) {
    arrowY = rect.top + rect.height + padding;
    direction = "up";
  }

  arrowX = Math.max(8, Math.min(viewportWidth - arrowSize - 8, arrowX));
  arrowY = Math.max(8, Math.min(viewportHeight - arrowSize - reasonHeight - 8, arrowY));

  pointerNode.style.left = `${arrowX}px`;
  pointerNode.style.top = `${arrowY}px`;
  pointerNode.dataset.direction = direction;
}

function stopAgentPointerOverlayLoop() {
  if (agentPointerRuntime.frameHandle) {
    window.cancelAnimationFrame(agentPointerRuntime.frameHandle);
    agentPointerRuntime.frameHandle = 0;
  }
  if (agentPointerRuntime.cleanupListeners) {
    agentPointerRuntime.cleanupListeners();
    agentPointerRuntime.cleanupListeners = null;
  }
}

function clearAgentPointerOverlay() {
  stopAgentPointerOverlayLoop();
  if (agentPointerRuntime.expiryTimer) {
    window.clearTimeout(agentPointerRuntime.expiryTimer);
    agentPointerRuntime.expiryTimer = 0;
  }
  agentPointerRuntime.lastTargetElement = null;
  if (agentPointerRuntime.overlay) {
    agentPointerRuntime.overlay.classList.remove("is-visible", "is-waiting");
  }
}

async function dismissAgentPointer(_reason) {
  const pointer = state.agentPointer;
  if (isStickyAgentPointerSource(pointer?.source)) {
    return;
  }
  state.agentPointer = null;
  clearAgentPointerOverlay();
  if (!pointer) return;
  try {
    await fetch("/api/agent-town/pointer", { method: "DELETE" });
  } catch {
    // Network hiccup; server pointer expires on its own TTL.
  }
}

async function bootstrapAgentPointer() {
  try {
    const res = await fetch("/api/agent-town/pointer", { headers: { Accept: "application/json" } });
    if (!res.ok) return;
    const payload = await res.json();
    if (payload && payload.pointer && payload.pointer.expiresAt > Date.now()) {
      handleIncomingAgentPointer(payload.pointer);
    }
  } catch {
    // No pointer endpoint / offline; no-op.
  }
}

// Wire bootstrap with a retry hook — when boot fails (e.g. /api/state timed
// out, network blip, server restart mid-load), the boot-fallback's "Retry"
// button can re-run bootstrap without a full page reload. A hard reload
// re-fetches the bundle and re-runs every other dependency; a retry just
// re-runs bootstrapApp and is cheaper.
function runBootstrap() {
  return bootstrapApp().catch((error) => {
    console.error("[vibe-research] app boot failed", error);
    markAppBootFailed(error);
  });
}
window.__vibeResearchRetryBoot = () => {
  // Reset the boot-reported flag so the next successful render fires
  // markAppBootReady again and dismisses the fallback.
  appBootReported = false;
  document.documentElement.dataset.appBoot = "loading";
  return runBootstrap();
};
void runBootstrap();
void bootstrapAgentPointer();
